import React, { useState, useRef, useEffect, useCallback } from 'react';
import { Play, Music, Heart, ChevronRight, ChevronLeft, Volume2, Lock, ArrowLeft, Phone, Video, MoreVertical, ChevronsDown } from 'lucide-react';
import { SLIDES, YOUTUBE_VIDEO_ID } from './constants';
import { SlideType } from './types';
import ProgressBar from './components/ProgressBar';
import FloatingHearts from './components/FloatingHearts';

// Helper to access window globals for YouTube API
declare global {
  interface Window {
    onYouTubeIframeAPIReady: () => void;
    YT: any;
  }
}

const App: React.FC = () => {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [isPlaying, setIsPlaying] = useState(false);
  const [password, setPassword] = useState('');
  const [error, setError] = useState(false);
  const playerRef = useRef<any>(null);

  // Initialize YouTube API
  useEffect(() => {
    // 1. Load the IFrame Player API code asynchronously.
    if (!window.YT) {
      const tag = document.createElement('script');
      tag.src = "https://www.youtube.com/iframe_api";
      const firstScriptTag = document.getElementsByTagName('script')[0];
      firstScriptTag.parentNode?.insertBefore(tag, firstScriptTag);
    }

    // 2. This function creates an <iframe> (and YouTube player)
    //    after the API code downloads.
    window.onYouTubeIframeAPIReady = () => {
      playerRef.current = new window.YT.Player('youtube-player', {
        height: '0',
        width: '0',
        videoId: YOUTUBE_VIDEO_ID,
        playerVars: {
          'playsinline': 1,
          'controls': 0,
          'disablekb': 1,
          'fs': 0,
          'loop': 1,
          'playlist': YOUTUBE_VIDEO_ID // Required for loop to work
        },
        events: {
          'onReady': (event: any) => {
             event.target.setVolume(50); // Set volume to 50%
          }
        }
      });
    };

    return () => {
      if (playerRef.current && playerRef.current.destroy) {
        playerRef.current.destroy();
      }
    };
  }, []);

  // Handle slide changes for audio
  useEffect(() => {
    if (currentIndex === 0) return; // Intro handled separately

    const currentSlide = SLIDES[currentIndex];

    if (currentSlide.type === SlideType.VIDEO) {
        // Pause background audio when on VIDEO slide
        if (playerRef.current && playerRef.current.pauseVideo) {
            playerRef.current.pauseVideo();
            setIsPlaying(false);
        }
    } else {
        // Resume background audio if we are NOT on video slide and NOT playing
        // This handles navigating away from the video slide
        if (!isPlaying && playerRef.current && playerRef.current.playVideo) {
            playerRef.current.playVideo();
            setIsPlaying(true);
        }
    }
  }, [currentIndex]);

  const handleStart = (e: React.MouseEvent) => {
    e.stopPropagation(); // Prevent main click handler

    // Normalize input: lowercase and remove spaces
    const cleanInput = password.toLowerCase().replace(/\s/g, '');

    if (cleanInput === 'seniseviyorum') {
      // Correct password
      if (!isPlaying && playerRef.current && playerRef.current.playVideo) {
        playerRef.current.playVideo();
        setIsPlaying(true);
      }
      setCurrentIndex(1);
      setError(false);
    } else {
      // Incorrect password
      setError(true);
      // Shake animation reset
      setTimeout(() => setError(false), 500);
    }
  };

  const handleInteraction = useCallback((e: React.MouseEvent) => {
    // If on INTRO (index 0), do NOT auto advance. Must use password button.
    if (currentIndex === 0) {
      return;
    }

    // Audio Logic: Attempt to play YouTube video on first interaction if not playing
    // EXCEPTION: Do not start background music if on VIDEO slide
    if (SLIDES[currentIndex].type !== SlideType.VIDEO && !isPlaying && playerRef.current && playerRef.current.playVideo) {
      playerRef.current.playVideo();
      setIsPlaying(true);
    }

    // Navigation Logic
    const { clientX } = e;
    const { innerWidth } = window;

    // Right side click -> Next
    if (clientX > innerWidth / 2) {
      // If on FINAL slide, disable click-to-next on background. 
      // User must click the heart specifically.
      if (SLIDES[currentIndex].type === SlideType.FINAL) {
        return;
      }

      if (currentIndex < SLIDES.length - 1) {
        setCurrentIndex((prev) => prev + 1);
      }
    } 
    // Left side click -> Previous
    else {
      if (currentIndex > 0) {
        setCurrentIndex((prev) => prev - 1);
      }
    }
  }, [currentIndex, isPlaying]);

  const restart = (e: React.MouseEvent) => {
    e.stopPropagation();
    setCurrentIndex(0);
    setPassword('');
    setIsPlaying(false);
    if (playerRef.current && playerRef.current.stopVideo) {
       playerRef.current.stopVideo();
    }
  };

  const currentSlide = SLIDES[currentIndex];

  // Render content based on slide type
  const renderContent = () => {
    switch (currentSlide.type) {
      case SlideType.INTRO:
        return (
          <div className="flex flex-col items-center justify-center h-full text-center px-6 animate-fade-in relative">

            {/* Sesi Açın Uyarısı */}
            <div className="absolute top-[15%] animate-pulse-slow">
              <div className="flex items-center gap-2 bg-white/40 backdrop-blur-sm px-4 py-2 rounded-full border border-white/60 shadow-sm">
                <Volume2 size={16} className="text-romantic-text" />
                <span className="text-xs font-sans tracking-widest uppercase text-romantic-text font-semibold">Sesi Açın</span>
              </div>
            </div>

            <div className="w-full max-w-xs space-y-6 z-20">
              {/* Şifre Input */}
              <div className={`transition-transform duration-100 ${error ? 'translate-x-[-10px] border-red-400' : ''} ${error ? 'animate-[pulse_0.5s_ease-in-out]' : ''}`}>
                <div className="relative group">
                  <input
                    type="text"
                    value={password}
                    onChange={(e) => {
                      setPassword(e.target.value);
                      setError(false);
                    }}
                    onClick={(e) => e.stopPropagation()} // Prevent slide navigation when typing
                    placeholder="Sihirli sözcüğü giriniz..."
                    className={`w-full bg-white/60 backdrop-blur-md border-2 ${error ? 'border-red-300 text-red-500' : 'border-white/50 text-romantic-text'} rounded-full px-6 py-4 text-center outline-none focus:border-romantic-primary focus:bg-white/80 transition-all font-serif text-lg placeholder:text-romantic-text/40 shadow-lg`}
                  />
                  {!password && (
                    <Lock size={16} className="absolute right-5 top-1/2 -translate-y-1/2 text-romantic-text/30" />
                  )}
                </div>
              </div>

              {/* Başla Butonu */}
              <div className="flex justify-center">
                <button 
                  onClick={handleStart}
                  className="bg-romantic-primary text-white px-10 py-4 rounded-full shadow-xl font-serif tracking-widest uppercase text-sm flex items-center gap-3 transform hover:scale-105 active:scale-95 transition-all duration-300 hover:bg-romantic-accent"
                >
                  <Play size={18} className="fill-current" />
                  Başla
                </button>
              </div>
            </div>
          </div>
        );

      case SlideType.WHATSAPP:
        return (
          <div className="flex flex-col h-full items-center justify-start pt-16 px-4 animate-fade-in relative z-20">
            {/* Phone/Chat Container - Floating Card */}
            {/* Reduced height on mobile to allow space for footer text and navigation */}
            <div className="w-full max-w-[320px] h-[55vh] md:h-[68vh] bg-[#E5DDD5] rounded-2xl shadow-2xl overflow-hidden flex flex-col relative border border-gray-300 ring-4 ring-black/5 mx-auto transition-all duration-300">

              {/* WhatsApp Header */}
              <div className="bg-[#075E54] text-white p-2 px-3 flex items-center shadow-md z-10 shrink-0">
                <ArrowLeft size={18} className="mr-1" />
                <div className="w-8 h-8 bg-gray-300 rounded-full mr-2 flex items-center justify-center text-gray-500 overflow-hidden shrink-0">
                  <div className="bg-gray-400 w-full h-full flex items-center justify-center text-xs font-bold">A</div>
                </div>
                <div className="flex-1 overflow-hidden">
                  <h3 className="font-semibold text-sm leading-tight truncate">{currentSlide.title}</h3>
                  <p className="text-[10px] opacity-80 truncate">Çevrimiçi</p>
                </div>
                <div className="flex gap-3 ml-2">
                  <Video size={16} />
                  <Phone size={16} />
                  <MoreVertical size={16} />
                </div>
              </div>

              {/* Chat Area */}
              <div className="flex-1 p-3 bg-[#E5DDD5] relative overflow-y-auto scrollbar-hide">
                  {/* Background pattern */}
                  <div className="absolute inset-0 opacity-10 bg-[url('https://user-images.githubusercontent.com/15075759/28719144-86dc0f70-73b1-11e7-911d-60d70fcded21.png')] pointer-events-none"></div>

                  {/* Date Separator */}
                  <div className="flex justify-center mb-4 relative z-10">
                    <span className="bg-[#D4EAF4] text-gray-600 text-[10px] font-medium px-2 py-0.5 rounded-lg shadow-sm">
                      {currentSlide.date}
                    </span>
                  </div>

                  {/* Messages */}
                  <div className="space-y-2 relative z-10 pb-4">
                    {currentSlide.messages?.map((msg, idx) => (
                      <div key={idx} className={`flex ${msg.isSender ? 'justify-end' : 'justify-start'}`}>
                        <div className={`
                          max-w-[85%] p-1.5 px-2.5 rounded-lg shadow-sm text-xs relative
                          ${msg.isSender ? 'bg-[#E2FFC7] rounded-tr-none' : 'bg-white rounded-tl-none'}
                        `}>
                          <p className="text-[#303030] leading-snug pb-1 whitespace-pre-wrap">{msg.text}</p>
                          <div className="text-right">
                             <span className="text-[9px] text-gray-500">{msg.time}</span>
                          </div>
                        </div>
                      </div>
                    ))}
                  </div>
              </div>
            </div>

            <p className="mt-2 text-xs text-romantic-text/60 font-sans italic animate-pulse">(Mesajı aşağı kaydırabilirsin.)</p>

            {/* Footer Text - Outside and Distinct */}
            {currentSlide.footerText && (
              <div className="mt-4 md:mt-6 text-center max-w-xs animate-fade-in" style={{ animationDelay: '0.5s' }}>
                  <p className="font-serif text-xl md:text-2xl text-romantic-text italic font-medium leading-relaxed drop-shadow-sm px-2">
                    {currentSlide.footerText}
                  </p>
              </div>
            )}
          </div>
        );

      case SlideType.MEMORY:
        return (
          <div className={`flex flex-col items-center justify-center h-full px-6 pb-20 animate-fade-in ${currentSlide.textAlign === 'text-left' ? 'items-start' : ''}`}>
            {/* First Image - Now supports containerClass for resizing */}
            <div className={`relative p-3 bg-white shadow-2xl mb-4 ${currentSlide.containerClass || 'w-full max-w-sm'} ${currentSlide.imageRotate || 'rotate-2'}`}>
              <div className={`${currentSlide.aspectRatio === 'aspect-auto' ? '' : (currentSlide.aspectRatio || 'aspect-[3/4]')} ${currentSlide.aspectRatio === 'aspect-auto' ? '' : 'overflow-hidden'} bg-gray-200`}>
                <img 
                  src={currentSlide.image} 
                  alt={currentSlide.title} 
                  className={`w-full ${currentSlide.aspectRatio === 'aspect-auto' ? 'h-auto' : 'h-full object-cover'}`}
                />
              </div>
              <div className="absolute -bottom-10 right-0 font-script text-4xl text-romantic-secondary/50 opacity-50 z-[-1]">
                {currentSlide.watermark || 'Anılar'}
              </div>
            </div>

            {/* Second Image (if exists) */}
            {currentSlide.secondImage && (
              <div className={`relative p-3 bg-white shadow-2xl mb-8 w-full max-w-sm ${currentSlide.imageRotate ? '-'+currentSlide.imageRotate : '-rotate-2'}`}>
                <div className={`${currentSlide.aspectRatio || 'aspect-[3/4]'} overflow-hidden bg-gray-200`}>
                  <img 
                    src={currentSlide.secondImage} 
                    alt={currentSlide.title} 
                    className="w-full h-full object-cover"
                  />
                </div>
              </div>
            )}

            <div className={`w-full max-w-sm ${currentSlide.textAlign || 'text-center'}`}>
              <h2 className="font-serif text-3xl mb-4 text-romantic-text">{currentSlide.title}</h2>
              <p className="font-sans text-lg leading-relaxed text-romantic-text/80 whitespace-pre-line">
                {currentSlide.text}
              </p>
              {currentSlide.author && (
                <p className="mt-2 text-sm text-romantic-secondary italic text-right font-serif">
                  — {currentSlide.author}
                </p>
              )}
            </div>
          </div>
        );

      case SlideType.COLLAGE:
        // Determine layout styles
        let layoutClass = "grid grid-cols-2 gap-3"; // Default Grid
        if (currentSlide.collageLayout === 'row') {
           layoutClass = "flex flex-row gap-2 h-64 justify-center items-center";
        } else if (currentSlide.collageLayout === 'col') {
           layoutClass = "flex flex-col gap-4 w-full mx-auto";
        }

        return (
          <div className="flex flex-col items-center justify-center h-full px-6 animate-fade-in">
             <h2 className="font-serif text-3xl mb-6 text-romantic-text text-center">{currentSlide.title}</h2>

             <div className={`w-full max-w-md bg-white p-3 shadow-xl transform rotate-1 ${layoutClass}`}>
                {currentSlide.collageImages?.map((img, idx) => (
                  <div key={idx} className={`bg-gray-100 rounded-sm ${
                    currentSlide.collageLayout === 'row' ? 'flex-1 h-full overflow-hidden' : 
                    currentSlide.collageLayout === 'col' ? 'w-full' : // Let image define height for col
                    'aspect-square overflow-hidden'
                  }`}>
                    <img src={img} alt={`Collage ${idx}`} className={`w-full hover:scale-110 transition-transform duration-500 ${
                      currentSlide.collageLayout === 'col' ? 'h-auto' : 'h-full object-cover'
                    }`} />
                  </div>
                ))}
             </div>

             {currentSlide.text && (
              <div className="mt-12 text-center">
                  <p className="font-script text-3xl text-romantic-text whitespace-pre-line leading-relaxed">{currentSlide.text}</p>
              </div>
             )}
          </div>
        );

      case SlideType.MESSAGE:
        return (
          <div className="flex flex-col items-center justify-center h-full px-8 text-center animate-fade-in relative">
            <div className="font-serif text-6xl text-romantic-primary opacity-20 absolute top-[20%] left-4">"</div>
            <h2 className="font-serif text-3xl md:text-4xl leading-relaxed text-romantic-text italic relative z-10">
              {currentSlide.text}
            </h2>
            <div className="font-serif text-6xl text-romantic-primary opacity-20 absolute bottom-[20%] right-4">"</div>
            <div className="mt-8">
               <Heart className="text-romantic-accent fill-current animate-pulse-slow" size={32} />
            </div>
          </div>
        );

      case SlideType.MUSIC:
        return (
          <div className="flex flex-col items-center justify-center h-full px-6 animate-fade-in">
             <div className="w-48 h-48 bg-gradient-to-br from-romantic-primary to-romantic-secondary rounded-full shadow-2xl flex items-center justify-center mb-10 animate-spin" style={{ animationDuration: '10s' }}>
                <Music size={64} className="text-white" />
             </div>
             <div className="text-center mb-8">
                <h3 className="font-serif text-2xl font-bold text-romantic-text mb-1">{currentSlide.title}</h3>
                <p className="font-sans text-sm text-romantic-secondary uppercase tracking-widest">{currentSlide.text}</p>
             </div>
             <div className="space-y-2 text-center">
               {currentSlide.extra?.map((line, i) => (
                 <p key={i} className="font-serif text-xl italic text-romantic-text/70">
                   {line}
                 </p>
               ))}
             </div>
          </div>
        );

      case SlideType.DREAMS:
        return (
          <div className="flex flex-col items-center justify-center h-full px-8 animate-fade-in">
            <h2 className="font-script text-5xl mb-12 text-romantic-text">{currentSlide.title}</h2>
            <ul className="space-y-6 w-full max-w-md">
              {currentSlide.extra?.map((item, i) => (
                <li key={i} className="flex items-center gap-4 group">
                  <span className="w-8 h-8 flex items-center justify-center rounded-full bg-romantic-primary/20 text-romantic-accent group-hover:bg-romantic-accent group-hover:text-white transition-colors duration-300">
                    <Heart size={14} className="fill-current" />
                  </span>
                  <span className="font-serif text-xl text-romantic-text border-b border-transparent group-hover:border-romantic-primary transition-all">
                    {item}
                  </span>
                </li>
              ))}
            </ul>
          </div>
        );

      case SlideType.VIDEO:
        return (
          <div className="flex flex-col items-center justify-center h-full w-full animate-fade-in relative z-50 p-4">
             {currentSlide.title && (
               <h2 className="font-serif text-2xl mb-4 text-romantic-text text-center">{currentSlide.title}</h2>
             )}
             <div className="w-full max-w-sm aspect-[9/16] max-h-[70vh] rounded-2xl overflow-hidden shadow-2xl border-4 border-white/50 bg-black">
               <iframe 
                  width="100%" 
                  height="100%" 
                  src={`https://www.youtube.com/embed/${currentSlide.videoId}?autoplay=1&rel=0&loop=1&playlist=${currentSlide.videoId}&controls=0&showinfo=0&modestbranding=1&iv_load_policy=3&fs=0`} 
                  title="YouTube video player" 
                  frameBorder="0" 
                  allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share" 
                  allowFullScreen
                  className="w-full h-full object-cover"
               ></iframe>
             </div>
          </div>
        );

      case SlideType.FINAL:
        return (
          <div className="flex flex-col items-center justify-center h-full px-6 text-center animate-fade-in">
            <h1 className="font-script text-6xl mb-6 text-romantic-text">{currentSlide.title}</h1>
            <p className="font-serif text-xl text-romantic-secondary mb-12">{currentSlide.text}</p>

            <div 
              className="relative cursor-pointer group"
              onClick={(e) => {
                e.stopPropagation();
                setCurrentIndex(prev => prev + 1);
              }}
            >
              <Heart size={150} className="text-romantic-accent fill-current animate-pulse group-hover:scale-110 transition-transform duration-300" />
              <span className="absolute inset-0 flex items-center justify-center text-white font-bold font-sans text-sm tracking-wider animate-bounce">
                Buraya Bas
              </span>
            </div>

            <button 
              onClick={restart}
              className="mt-20 text-xs font-sans uppercase tracking-widest text-romantic-secondary/50 hover:text-romantic-secondary transition-colors z-50 p-4 cursor-pointer"
            >
              Başa Dön ↺
            </button>
          </div>
        );

      default:
        return null;
    }
  };

  return (
    <div 
      onClick={handleInteraction}
      className="relative w-full h-[100dvh] bg-romantic-bg overflow-hidden cursor-pointer select-none"
    >
      {/* Hidden YouTube Player */}
      <div id="youtube-player" className="absolute top-0 left-0 opacity-0 pointer-events-none -z-50 h-0 w-0" />

      <ProgressBar total={SLIDES.length} current={currentIndex} />
      <FloatingHearts />

      {/* Background Gradient Mesh Effect */}
      <div className="absolute top-[-20%] right-[-10%] w-[500px] h-[500px] bg-romantic-primary/20 rounded-full blur-[100px] pointer-events-none" />
      <div className="absolute bottom-[-10%] left-[-10%] w-[400px] h-[400px] bg-romantic-secondary/20 rounded-full blur-[80px] pointer-events-none" />

      {/* Main Content Area */}
      <main className="relative z-10 w-full h-full max-w-lg mx-auto transition-all duration-700 ease-in-out">
        {renderContent()}
      </main>

      {/* Footer Navigation Hints & Page Number */}
      {currentIndex > 0 && (
        <div 
          className="absolute bottom-12 md:bottom-8 w-full z-50 pointer-events-none px-8"
          style={{ paddingBottom: 'env(safe-area-inset-bottom)' }}
        >
          <div className="flex items-center justify-between text-romantic-text/40">
            {/* Left Hint (Previous) */}
            <div className={`w-24 flex justify-start transition-opacity duration-300 ${currentIndex > 1 ? 'opacity-100 animate-pulse' : 'opacity-0'}`}>
               <div className="flex items-center gap-1 font-sans text-[10px] uppercase tracking-widest">
                 <ChevronLeft size={10} /> Geri
               </div>
            </div>

            {/* Page Number */}
            <div className="font-serif text-sm font-medium tracking-widest opacity-60">
              {currentIndex} / {SLIDES.length - 1}
            </div>

            {/* Right Hint (Next) */}
            <div className={`w-24 flex justify-end transition-opacity duration-300 ${currentIndex < SLIDES.length - 1 ? 'opacity-100 animate-pulse' : 'opacity-0'}`}>
               <div className="flex items-center gap-1 font-sans text-[10px] uppercase tracking-widest">
                 İleri <ChevronRight size={10} />
               </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { Play, Music, Heart, ChevronRight, ChevronLeft, Volume2, Lock, ArrowLeft, Phone, Video, MoreVertical, ChevronsDown, VolumeX } from 'lucide-react';
import { SLIDES, YOUTUBE_VIDEO_ID } from './constants';
import { SlideType } from './types';
import ProgressBar from './components/ProgressBar';
import FloatingHearts from './components/FloatingHearts';

// Helper to access window globals for YouTube API
declare global {
  interface Window {
    onYouTubeIframeAPIReady: () => void;
    YT: any;
  }
}

const App: React.FC = () => {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [isPlaying, setIsPlaying] = useState(false);
  const [password, setPassword] = useState('');
  const [error, setError] = useState(false);
  const playerRef = useRef<any>(null);

  // Initialize YouTube API
  useEffect(() => {
    // 1. Load the IFrame Player API code asynchronously.
    if (!window.YT) {
      const tag = document.createElement('script');
      tag.src = "https://www.youtube.com/iframe_api";
      const firstScriptTag = document.getElementsByTagName('script')[0];
      firstScriptTag.parentNode?.insertBefore(tag, firstScriptTag);
    }

    // 2. This function creates an <iframe> (and YouTube player)
    //    after the API code downloads.
    window.onYouTubeIframeAPIReady = () => {
      playerRef.current = new window.YT.Player('youtube-player', {
        height: '1', // iOS requires non-zero dimensions for playback
        width: '1',  // iOS requires non-zero dimensions for playback
        videoId: YOUTUBE_VIDEO_ID,
        playerVars: {
          'playsinline': 1, // Crucial for iOS inline playback
          'controls': 0,
          'disablekb': 1,
          'fs': 0,
          'loop': 1,
          'playlist': YOUTUBE_VIDEO_ID // Required for loop to work
        },
        events: {
          'onReady': (event: any) => {
             event.target.setVolume(50); // Set volume to 50%
          }
        }
      });
    };

    return () => {
      if (playerRef.current && playerRef.current.destroy) {
        playerRef.current.destroy();
      }
    };
  }, []);

  // Handle slide changes for audio
  useEffect(() => {
    if (currentIndex === 0) return; // Intro handled separately

    const currentSlide = SLIDES[currentIndex];

    if (currentSlide.type === SlideType.VIDEO) {
        // Pause background audio when on VIDEO slide
        if (playerRef.current && playerRef.current.pauseVideo) {
            playerRef.current.pauseVideo();
            setIsPlaying(false);
        }
    } else {
        // Resume background audio if we are NOT on video slide and NOT playing
        // This handles navigating away from the video slide
        if (!isPlaying && playerRef.current && playerRef.current.playVideo) {
            playerRef.current.playVideo();
            setIsPlaying(true);
        }
    }
  }, [currentIndex]);

  const handleStart = (e: React.MouseEvent) => {
    e.stopPropagation(); // Prevent main click handler

    // Normalize input: lowercase and remove spaces
    const cleanInput = password.toLowerCase().replace(/\s/g, '');

    if (cleanInput === 'seniseviyorum') {
      // Correct password
      // Important: playVideo must be directly in the event loop for iOS
      if (playerRef.current && playerRef.current.playVideo) {
        playerRef.current.playVideo();
        setIsPlaying(true);
      }
      setCurrentIndex(1);
      setError(false);
    } else {
      // Incorrect password
      setError(true);
      // Shake animation reset
      setTimeout(() => setError(false), 500);
    }
  };

  const handleInteraction = useCallback((e: React.MouseEvent) => {
    // If on INTRO (index 0), do NOT auto advance. Must use password button.
    if (currentIndex === 0) {
      return;
    }

    // Audio Logic: Attempt to play YouTube video on first interaction if not playing
    // EXCEPTION: Do not start background music if on VIDEO slide
    if (SLIDES[currentIndex].type !== SlideType.VIDEO && !isPlaying && playerRef.current && playerRef.current.playVideo) {
      playerRef.current.playVideo();
      setIsPlaying(true);
    }

    // Navigation Logic
    const { clientX } = e;
    const { innerWidth } = window;

    // Right side click -> Next
    if (clientX > innerWidth / 2) {
      // If on FINAL slide, disable click-to-next on background. 
      // User must click the heart specifically.
      if (SLIDES[currentIndex].type === SlideType.FINAL) {
        return;
      }

      if (currentIndex < SLIDES.length - 1) {
        setCurrentIndex((prev) => prev + 1);
      }
    } 
    // Left side click -> Previous
    else {
      if (currentIndex > 0) {
        setCurrentIndex((prev) => prev - 1);
      }
    }
  }, [currentIndex, isPlaying]);

  const restart = (e: React.MouseEvent) => {
    e.stopPropagation();
    setCurrentIndex(0);
    setPassword('');
    setIsPlaying(false);
    if (playerRef.current && playerRef.current.stopVideo) {
       playerRef.current.stopVideo();
    }
  };

  const currentSlide = SLIDES[currentIndex];

  // Render content based on slide type
  const renderContent = () => {
    switch (currentSlide.type) {
      case SlideType.INTRO:
        return (
          <div className="flex flex-col items-center justify-center h-full text-center px-6 animate-fade-in relative">

            {/* Sesi Açın Uyarısı */}
            <div className="absolute top-[15%] animate-pulse-slow">
              <div className="flex items-center gap-2 bg-white/40 backdrop-blur-sm px-4 py-2 rounded-full border border-white/60 shadow-sm">
                <Volume2 size={16} className="text-romantic-text" />
                <span className="text-xs font-sans tracking-widest uppercase text-romantic-text font-semibold">Sesi Açın</span>
              </div>
            </div>

            <div className="w-full max-w-xs space-y-6 z-20">
              {/* Şifre Input */}
              <div className={`transition-transform duration-100 ${error ? 'translate-x-[-10px] border-red-400' : ''} ${error ? 'animate-[pulse_0.5s_ease-in-out]' : ''}`}>
                <div className="relative group">
                  <input
                    type="text"
                    value={password}
                    onChange={(e) => {
                      setPassword(e.target.value);
                      setError(false);
                    }}
                    onClick={(e) => e.stopPropagation()} // Prevent slide navigation when typing
                    placeholder="Sihirli sözcüğü giriniz..."
                    className={`w-full bg-white/60 backdrop-blur-md border-2 ${error ? 'border-red-300 text-red-500' : 'border-white/50 text-romantic-text'} rounded-full px-6 py-4 text-center outline-none focus:border-romantic-primary focus:bg-white/80 transition-all font-serif text-lg placeholder:text-romantic-text/40 shadow-lg`}
                  />
                  {!password && (
                    <Lock size={16} className="absolute right-5 top-1/2 -translate-y-1/2 text-romantic-text/30" />
                  )}
                </div>
              </div>

              {/* Başla Butonu */}
              <div className="flex justify-center">
                <button 
                  onClick={handleStart}
                  className="bg-romantic-primary text-white px-10 py-4 rounded-full shadow-xl font-serif tracking-widest uppercase text-sm flex items-center gap-3 transform hover:scale-105 active:scale-95 transition-all duration-300 hover:bg-romantic-accent"
                >
                  <Play size={18} className="fill-current" />
                  Başla
                </button>
              </div>
            </div>
          </div>
        );

      case SlideType.WHATSAPP:
        return (
          <div className="flex flex-col h-full items-center justify-start pt-16 px-4 animate-fade-in relative z-20">
            {/* Phone/Chat Container - Floating Card */}
            {/* Reduced height on mobile to allow space for footer text and navigation */}
            <div className="w-full max-w-[320px] h-[55vh] md:h-[68vh] bg-[#E5DDD5] rounded-2xl shadow-2xl overflow-hidden flex flex-col relative border border-gray-300 ring-4 ring-black/5 mx-auto transition-all duration-300">

              {/* WhatsApp Header */}
              <div className="bg-[#075E54] text-white p-2 px-3 flex items-center shadow-md z-10 shrink-0">
                <ArrowLeft size={18} className="mr-1" />
                <div className="w-8 h-8 bg-gray-300 rounded-full mr-2 flex items-center justify-center text-gray-500 overflow-hidden shrink-0">
                  <div className="bg-gray-400 w-full h-full flex items-center justify-center text-xs font-bold">A</div>
                </div>
                <div className="flex-1 overflow-hidden">
                  <h3 className="font-semibold text-sm leading-tight truncate">{currentSlide.title}</h3>
                  <p className="text-[10px] opacity-80 truncate">Çevrimiçi</p>
                </div>
                <div className="flex gap-3 ml-2">
                  <Video size={16} />
                  <Phone size={16} />
                  <MoreVertical size={16} />
                </div>
              </div>

              {/* Chat Area */}
              <div className="flex-1 p-3 bg-[#E5DDD5] relative overflow-y-auto scrollbar-hide">
                  {/* Background pattern */}
                  <div className="absolute inset-0 opacity-10 bg-[url('https://user-images.githubusercontent.com/15075759/28719144-86dc0f70-73b1-11e7-911d-60d70fcded21.png')] pointer-events-none"></div>

                  {/* Date Separator */}
                  <div className="flex justify-center mb-4 relative z-10">
                    <span className="bg-[#D4EAF4] text-gray-600 text-[10px] font-medium px-2 py-0.5 rounded-lg shadow-sm">
                      {currentSlide.date}
                    </span>
                  </div>

                  {/* Messages */}
                  <div className="space-y-2 relative z-10 pb-4">
                    {currentSlide.messages?.map((msg, idx) => (
                      <div key={idx} className={`flex ${msg.isSender ? 'justify-end' : 'justify-start'}`}>
                        <div className={`
                          max-w-[85%] p-1.5 px-2.5 rounded-lg shadow-sm text-xs relative
                          ${msg.isSender ? 'bg-[#E2FFC7] rounded-tr-none' : 'bg-white rounded-tl-none'}
                        `}>
                          <p className="text-[#303030] leading-snug pb-1 whitespace-pre-wrap">{msg.text}</p>
                          <div className="text-right">
                             <span className="text-[9px] text-gray-500">{msg.time}</span>
                          </div>
                        </div>
                      </div>
                    ))}
                  </div>
              </div>
            </div>

            <p className="mt-2 text-xs text-romantic-text/60 font-sans italic animate-pulse">(Mesajı aşağı kaydırabilirsin.)</p>

            {/* Footer Text - Outside and Distinct */}
            {currentSlide.footerText && (
              <div className="mt-4 md:mt-6 text-center max-w-xs animate-fade-in" style={{ animationDelay: '0.5s' }}>
                  <p className="font-serif text-xl md:text-2xl text-romantic-text italic font-medium leading-relaxed drop-shadow-sm px-2">
                    {currentSlide.footerText}
                  </p>
              </div>
            )}
          </div>
        );

      case SlideType.MEMORY:
        return (
          <div className={`flex flex-col items-center justify-center h-full px-6 pb-20 animate-fade-in ${currentSlide.textAlign === 'text-left' ? 'items-start' : ''}`}>
            {/* First Image - Now supports containerClass for resizing */}
            <div className={`relative p-3 bg-white shadow-2xl mb-4 ${currentSlide.containerClass || 'w-full max-w-sm'} ${currentSlide.imageRotate || 'rotate-2'}`}>
              <div className={`${currentSlide.aspectRatio === 'aspect-auto' ? '' : (currentSlide.aspectRatio || 'aspect-[3/4]')} ${currentSlide.aspectRatio === 'aspect-auto' ? '' : 'overflow-hidden'} bg-gray-200`}>
                <img 
                  src={currentSlide.image} 
                  alt={currentSlide.title} 
                  className={`w-full ${currentSlide.aspectRatio === 'aspect-auto' ? 'h-auto' : 'h-full object-cover'}`}
                />
              </div>
              <div className="absolute -bottom-10 right-0 font-script text-4xl text-romantic-secondary/50 opacity-50 z-[-1]">
                {currentSlide.watermark || 'Anılar'}
              </div>
            </div>

            {/* Second Image (if exists) */}
            {currentSlide.secondImage && (
              <div className={`relative p-3 bg-white shadow-2xl mb-8 w-full max-w-sm ${currentSlide.imageRotate ? '-'+currentSlide.imageRotate : '-rotate-2'}`}>
                <div className={`${currentSlide.aspectRatio || 'aspect-[3/4]'} overflow-hidden bg-gray-200`}>
                  <img 
                    src={currentSlide.secondImage} 
                    alt={currentSlide.title} 
                    className="w-full h-full object-cover"
                  />
                </div>
              </div>
            )}

            <div className={`w-full max-w-sm ${currentSlide.textAlign || 'text-center'}`}>
              <h2 className="font-serif text-3xl mb-4 text-romantic-text">{currentSlide.title}</h2>
              <p className="font-sans text-lg leading-relaxed text-romantic-text/80 whitespace-pre-line">
                {currentSlide.text}
              </p>
              {currentSlide.author && (
                <p className="mt-2 text-sm text-romantic-secondary italic text-right font-serif">
                  — {currentSlide.author}
                </p>
              )}
            </div>
          </div>
        );

      case SlideType.COLLAGE:
        // Determine layout styles
        let layoutClass = "grid grid-cols-2 gap-3"; // Default Grid
        if (currentSlide.collageLayout === 'row') {
           layoutClass = "flex flex-row gap-2 h-64 justify-center items-center";
        } else if (currentSlide.collageLayout === 'col') {
           layoutClass = "flex flex-col gap-4 w-full mx-auto";
        }

        return (
          <div className="flex flex-col items-center justify-center h-full px-6 animate-fade-in">
             <h2 className="font-serif text-3xl mb-6 text-romantic-text text-center">{currentSlide.title}</h2>

             <div className={`w-full max-w-md bg-white p-3 shadow-xl transform rotate-1 ${layoutClass}`}>
                {currentSlide.collageImages?.map((img, idx) => (
                  <div key={idx} className={`bg-gray-100 rounded-sm ${
                    currentSlide.collageLayout === 'row' ? 'flex-1 h-full overflow-hidden' : 
                    currentSlide.collageLayout === 'col' ? 'w-full' : // Let image define height for col
                    'aspect-square overflow-hidden'
                  }`}>
                    <img src={img} alt={`Collage ${idx}`} className={`w-full hover:scale-110 transition-transform duration-500 ${
                      currentSlide.collageLayout === 'col' ? 'h-auto' : 'h-full object-cover'
                    }`} />
                  </div>
                ))}
             </div>

             {currentSlide.text && (
              <div className="mt-12 text-center">
                  <p className="font-script text-3xl text-romantic-text whitespace-pre-line leading-relaxed">{currentSlide.text}</p>
              </div>
             )}
          </div>
        );

      case SlideType.MESSAGE:
        return (
          <div className="flex flex-col items-center justify-center h-full px-8 text-center animate-fade-in relative">
            <div className="font-serif text-6xl text-romantic-primary opacity-20 absolute top-[20%] left-4">"</div>
            <h2 className="font-serif text-3xl md:text-4xl leading-relaxed text-romantic-text italic relative z-10">
              {currentSlide.text}
            </h2>
            <div className="font-serif text-6xl text-romantic-primary opacity-20 absolute bottom-[20%] right-4">"</div>
            <div className="mt-8">
               <Heart className="text-romantic-accent fill-current animate-pulse-slow" size={32} />
            </div>
          </div>
        );

      case SlideType.MUSIC:
        return (
          <div className="flex flex-col items-center justify-center h-full px-6 animate-fade-in">
             <div className="w-48 h-48 bg-gradient-to-br from-romantic-primary to-romantic-secondary rounded-full shadow-2xl flex items-center justify-center mb-10 animate-spin" style={{ animationDuration: '10s' }}>
                <Music size={64} className="text-white" />
             </div>
             <div className="text-center mb-8">
                <h3 className="font-serif text-2xl font-bold text-romantic-text mb-1">{currentSlide.title}</h3>
                <p className="font-sans text-sm text-romantic-secondary uppercase tracking-widest">{currentSlide.text}</p>
             </div>
             <div className="space-y-2 text-center">
               {currentSlide.extra?.map((line, i) => (
                 <p key={i} className="font-serif text-xl italic text-romantic-text/70">
                   {line}
                 </p>
               ))}
             </div>
          </div>
        );

      case SlideType.DREAMS:
        return (
          <div className="flex flex-col items-center justify-center h-full px-8 animate-fade-in">
            <h2 className="font-script text-5xl mb-12 text-romantic-text">{currentSlide.title}</h2>
            <ul className="space-y-6 w-full max-w-md">
              {currentSlide.extra?.map((item, i) => (
                <li key={i} className="flex items-center gap-4 group">
                  <span className="w-8 h-8 flex items-center justify-center rounded-full bg-romantic-primary/20 text-romantic-accent group-hover:bg-romantic-accent group-hover:text-white transition-colors duration-300">
                    <Heart size={14} className="fill-current" />
                  </span>
                  <span className="font-serif text-xl text-romantic-text border-b border-transparent group-hover:border-romantic-primary transition-all">
                    {item}
                  </span>
                </li>
              ))}
            </ul>
          </div>
        );

      case SlideType.VIDEO:
        return (
          <div className="flex flex-col items-center justify-center h-full w-full animate-fade-in relative z-50 p-4">
             {currentSlide.title && (
               <h2 className="font-serif text-2xl mb-4 text-romantic-text text-center">{currentSlide.title}</h2>
             )}
             <div className="w-full max-w-sm aspect-[9/16] max-h-[70vh] rounded-2xl overflow-hidden shadow-2xl border-4 border-white/50 bg-black relative group">
               {/* 
                  iOS Fixes:
                  1. playsinline=1: Prevents fullscreen takeover and redirect logic
                  2. mute=1: Required for autoplay on mobile without user gesture on THIS iframe
                  3. controls=1: Allowed user to Unmute/Play if autoplay fails
               */}
               <iframe 
                  width="100%" 
                  height="100%" 
                  src={`https://www.youtube.com/embed/${currentSlide.videoId}?autoplay=1&playsinline=1&mute=1&rel=0&loop=1&playlist=${currentSlide.videoId}&controls=1&showinfo=0&modestbranding=1&iv_load_policy=3&fs=0`} 
                  title="YouTube video player" 
                  frameBorder="0" 
                  allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share" 
                  allowFullScreen
                  className="w-full h-full object-cover"
               ></iframe>
             </div>

             {/* iOS Hint */}
             <div className="mt-4 flex items-center gap-2 text-romantic-text/60 animate-pulse bg-white/50 px-3 py-1 rounded-full">
               <VolumeX size={14} />
               <p className="font-sans text-xs">Otomatik başlamazsa veya ses gelmezse videoya dokunun.</p>
             </div>
          </div>
        );

      case SlideType.FINAL:
        return (
          <div className="flex flex-col items-center justify-center h-full px-6 text-center animate-fade-in">
            <h1 className="font-script text-6xl mb-6 text-romantic-text">{currentSlide.title}</h1>
            <p className="font-serif text-xl text-romantic-secondary mb-12">{currentSlide.text}</p>

            <div 
              className="relative cursor-pointer group"
              onClick={(e) => {
                e.stopPropagation();
                setCurrentIndex(prev => prev + 1);
              }}
            >
              <Heart size={150} className="text-romantic-accent fill-current animate-pulse group-hover:scale-110 transition-transform duration-300" />
              <span className="absolute inset-0 flex items-center justify-center text-white font-bold font-sans text-sm tracking-wider animate-bounce">
                Buraya Bas
              </span>
            </div>

            <button 
              onClick={restart}
              className="mt-20 text-xs font-sans uppercase tracking-widest text-romantic-secondary/50 hover:text-romantic-secondary transition-colors z-50 p-4 cursor-pointer"
            >
              Başa Dön ↺
            </button>
          </div>
        );

      default:
        return null;
    }
  };

  return (
    <div 
      onClick={handleInteraction}
      className="relative w-full h-[100dvh] bg-romantic-bg overflow-hidden cursor-pointer select-none"
    >
      {/* 
        Hidden YouTube Player (Background Music)
        iOS Fix: Must be 1x1px (not 0x0) to prevent browser optimizing it away.
        Opacity set to almost 0 but technically visible to the renderer.
      */}
      <div id="youtube-player" className="absolute top-0 left-0 opacity-1 pointer-events-none -z-50 h-[1px] w-[1px]" />

      <ProgressBar total={SLIDES.length} current={currentIndex} />
      <FloatingHearts />

      {/* Background Gradient Mesh Effect */}
      <div className="absolute top-[-20%] right-[-10%] w-[500px] h-[500px] bg-romantic-primary/20 rounded-full blur-[100px] pointer-events-none" />
      <div className="absolute bottom-[-10%] left-[-10%] w-[400px] h-[400px] bg-romantic-secondary/20 rounded-full blur-[80px] pointer-events-none" />

      {/* Main Content Area */}
      <main className="relative z-10 w-full h-full max-w-lg mx-auto transition-all duration-700 ease-in-out">
        {renderContent()}
      </main>

      {/* Footer Navigation Hints & Page Number */}
      {currentIndex > 0 && (
        <div 
          className="absolute bottom-12 md:bottom-8 w-full z-50 pointer-events-none px-8"
          style={{ paddingBottom: 'env(safe-area-inset-bottom)' }}
        >
          <div className="flex items-center justify-between text-romantic-text/40">
            {/* Left Hint (Previous) */}
            <div className={`w-24 flex justify-start transition-opacity duration-300 ${currentIndex > 1 ? 'opacity-100 animate-pulse' : 'opacity-0'}`}>
               <div className="flex items-center gap-1 font-sans text-[10px] uppercase tracking-widest">
                 <ChevronLeft size={10} /> Geri
               </div>
            </div>

            {/* Page Number */}
            <div className="font-serif text-sm font-medium tracking-widest opacity-60">
              {currentIndex} / {SLIDES.length - 1}
            </div>

            {/* Right Hint (Next) */}
            <div className={`w-24 flex justify-end transition-opacity duration-300 ${currentIndex < SLIDES.length - 1 ? 'opacity-100 animate-pulse' : 'opacity-0'}`}>
               <div className="flex items-center gap-1 font-sans text-[10px] uppercase tracking-widest">
                 İleri <ChevronRight size={10} />
               </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { Play, Music, Heart, ChevronRight, ChevronLeft, Volume2, Lock, ArrowLeft, Phone, Video, MoreVertical, ChevronsDown, VolumeX } from 'lucide-react';
import { SLIDES, YOUTUBE_VIDEO_ID } from './constants';
import { SlideType } from './types';
import ProgressBar from './components/ProgressBar';
import FloatingHearts from './components/FloatingHearts';

// Helper to access window globals for YouTube API
declare global {
  interface Window {
    onYouTubeIframeAPIReady: () => void;
    YT: any;
  }
}

const App: React.FC = () => {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [isPlaying, setIsPlaying] = useState(false);
  const [password, setPassword] = useState('');
  const [error, setError] = useState(false);
  const playerRef = useRef<any>(null);

  // Countdown State
  const [timeLeft, setTimeLeft] = useState({
    days: 0,
    hours: 0,
    minutes: 0,
    seconds: 0
  });

  // Calculate Countdown
  useEffect(() => {
    const targetDate = new Date('2026-04-25T00:00:00').getTime();

    const interval = setInterval(() => {
      const now = new Date().getTime();
      const difference = targetDate - now;

      if (difference <= 0) {
        clearInterval(interval);
        setTimeLeft({ days: 0, hours: 0, minutes: 0, seconds: 0 });
      } else {
        setTimeLeft({
          days: Math.floor(difference / (1000 * 60 * 60 * 24)),
          hours: Math.floor((difference % (1000 * 60 * 60 * 24)) / (1000 * 60 * 60)),
          minutes: Math.floor((difference % (1000 * 60 * 60)) / (1000 * 60)),
          seconds: Math.floor((difference % (1000 * 60)) / 1000)
        });
      }
    }, 1000);

    return () => clearInterval(interval);
  }, []);

  // Initialize YouTube API
  useEffect(() => {
    if (!window.YT) {
      const tag = document.createElement('script');
      tag.src = "https://www.youtube.com/iframe_api";
      const firstScriptTag = document.getElementsByTagName('script')[0];
      firstScriptTag.parentNode?.insertBefore(tag, firstScriptTag);
    }

    window.onYouTubeIframeAPIReady = () => {
      playerRef.current = new window.YT.Player('youtube-player', {
        height: '1',
        width: '1',
        videoId: YOUTUBE_VIDEO_ID,
        playerVars: {
          'playsinline': 1,
          'controls': 0,
          'disablekb': 1,
          'fs': 0,
          'loop': 1,
          'playlist': YOUTUBE_VIDEO_ID
        },
        events: {
          'onReady': (event: any) => {
             event.target.setVolume(50);
          }
        }
      });
    };

    return () => {
      if (playerRef.current && playerRef.current.destroy) {
        playerRef.current.destroy();
      }
    };
  }, []);

  useEffect(() => {
    if (currentIndex === 0) return;
    const currentSlide = SLIDES[currentIndex];
    if (currentSlide.type === SlideType.VIDEO) {
        if (playerRef.current && playerRef.current.pauseVideo) {
            playerRef.current.pauseVideo();
            setIsPlaying(false);
        }
    } else {
        if (!isPlaying && playerRef.current && playerRef.current.playVideo) {
            playerRef.current.playVideo();
            setIsPlaying(true);
        }
    }
  }, [currentIndex]);

  const handleStart = (e: React.MouseEvent) => {
    e.stopPropagation();
    const cleanInput = password.toLowerCase().replace(/\s/g, '');
    if (cleanInput === 'seniseviyorum') {
      if (playerRef.current && playerRef.current.playVideo) {
        playerRef.current.playVideo();
        setIsPlaying(true);
      }
      setCurrentIndex(1);
      setError(false);
    } else {
      setError(true);
      setTimeout(() => setError(false), 500);
    }
  };

  const handleInteraction = useCallback((e: React.MouseEvent) => {
    if (currentIndex === 0) return;
    if (SLIDES[currentIndex].type !== SlideType.VIDEO && !isPlaying && playerRef.current && playerRef.current.playVideo) {
      playerRef.current.playVideo();
      setIsPlaying(true);
    }
    const { clientX } = e;
    const { innerWidth } = window;
    if (clientX > innerWidth / 2) {
      if (SLIDES[currentIndex].type === SlideType.FINAL) return;
      if (currentIndex < SLIDES.length - 1) setCurrentIndex((prev) => prev + 1);
    } else {
      if (currentIndex > 0) setCurrentIndex((prev) => prev - 1);
    }
  }, [currentIndex, isPlaying]);

  const restart = (e: React.MouseEvent) => {
    e.stopPropagation();
    setCurrentIndex(0);
    setPassword('');
    setIsPlaying(false);
    if (playerRef.current && playerRef.current.stopVideo) {
       playerRef.current.stopVideo();
    }
  };

  const renderContent = () => {
    const currentSlide = SLIDES[currentIndex];
    switch (currentSlide.type) {
      case SlideType.INTRO:
        return (
          <div className="flex flex-col items-center justify-center h-full text-center px-6 animate-fade-in relative">
            <div className="absolute top-[8%] animate-pulse-slow">
              <div className="flex items-center gap-2 bg-white/40 backdrop-blur-sm px-4 py-2 rounded-full border border-white/60 shadow-sm">
                <Volume2 size={16} className="text-romantic-text" />
                <span className="text-xs font-sans tracking-widest uppercase text-romantic-text font-semibold">Sesi Açın</span>
              </div>
            </div>

            {/* Countdown Section */}
            <div className="mb-10 w-full max-w-sm">
              <h2 className="font-serif text-2xl md:text-3xl text-romantic-text mb-6 drop-shadow-sm">En Güzel Günümüze</h2>
              <div className="grid grid-cols-4 gap-2 md:gap-4 px-2">
                {[
                  { label: 'Gün', value: timeLeft.days },
                  { label: 'Saat', value: timeLeft.hours },
                  { label: 'Dak', value: timeLeft.minutes },
                  { label: 'Sn', value: timeLeft.seconds }
                ].map((item, idx) => (
                  <div key={idx} className="bg-white/50 backdrop-blur-md rounded-2xl p-2 md:p-3 border border-white/40 shadow-sm flex flex-col items-center">
                    <span className="font-sans text-xl md:text-2xl font-bold text-romantic-accent tabular-nums">
                      {String(item.value).padStart(2, '0')}
                    </span>
                    <span className="font-serif text-[10px] md:text-xs uppercase tracking-widest text-romantic-text/70">
                      {item.label}
                    </span>
                  </div>
                ))}
              </div>
            </div>

            <div className="w-full max-w-xs space-y-6 z-20">
              <div className={`transition-transform duration-100 ${error ? 'translate-x-[-10px] border-red-400' : ''} ${error ? 'animate-[pulse_0.5s_ease-in-out]' : ''}`}>
                <div className="relative group">
                  <input
                    type="text"
                    value={password}
                    onChange={(e) => {
                      setPassword(e.target.value);
                      setError(false);
                    }}
                    onClick={(e) => e.stopPropagation()}
                    placeholder="Sihirli sözcüğü giriniz..."
                    className={`w-full bg-white/60 backdrop-blur-md border-2 ${error ? 'border-red-300 text-red-500' : 'border-white/50 text-romantic-text'} rounded-full px-6 py-4 text-center outline-none focus:border-romantic-primary focus:bg-white/80 transition-all font-serif text-lg placeholder:text-romantic-text/40 shadow-lg`}
                  />
                  {!password && <Lock size={16} className="absolute right-5 top-1/2 -translate-y-1/2 text-romantic-text/30" />}
                </div>
              </div>
              <div className="flex justify-center">
                <button 
                  onClick={handleStart}
                  className="bg-romantic-primary text-white px-10 py-4 rounded-full shadow-xl font-serif tracking-widest uppercase text-sm flex items-center gap-3 transform hover:scale-105 active:scale-95 transition-all duration-300 hover:bg-romantic-accent"
                >
                  <Play size={18} className="fill-current" />
                  Başla
                </button>
              </div>
            </div>
          </div>
        );

      case SlideType.WHATSAPP:
        return (
          <div className="flex flex-col h-full items-center justify-start pt-16 px-4 animate-fade-in relative z-20">
            <div className="w-full max-w-[320px] h-[55vh] md:h-[68vh] bg-[#E5DDD5] rounded-2xl shadow-2xl overflow-hidden flex flex-col relative border border-gray-300 ring-4 ring-black/5 mx-auto transition-all duration-300">
              <div className="bg-[#075E54] text-white p-2 px-3 flex items-center shadow-md z-10 shrink-0">
                <ArrowLeft size={18} className="mr-1" />
                <div className="w-8 h-8 bg-gray-300 rounded-full mr-2 flex items-center justify-center text-gray-500 overflow-hidden shrink-0">
                  <div className="bg-gray-400 w-full h-full flex items-center justify-center text-xs font-bold">A</div>
                </div>
                <div className="flex-1 overflow-hidden">
                  <h3 className="font-semibold text-sm leading-tight truncate">{currentSlide.title}</h3>
                  <p className="text-[10px] opacity-80 truncate">Çevrimiçi</p>
                </div>
                <div className="flex gap-3 ml-2">
                  <Video size={16} />
                  <Phone size={16} />
                  <MoreVertical size={16} />
                </div>
              </div>
              <div className="flex-1 p-3 bg-[#E5DDD5] relative overflow-y-auto scrollbar-hide">
                  <div className="absolute inset-0 opacity-10 bg-[url('https://user-images.githubusercontent.com/15075759/28719144-86dc0f70-73b1-11e7-911d-60d70fcded21.png')] pointer-events-none"></div>
                  <div className="flex justify-center mb-4 relative z-10">
                    <span className="bg-[#D4EAF4] text-gray-600 text-[10px] font-medium px-2 py-0.5 rounded-lg shadow-sm">{currentSlide.date}</span>
                  </div>
                  <div className="space-y-2 relative z-10 pb-4">
                    {currentSlide.messages?.map((msg, idx) => (
                      <div key={idx} className={`flex ${msg.isSender ? 'justify-end' : 'justify-start'}`}>
                        <div className={`max-w-[85%] p-1.5 px-2.5 rounded-lg shadow-sm text-xs relative ${msg.isSender ? 'bg-[#E2FFC7] rounded-tr-none' : 'bg-white rounded-tl-none'}`}>
                          <p className="text-[#303030] leading-snug pb-1 whitespace-pre-wrap">{msg.text}</p>
                          <div className="text-right"><span className="text-[9px] text-gray-500">{msg.time}</span></div>
                        </div>
                      </div>
                    ))}
                  </div>
              </div>
            </div>
            <p className="mt-2 text-xs text-romantic-text/60 font-sans italic animate-pulse">(Mesajı aşağı kaydırabilirsin.)</p>
            {currentSlide.footerText && (
              <div className="mt-4 md:mt-6 text-center max-w-xs animate-fade-in" style={{ animationDelay: '0.5s' }}>
                  <p className="font-serif text-xl md:text-2xl text-romantic-text italic font-medium leading-relaxed drop-shadow-sm px-2">{currentSlide.footerText}</p>
              </div>
            )}
          </div>
        );

      case SlideType.MEMORY:
        return (
          <div className={`flex flex-col items-center justify-center h-full px-6 pb-20 animate-fade-in ${currentSlide.textAlign === 'text-left' ? 'items-start' : ''}`}>
            <div className={`relative p-3 bg-white shadow-2xl mb-4 ${currentSlide.containerClass || 'w-full max-w-sm'} ${currentSlide.imageRotate || 'rotate-2'}`}>
              <div className={`${currentSlide.aspectRatio === 'aspect-auto' ? '' : (currentSlide.aspectRatio || 'aspect-[3/4]')} ${currentSlide.aspectRatio === 'aspect-auto' ? '' : 'overflow-hidden'} bg-gray-200`}>
                <img src={currentSlide.image} alt={currentSlide.title} className={`w-full ${currentSlide.aspectRatio === 'aspect-auto' ? 'h-auto' : 'h-full object-cover'}`} />
              </div>
              <div className="absolute -bottom-10 right-0 font-script text-4xl text-romantic-secondary/50 opacity-50 z-[-1]">{currentSlide.watermark || 'Anılar'}</div>
            </div>
            {currentSlide.secondImage && (
              <div className={`relative p-3 bg-white shadow-2xl mb-8 w-full max-w-sm ${currentSlide.imageRotate ? '-'+currentSlide.imageRotate : '-rotate-2'}`}>
                <div className={`${currentSlide.aspectRatio || 'aspect-[3/4]'} overflow-hidden bg-gray-200`}>
                  <img src={currentSlide.secondImage} alt={currentSlide.title} className="w-full h-full object-cover" />
                </div>
              </div>
            )}
            <div className={`w-full max-w-sm ${currentSlide.textAlign || 'text-center'}`}>
              <h2 className="font-serif text-3xl mb-4 text-romantic-text">{currentSlide.title}</h2>
              <p className="font-sans text-lg leading-relaxed text-romantic-text/80 whitespace-pre-line">{currentSlide.text}</p>
              {currentSlide.author && <p className="mt-2 text-sm text-romantic-secondary italic text-right font-serif">— {currentSlide.author}</p>}
            </div>
          </div>
        );

      case SlideType.COLLAGE:
        let layoutClass = "grid grid-cols-2 gap-3";
        if (currentSlide.collageLayout === 'row') layoutClass = "flex flex-row gap-2 h-64 justify-center items-center";
        else if (currentSlide.collageLayout === 'col') layoutClass = "flex flex-col gap-4 w-full mx-auto";
        return (
          <div className="flex flex-col items-center justify-center h-full px-6 animate-fade-in">
             <h2 className="font-serif text-3xl mb-6 text-romantic-text text-center">{currentSlide.title}</h2>
             <div className={`w-full max-w-md bg-white p-3 shadow-xl transform rotate-1 ${layoutClass}`}>
                {currentSlide.collageImages?.map((img, idx) => (
                  <div key={idx} className={`bg-gray-100 rounded-sm ${currentSlide.collageLayout === 'row' ? 'flex-1 h-full overflow-hidden' : currentSlide.collageLayout === 'col' ? 'w-full' : 'aspect-square overflow-hidden'}`}>
                    <img src={img} alt={`Collage ${idx}`} className={`w-full hover:scale-110 transition-transform duration-500 ${currentSlide.collageLayout === 'col' ? 'h-auto' : 'h-full object-cover'}`} />
                  </div>
                ))}
             </div>
             {currentSlide.text && <div className="mt-12 text-center"><p className="font-script text-3xl text-romantic-text whitespace-pre-line leading-relaxed">{currentSlide.text}</p></div>}
          </div>
        );

      case SlideType.MESSAGE:
        return (
          <div className="flex flex-col items-center justify-center h-full px-8 text-center animate-fade-in relative">
            <div className="font-serif text-6xl text-romantic-primary opacity-20 absolute top-[20%] left-4">"</div>
            <h2 className="font-serif text-3xl md:text-4xl leading-relaxed text-romantic-text italic relative z-10">{currentSlide.text}</h2>
            <div className="font-serif text-6xl text-romantic-primary opacity-20 absolute bottom-[20%] right-4">"</div>
            <div className="mt-8"><Heart className="text-romantic-accent fill-current animate-pulse-slow" size={32} /></div>
          </div>
        );

      case SlideType.MUSIC:
        return (
          <div className="flex flex-col items-center justify-center h-full px-6 animate-fade-in">
             <div className="w-48 h-48 bg-gradient-to-br from-romantic-primary to-romantic-secondary rounded-full shadow-2xl flex items-center justify-center mb-10 animate-spin" style={{ animationDuration: '10s' }}><Music size={64} className="text-white" /></div>
             <div className="text-center mb-8">
                <h3 className="font-serif text-2xl font-bold text-romantic-text mb-1">{currentSlide.title}</h3>
                <p className="font-sans text-sm text-romantic-secondary uppercase tracking-widest">{currentSlide.text}</p>
             </div>
             <div className="space-y-2 text-center">
               {currentSlide.extra?.map((line, i) => <p key={i} className="font-serif text-xl italic text-romantic-text/70">{line}</p>)}
             </div>
          </div>
        );

      case SlideType.DREAMS:
        return (
          <div className="flex flex-col items-center justify-center h-full px-8 animate-fade-in">
            <h2 className="font-script text-5xl mb-12 text-romantic-text">{currentSlide.title}</h2>
            <ul className="space-y-6 w-full max-w-md">
              {currentSlide.extra?.map((item, i) => (
                <li key={i} className="flex items-center gap-4 group">
                  <span className="w-8 h-8 flex items-center justify-center rounded-full bg-romantic-primary/20 text-romantic-accent group-hover:bg-romantic-accent group-hover:text-white transition-colors duration-300"><Heart size={14} className="fill-current" /></span>
                  <span className="font-serif text-xl text-romantic-text border-b border-transparent group-hover:border-romantic-primary transition-all">{item}</span>
                </li>
              ))}
            </ul>
          </div>
        );

      case SlideType.VIDEO:
        return (
          <div className="flex flex-col items-center justify-center h-full w-full animate-fade-in relative z-50 p-4">
             {currentSlide.title && <h2 className="font-serif text-2xl mb-4 text-romantic-text text-center">{currentSlide.title}</h2>}
             <div className="w-full max-w-sm aspect-[9/16] max-h-[70vh] rounded-2xl overflow-hidden shadow-2xl border-4 border-white/50 bg-black relative group">
               <iframe width="100%" height="100%" src={`https://www.youtube.com/embed/${currentSlide.videoId}?autoplay=1&playsinline=1&mute=1&rel=0&loop=1&playlist=${currentSlide.videoId}&controls=1&showinfo=0&modestbranding=1&iv_load_policy=3&fs=0`} title="YouTube video player" frameBorder="0" allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share" allowFullScreen className="w-full h-full object-cover"></iframe>
             </div>
             <div className="mt-4 flex items-center gap-2 text-romantic-text/60 animate-pulse bg-white/50 px-3 py-1 rounded-full"><VolumeX size={14} /><p className="font-sans text-xs">Otomatik başlamazsa veya ses gelmezse videoya dokunun.</p></div>
          </div>
        );

      case SlideType.FINAL:
        return (
          <div className="flex flex-col items-center justify-center h-full px-6 text-center animate-fade-in">
            <h1 className="font-script text-6xl mb-6 text-romantic-text">{currentSlide.title}</h1>
            <p className="font-serif text-xl text-romantic-secondary mb-12">{currentSlide.text}</p>
            <div className="relative cursor-pointer group" onClick={(e) => { e.stopPropagation(); setCurrentIndex(prev => prev + 1); }}>
              <Heart size={150} className="text-romantic-accent fill-current animate-pulse group-hover:scale-110 transition-transform duration-300" />
              <span className="absolute inset-0 flex items-center justify-center text-white font-bold font-sans text-sm tracking-wider animate-bounce">Buraya Bas</span>
            </div>
            <button onClick={restart} className="mt-20 text-xs font-sans uppercase tracking-widest text-romantic-secondary/50 hover:text-romantic-secondary transition-colors z-50 p-4 cursor-pointer">Başa Dön ↺</button>
          </div>
        );
      default: return null;
    }
  };

  return (
    <div onClick={handleInteraction} className="relative w-full h-[100dvh] bg-romantic-bg overflow-hidden cursor-pointer select-none">
      <div id="youtube-player" className="absolute top-0 left-0 opacity-1 pointer-events-none -z-50 h-[1px] w-[1px]" />
      <ProgressBar total={SLIDES.length} current={currentIndex} />
      <FloatingHearts />
      <div className="absolute top-[-20%] right-[-10%] w-[500px] h-[500px] bg-romantic-primary/20 rounded-full blur-[100px] pointer-events-none" />
      <div className="absolute bottom-[-10%] left-[-10%] w-[400px] h-[400px] bg-romantic-secondary/20 rounded-full blur-[80px] pointer-events-none" />
      <main className="relative z-10 w-full h-full max-w-lg mx-auto transition-all duration-700 ease-in-out">
        {renderContent()}
      </main>
      {currentIndex > 0 && (
        <div className="absolute bottom-12 md:bottom-8 w-full z-50 pointer-events-none px-8" style={{ paddingBottom: 'env(safe-area-inset-bottom)' }}>
          <div className="flex items-center justify-between text-romantic-text/40">
            <div className={`w-24 flex justify-start transition-opacity duration-300 ${currentIndex > 1 ? 'opacity-100 animate-pulse' : 'opacity-0'}`}><div className="flex items-center gap-1 font-sans text-[10px] uppercase tracking-widest"><ChevronLeft size={10} /> Geri</div></div>
            <div className="font-serif text-sm font-medium tracking-widest opacity-60">{currentIndex} / {SLIDES.length - 1}</div>
            <div className={`w-24 flex justify-end transition-opacity duration-300 ${currentIndex < SLIDES.length - 1 ? 'opacity-100 animate-pulse' : 'opacity-0'}`}><div className="flex items-center gap-1 font-sans text-[10px] uppercase tracking-widest">İleri <ChevronRight size={10} /></div></div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { Play, Music, Heart, ChevronRight, ChevronLeft, Volume2, Lock, ArrowLeft, Phone, Video, MoreVertical, ChevronsDown, VolumeX } from 'lucide-react';
import { SLIDES, YOUTUBE_VIDEO_ID } from './constants';
import { SlideType } from './types';
import ProgressBar from './components/ProgressBar';
import FloatingHearts from './components/FloatingHearts';

// Helper to access window globals for YouTube API
declare global {
  interface Window {
    onYouTubeIframeAPIReady: () => void;
    YT: any;
  }
}

const App: React.FC = () => {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [isPlaying, setIsPlaying] = useState(false);
  const [password, setPassword] = useState('');
  const [error, setError] = useState(false);
  const playerRef = useRef<any>(null);

  // Countdown State
  const [timeLeft, setTimeLeft] = useState({
    days: 0,
    hours: 0,
    minutes: 0,
    seconds: 0
  });

  // Calculate Countdown
  useEffect(() => {
    const targetDate = new Date('2026-04-25T00:00:00').getTime();

    const interval = setInterval(() => {
      const now = new Date().getTime();
      const difference = targetDate - now;

      if (difference <= 0) {
        clearInterval(interval);
        setTimeLeft({ days: 0, hours: 0, minutes: 0, seconds: 0 });
      } else {
        setTimeLeft({
          days: Math.floor(difference / (1000 * 60 * 60 * 24)),
          hours: Math.floor((difference % (1000 * 60 * 60 * 24)) / (1000 * 60 * 60)),
          minutes: Math.floor((difference % (1000 * 60 * 60)) / (1000 * 60)),
          seconds: Math.floor((difference % (1000 * 60)) / 1000)
        });
      }
    }, 1000);

    return () => clearInterval(interval);
  }, []);

  // Initialize YouTube API
  useEffect(() => {
    if (!window.YT) {
      const tag = document.createElement('script');
      tag.src = "https://www.youtube.com/iframe_api";
      const firstScriptTag = document.getElementsByTagName('script')[0];
      firstScriptTag.parentNode?.insertBefore(tag, firstScriptTag);
    }

    window.onYouTubeIframeAPIReady = () => {
      playerRef.current = new window.YT.Player('youtube-player', {
        height: '1',
        width: '1',
        videoId: YOUTUBE_VIDEO_ID,
        playerVars: {
          'playsinline': 1,
          'controls': 0,
          'disablekb': 1,
          'fs': 0,
          'loop': 1,
          'playlist': YOUTUBE_VIDEO_ID
        },
        events: {
          'onReady': (event: any) => {
             event.target.setVolume(50);
          }
        }
      });
    };

    return () => {
      if (playerRef.current && playerRef.current.destroy) {
        playerRef.current.destroy();
      }
    };
  }, []);

  useEffect(() => {
    if (currentIndex === 0) return;
    const currentSlide = SLIDES[currentIndex];
    if (currentSlide.type === SlideType.VIDEO) {
        if (playerRef.current && playerRef.current.pauseVideo) {
            playerRef.current.pauseVideo();
            setIsPlaying(false);
        }
    } else {
        if (!isPlaying && playerRef.current && playerRef.current.playVideo) {
            playerRef.current.playVideo();
            setIsPlaying(true);
        }
    }
  }, [currentIndex]);

  const handleStart = (e: React.MouseEvent) => {
    e.stopPropagation();
    const cleanInput = password.toLowerCase().replace(/\s/g, '');
    if (cleanInput === 'seniseviyorum') {
      if (playerRef.current && playerRef.current.playVideo) {
        playerRef.current.playVideo();
        setIsPlaying(true);
      }
      setCurrentIndex(1);
      setError(false);
    } else {
      setError(true);
      setTimeout(() => setError(false), 500);
    }
  };

  const handleInteraction = useCallback((e: React.MouseEvent) => {
    if (currentIndex === 0) return;
    if (SLIDES[currentIndex].type !== SlideType.VIDEO && !isPlaying && playerRef.current && playerRef.current.playVideo) {
      playerRef.current.playVideo();
      setIsPlaying(true);
    }
    const { clientX } = e;
    const { innerWidth } = window;
    if (clientX > innerWidth / 2) {
      if (SLIDES[currentIndex].type === SlideType.FINAL) return;
      if (currentIndex < SLIDES.length - 1) setCurrentIndex((prev) => prev + 1);
    } else {
      if (currentIndex > 0) setCurrentIndex((prev) => prev - 1);
    }
  }, [currentIndex, isPlaying]);

  const restart = (e: React.MouseEvent) => {
    e.stopPropagation();
    setCurrentIndex(0);
    setPassword('');
    setIsPlaying(false);
    if (playerRef.current && playerRef.current.stopVideo) {
       playerRef.current.stopVideo();
    }
  };

  const renderContent = () => {
    const currentSlide = SLIDES[currentIndex];
    switch (currentSlide.type) {
      case SlideType.INTRO:
        return (
          <div className="flex flex-col items-center justify-center h-full text-center px-6 animate-fade-in relative overflow-hidden">
            {/* Romantic Background Decoration for Intro */}
            <div className="absolute inset-0 z-0 flex items-center justify-center pointer-events-none">
               <div className="absolute w-[500px] h-[500px] bg-romantic-primary/10 rounded-full blur-[100px] animate-pulse-slow"></div>
               <Heart className="text-white/20 w-80 h-80 animate-pulse" fill="currentColor" strokeWidth={0} />
            </div>

            <div className="z-10 w-full flex flex-col items-center">
              {/* Volume Hint */}
              <div className="mb-6 animate-bounce">
                <div className="flex items-center gap-2 bg-white/60 backdrop-blur-md px-4 py-1.5 rounded-full border border-white/60 shadow-sm text-romantic-secondary">
                  <Volume2 size={14} />
                  <span className="text-[10px] font-sans tracking-widest uppercase font-bold">Sesi Açın</span>
                </div>
              </div>

              {/* Title Section */}
              <div className="mb-8">
                <h1 className="font-script text-6xl md:text-7xl text-romantic-text mb-2 drop-shadow-sm transform -rotate-2">
                  Şeyma <span className="text-romantic-accent text-4xl">&</span> Akif
                </h1>
                <div className="flex items-center justify-center gap-3">
                   <div className="h-[1px] w-8 bg-romantic-secondary/30"></div>
                   <p className="font-serif text-lg md:text-xl text-romantic-secondary tracking-[0.2em] uppercase">En Güzel Günümüze</p>
                   <div className="h-[1px] w-8 bg-romantic-secondary/30"></div>
                </div>
              </div>

              {/* Countdown Section - Glassmorphism */}
              <div className="grid grid-cols-4 gap-3 mb-12 w-full max-w-sm">
                {[
                  { label: 'Gün', value: timeLeft.days },
                  { label: 'Saat', value: timeLeft.hours },
                  { label: 'Dakika', value: timeLeft.minutes },
                  { label: 'Saniye', value: timeLeft.seconds }
                ].map((item, idx) => (
                  <div key={idx} className="flex flex-col items-center p-3 bg-white/40 backdrop-blur-sm rounded-2xl border border-white/60 shadow-lg hover:bg-white/50 transition-colors">
                    <span className="font-serif text-2xl md:text-3xl font-bold text-romantic-text tabular-nums leading-none mb-1">
                      {String(item.value).padStart(2, '0')}
                    </span>
                    <span className="font-sans text-[9px] uppercase tracking-wider text-romantic-secondary/80 font-medium">
                      {item.label}
                    </span>
                  </div>
                ))}
              </div>

              {/* Login Section */}
              <div className="w-full max-w-xs space-y-5">
                <div className={`transition-transform duration-200 ${error ? 'translate-x-[-10px]' : ''}`}>
                  <div className="relative group">
                    <input
                      type="text"
                      value={password}
                      onChange={(e) => {
                        setPassword(e.target.value);
                        setError(false);
                      }}
                      onClick={(e) => e.stopPropagation()}
                      placeholder="Sihirli sözcük..."
                      className={`w-full bg-white/80 backdrop-blur-md border-2 ${error ? 'border-red-300 text-red-500 placeholder:text-red-300' : 'border-white text-romantic-text'} rounded-2xl px-6 py-4 text-center outline-none focus:border-romantic-primary focus:ring-4 focus:ring-romantic-primary/10 transition-all font-serif text-xl placeholder:text-romantic-text/30 shadow-xl placeholder:italic`}
                    />
                    {!password && <Heart size={16} className="absolute right-5 top-1/2 -translate-y-1/2 text-romantic-primary/40 animate-pulse" fill="currentColor" />}
                  </div>
                  {error && <p className="text-red-400 text-xs mt-2 font-sans text-center">İpucu: Birbirimize hep söylediğimiz o iki kelime...</p>}
                </div>

                <div className="flex justify-center">
                  <button 
                    onClick={handleStart}
                    className="group relative bg-gradient-to-r from-romantic-primary to-romantic-accent text-white px-12 py-4 rounded-full shadow-xl font-serif tracking-widest uppercase text-sm flex items-center gap-3 overflow-hidden transform transition-all hover:scale-105 active:scale-95 hover:shadow-2xl hover:brightness-110"
                  >
                    <div className="absolute inset-0 bg-white/20 translate-y-full group-hover:translate-y-0 transition-transform duration-300"></div>
                    <span className="relative flex items-center gap-2">
                      <Play size={16} className="fill-current" /> Hikayemiz Başlasın
                    </span>
                  </button>
                </div>
              </div>
            </div>
          </div>
        );

      case SlideType.WHATSAPP:
        return (
          <div className="flex flex-col h-full items-center justify-start pt-16 px-4 animate-fade-in relative z-20">
            <div className="w-full max-w-[320px] h-[55vh] md:h-[68vh] bg-[#E5DDD5] rounded-2xl shadow-2xl overflow-hidden flex flex-col relative border border-gray-300 ring-4 ring-black/5 mx-auto transition-all duration-300">
              <div className="bg-[#075E54] text-white p-2 px-3 flex items-center shadow-md z-10 shrink-0">
                <ArrowLeft size={18} className="mr-1" />
                <div className="w-8 h-8 bg-gray-300 rounded-full mr-2 flex items-center justify-center text-gray-500 overflow-hidden shrink-0">
                  <div className="bg-gray-400 w-full h-full flex items-center justify-center text-xs font-bold">A</div>
                </div>
                <div className="flex-1 overflow-hidden">
                  <h3 className="font-semibold text-sm leading-tight truncate">{currentSlide.title}</h3>
                  <p className="text-[10px] opacity-80 truncate">Çevrimiçi</p>
                </div>
                <div className="flex gap-3 ml-2">
                  <Video size={16} />
                  <Phone size={16} />
                  <MoreVertical size={16} />
                </div>
              </div>
              <div className="flex-1 p-3 bg-[#E5DDD5] relative overflow-y-auto scrollbar-hide">
                  <div className="absolute inset-0 opacity-10 bg-[url('https://user-images.githubusercontent.com/15075759/28719144-86dc0f70-73b1-11e7-911d-60d70fcded21.png')] pointer-events-none"></div>
                  <div className="flex justify-center mb-4 relative z-10">
                    <span className="bg-[#D4EAF4] text-gray-600 text-[10px] font-medium px-2 py-0.5 rounded-lg shadow-sm">{currentSlide.date}</span>
                  </div>
                  <div className="space-y-2 relative z-10 pb-4">
                    {currentSlide.messages?.map((msg, idx) => (
                      <div key={idx} className={`flex ${msg.isSender ? 'justify-end' : 'justify-start'}`}>
                        <div className={`max-w-[85%] p-1.5 px-2.5 rounded-lg shadow-sm text-xs relative ${msg.isSender ? 'bg-[#E2FFC7] rounded-tr-none' : 'bg-white rounded-tl-none'}`}>
                          <p className="text-[#303030] leading-snug pb-1 whitespace-pre-wrap">{msg.text}</p>
                          <div className="text-right"><span className="text-[9px] text-gray-500">{msg.time}</span></div>
                        </div>
                      </div>
                    ))}
                  </div>
              </div>
            </div>
            <p className="mt-2 text-xs text-romantic-text/60 font-sans italic animate-pulse">(Mesajı aşağı kaydırabilirsin.)</p>
            {currentSlide.footerText && (
              <div className="mt-4 md:mt-6 text-center max-w-xs animate-fade-in" style={{ animationDelay: '0.5s' }}>
                  <p className="font-serif text-xl md:text-2xl text-romantic-text italic font-medium leading-relaxed drop-shadow-sm px-2">{currentSlide.footerText}</p>
              </div>
            )}
          </div>
        );

      case SlideType.MEMORY:
        return (
          <div className={`flex flex-col items-center justify-center h-full px-6 pb-20 animate-fade-in ${currentSlide.textAlign === 'text-left' ? 'items-start' : ''}`}>
            <div className={`relative p-3 bg-white shadow-2xl mb-4 ${currentSlide.containerClass || 'w-full max-w-sm'} ${currentSlide.imageRotate || 'rotate-2'}`}>
              <div className={`${currentSlide.aspectRatio === 'aspect-auto' ? '' : (currentSlide.aspectRatio || 'aspect-[3/4]')} ${currentSlide.aspectRatio === 'aspect-auto' ? '' : 'overflow-hidden'} bg-gray-200`}>
                <img src={currentSlide.image} alt={currentSlide.title} className={`w-full ${currentSlide.aspectRatio === 'aspect-auto' ? 'h-auto' : 'h-full object-cover'}`} />
              </div>
              <div className="absolute -bottom-10 right-0 font-script text-4xl text-romantic-secondary/50 opacity-50 z-[-1]">{currentSlide.watermark || 'Anılar'}</div>
            </div>
            {currentSlide.secondImage && (
              <div className={`relative p-3 bg-white shadow-2xl mb-8 w-full max-w-sm ${currentSlide.imageRotate ? '-'+currentSlide.imageRotate : '-rotate-2'}`}>
                <div className={`${currentSlide.aspectRatio || 'aspect-[3/4]'} overflow-hidden bg-gray-200`}>
                  <img src={currentSlide.secondImage} alt={currentSlide.title} className="w-full h-full object-cover" />
                </div>
              </div>
            )}
            <div className={`w-full max-w-sm ${currentSlide.textAlign || 'text-center'}`}>
              <h2 className="font-serif text-3xl mb-4 text-romantic-text">{currentSlide.title}</h2>
              <p className="font-sans text-lg leading-relaxed text-romantic-text/80 whitespace-pre-line">{currentSlide.text}</p>
              {currentSlide.author && <p className="mt-2 text-sm text-romantic-secondary italic text-right font-serif">— {currentSlide.author}</p>}
            </div>
          </div>
        );

      case SlideType.COLLAGE:
        let layoutClass = "grid grid-cols-2 gap-3";
        if (currentSlide.collageLayout === 'row') layoutClass = "flex flex-row gap-2 h-64 justify-center items-center";
        else if (currentSlide.collageLayout === 'col') layoutClass = "flex flex-col gap-4 w-full mx-auto";
        return (
          <div className="flex flex-col items-center justify-center h-full px-6 animate-fade-in">
             <h2 className="font-serif text-3xl mb-6 text-romantic-text text-center">{currentSlide.title}</h2>
             <div className={`w-full max-w-md bg-white p-3 shadow-xl transform rotate-1 ${layoutClass}`}>
                {currentSlide.collageImages?.map((img, idx) => (
                  <div key={idx} className={`bg-gray-100 rounded-sm ${currentSlide.collageLayout === 'row' ? 'flex-1 h-full overflow-hidden' : currentSlide.collageLayout === 'col' ? 'w-full' : 'aspect-square overflow-hidden'}`}>
                    <img src={img} alt={`Collage ${idx}`} className={`w-full hover:scale-110 transition-transform duration-500 ${currentSlide.collageLayout === 'col' ? 'h-auto' : 'h-full object-cover'}`} />
                  </div>
                ))}
             </div>
             {currentSlide.text && <div className="mt-12 text-center"><p className="font-script text-3xl text-romantic-text whitespace-pre-line leading-relaxed">{currentSlide.text}</p></div>}
          </div>
        );

      case SlideType.MESSAGE:
        return (
          <div className="flex flex-col items-center justify-center h-full px-8 text-center animate-fade-in relative">
            <div className="font-serif text-6xl text-romantic-primary opacity-20 absolute top-[20%] left-4">"</div>
            <h2 className="font-serif text-3xl md:text-4xl leading-relaxed text-romantic-text italic relative z-10">{currentSlide.text}</h2>
            <div className="font-serif text-6xl text-romantic-primary opacity-20 absolute bottom-[20%] right-4">"</div>
            <div className="mt-8"><Heart className="text-romantic-accent fill-current animate-pulse-slow" size={32} /></div>
          </div>
        );

      case SlideType.MUSIC:
        return (
          <div className="flex flex-col items-center justify-center h-full px-6 animate-fade-in">
             <div className="w-48 h-48 bg-gradient-to-br from-romantic-primary to-romantic-secondary rounded-full shadow-2xl flex items-center justify-center mb-10 animate-spin" style={{ animationDuration: '10s' }}><Music size={64} className="text-white" /></div>
             <div className="text-center mb-8">
                <h3 className="font-serif text-2xl font-bold text-romantic-text mb-1">{currentSlide.title}</h3>
                <p className="font-sans text-sm text-romantic-secondary uppercase tracking-widest">{currentSlide.text}</p>
             </div>
             <div className="space-y-2 text-center">
               {currentSlide.extra?.map((line, i) => <p key={i} className="font-serif text-xl italic text-romantic-text/70">{line}</p>)}
             </div>
          </div>
        );

      case SlideType.DREAMS:
        return (
          <div className="flex flex-col items-center justify-center h-full px-8 animate-fade-in">
            <h2 className="font-script text-5xl mb-12 text-romantic-text">{currentSlide.title}</h2>
            <ul className="space-y-6 w-full max-w-md">
              {currentSlide.extra?.map((item, i) => (
                <li key={i} className="flex items-center gap-4 group">
                  <span className="w-8 h-8 flex items-center justify-center rounded-full bg-romantic-primary/20 text-romantic-accent group-hover:bg-romantic-accent group-hover:text-white transition-colors duration-300"><Heart size={14} className="fill-current" /></span>
                  <span className="font-serif text-xl text-romantic-text border-b border-transparent group-hover:border-romantic-primary transition-all">{item}</span>
                </li>
              ))}
            </ul>
          </div>
        );

      case SlideType.VIDEO:
        return (
          <div className="flex flex-col items-center justify-center h-full w-full animate-fade-in relative z-50 p-4">
             {currentSlide.title && <h2 className="font-serif text-2xl mb-4 text-romantic-text text-center">{currentSlide.title}</h2>}
             <div className="w-full max-w-sm aspect-[9/16] max-h-[70vh] rounded-2xl overflow-hidden shadow-2xl border-4 border-white/50 bg-black relative group">
               <iframe width="100%" height="100%" src={`https://www.youtube.com/embed/${currentSlide.videoId}?autoplay=1&playsinline=1&mute=1&rel=0&loop=1&playlist=${currentSlide.videoId}&controls=1&showinfo=0&modestbranding=1&iv_load_policy=3&fs=0`} title="YouTube video player" frameBorder="0" allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share" allowFullScreen className="w-full h-full object-cover"></iframe>
             </div>
             <div className="mt-4 flex items-center gap-2 text-romantic-text/60 animate-pulse bg-white/50 px-3 py-1 rounded-full"><VolumeX size={14} /><p className="font-sans text-xs">Otomatik başlamazsa veya ses gelmezse videoya dokunun.</p></div>
          </div>
        );

      case SlideType.FINAL:
        return (
          <div className="flex flex-col items-center justify-center h-full px-6 text-center animate-fade-in">
            <h1 className="font-script text-6xl mb-6 text-romantic-text">{currentSlide.title}</h1>
            <p className="font-serif text-xl text-romantic-secondary mb-12">{currentSlide.text}</p>
            <div className="relative cursor-pointer group" onClick={(e) => { e.stopPropagation(); setCurrentIndex(prev => prev + 1); }}>
              <Heart size={150} className="text-romantic-accent fill-current animate-pulse group-hover:scale-110 transition-transform duration-300" />
              <span className="absolute inset-0 flex items-center justify-center text-white font-bold font-sans text-sm tracking-wider animate-bounce">Buraya Bas</span>
            </div>
            <button onClick={restart} className="mt-20 text-xs font-sans uppercase tracking-widest text-romantic-secondary/50 hover:text-romantic-secondary transition-colors z-50 p-4 cursor-pointer">Başa Dön ↺</button>
          </div>
        );
      default: return null;
    }
  };

  return (
    <div onClick={handleInteraction} className="relative w-full h-[100dvh] bg-romantic-bg overflow-hidden cursor-pointer select-none">
      <div id="youtube-player" className="absolute top-0 left-0 opacity-1 pointer-events-none -z-50 h-[1px] w-[1px]" />
      <ProgressBar total={SLIDES.length} current={currentIndex} />
      <FloatingHearts />
      <div className="absolute top-[-20%] right-[-10%] w-[500px] h-[500px] bg-romantic-primary/20 rounded-full blur-[100px] pointer-events-none" />
      <div className="absolute bottom-[-10%] left-[-10%] w-[400px] h-[400px] bg-romantic-secondary/20 rounded-full blur-[80px] pointer-events-none" />
      <main className="relative z-10 w-full h-full max-w-lg mx-auto transition-all duration-700 ease-in-out">
        {renderContent()}
      </main>
      {currentIndex > 0 && (
        <div className="absolute bottom-12 md:bottom-8 w-full z-50 pointer-events-none px-8" style={{ paddingBottom: 'env(safe-area-inset-bottom)' }}>
          <div className="flex items-center justify-between text-romantic-text/40">
            <div className={`w-24 flex justify-start transition-opacity duration-300 ${currentIndex > 1 ? 'opacity-100 animate-pulse' : 'opacity-0'}`}><div className="flex items-center gap-1 font-sans text-[10px] uppercase tracking-widest"><ChevronLeft size={10} /> Geri</div></div>
            <div className="font-serif text-sm font-medium tracking-widest opacity-60">{currentIndex} / {SLIDES.length - 1}</div>
            <div className={`w-24 flex justify-end transition-opacity duration-300 ${currentIndex < SLIDES.length - 1 ? 'opacity-100 animate-pulse' : 'opacity-0'}`}><div className="flex items-center gap-1 font-sans text-[10px] uppercase tracking-widest">İleri <ChevronRight size={10} /></div></div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect, useCallback, useMemo } from 'react';
import { Play, Music, Heart, ChevronRight, ChevronLeft, Volume2, Lock, ArrowLeft, Phone, Video, MoreVertical, ChevronsDown, VolumeX } from 'lucide-react';
import { SLIDES, YOUTUBE_VIDEO_ID } from './constants';
import { SlideType } from './types';
import ProgressBar from './components/ProgressBar';
import FloatingHearts from './components/FloatingHearts';

// Helper to access window globals for YouTube API
declare global {
  interface Window {
    onYouTubeIframeAPIReady: () => void;
    YT: any;
  }
}

const App: React.FC = () => {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [isPlaying, setIsPlaying] = useState(false);
  const [password, setPassword] = useState('');
  const [error, setError] = useState(false);
  const playerRef = useRef<any>(null);

  // Countdown State
  const [timeLeft, setTimeLeft] = useState({
    days: 0,
    hours: 0,
    minutes: 0,
    seconds: 0
  });

  // Calculate Countdown
  useEffect(() => {
    const targetDate = new Date('2026-04-25T00:00:00').getTime();

    const interval = setInterval(() => {
      const now = new Date().getTime();
      const difference = targetDate - now;

      if (difference <= 0) {
        clearInterval(interval);
        setTimeLeft({ days: 0, hours: 0, minutes: 0, seconds: 0 });
      } else {
        setTimeLeft({
          days: Math.floor(difference / (1000 * 60 * 60 * 24)),
          hours: Math.floor((difference % (1000 * 60 * 60 * 24)) / (1000 * 60 * 60)),
          minutes: Math.floor((difference % (1000 * 60 * 60)) / (1000 * 60)),
          seconds: Math.floor((difference % (1000 * 60)) / 1000)
        });
      }
    }, 1000);

    return () => clearInterval(interval);
  }, []);

  // Generate static random hearts for Intro to avoid re-render flicker
  const introHearts = useMemo(() => {
    return Array.from({ length: 30 }).map((_, i) => ({
      id: i,
      left: Math.random() * 100,
      delay: Math.random() * 20, // Spread start times
      duration: 10 + Math.random() * 15, // Slow floating
      size: 10 + Math.random() * 24,
      color: Math.random() > 0.6 ? '#FF6B6B' : '#D4A5A5',
      opacity: 0.3 + Math.random() * 0.4
    }));
  }, []);

  // Initialize YouTube API
  useEffect(() => {
    if (!window.YT) {
      const tag = document.createElement('script');
      tag.src = "https://www.youtube.com/iframe_api";
      const firstScriptTag = document.getElementsByTagName('script')[0];
      firstScriptTag.parentNode?.insertBefore(tag, firstScriptTag);
    }

    window.onYouTubeIframeAPIReady = () => {
      playerRef.current = new window.YT.Player('youtube-player', {
        height: '1',
        width: '1',
        videoId: YOUTUBE_VIDEO_ID,
        playerVars: {
          'playsinline': 1,
          'controls': 0,
          'disablekb': 1,
          'fs': 0,
          'loop': 1,
          'playlist': YOUTUBE_VIDEO_ID
        },
        events: {
          'onReady': (event: any) => {
             event.target.setVolume(50);
          }
        }
      });
    };

    return () => {
      if (playerRef.current && playerRef.current.destroy) {
        playerRef.current.destroy();
      }
    };
  }, []);

  useEffect(() => {
    if (currentIndex === 0) return;
    const currentSlide = SLIDES[currentIndex];
    if (currentSlide.type === SlideType.VIDEO) {
        if (playerRef.current && playerRef.current.pauseVideo) {
            playerRef.current.pauseVideo();
            setIsPlaying(false);
        }
    } else {
        if (!isPlaying && playerRef.current && playerRef.current.playVideo) {
            playerRef.current.playVideo();
            setIsPlaying(true);
        }
    }
  }, [currentIndex]);

  const handleStart = (e: React.MouseEvent) => {
    e.stopPropagation();
    const cleanInput = password.toLowerCase().replace(/\s/g, '');
    if (cleanInput === 'seniseviyorum') {
      if (playerRef.current && playerRef.current.playVideo) {
        playerRef.current.playVideo();
        setIsPlaying(true);
      }
      setCurrentIndex(1);
      setError(false);
    } else {
      setError(true);
      setTimeout(() => setError(false), 500);
    }
  };

  const handleInteraction = useCallback((e: React.MouseEvent) => {
    if (currentIndex === 0) return;
    if (SLIDES[currentIndex].type !== SlideType.VIDEO && !isPlaying && playerRef.current && playerRef.current.playVideo) {
      playerRef.current.playVideo();
      setIsPlaying(true);
    }
    const { clientX } = e;
    const { innerWidth } = window;
    if (clientX > innerWidth / 2) {
      if (SLIDES[currentIndex].type === SlideType.FINAL) return;
      if (currentIndex < SLIDES.length - 1) setCurrentIndex((prev) => prev + 1);
    } else {
      if (currentIndex > 0) setCurrentIndex((prev) => prev - 1);
    }
  }, [currentIndex, isPlaying]);

  const restart = (e: React.MouseEvent) => {
    e.stopPropagation();
    setCurrentIndex(0);
    setPassword('');
    setIsPlaying(false);
    if (playerRef.current && playerRef.current.stopVideo) {
       playerRef.current.stopVideo();
    }
  };

  const renderContent = () => {
    const currentSlide = SLIDES[currentIndex];
    switch (currentSlide.type) {
      case SlideType.INTRO:
        return (
          <div className="flex flex-col items-center justify-center h-full text-center px-6 animate-fade-in relative overflow-hidden">
            {/* Flying Hearts Background */}
            <div className="absolute inset-0 overflow-hidden pointer-events-none z-0">
               {introHearts.map((heart) => (
                 <div
                   key={heart.id}
                   className="absolute -bottom-10"
                   style={{
                     left: `${heart.left}%`,
                     animation: `floatUp ${heart.duration}s linear infinite`,
                     animationDelay: `-${heart.delay}s`,
                     color: heart.color,
                     opacity: heart.opacity
                   }}
                 >
                   <Heart size={heart.size} fill="currentColor" />
                 </div>
               ))}
            </div>

            {/* Romantic Background Decoration for Intro */}
            <div className="absolute inset-0 z-0 flex items-center justify-center pointer-events-none">
               <div className="absolute w-[500px] h-[500px] bg-romantic-primary/10 rounded-full blur-[100px] animate-pulse-slow"></div>
               <Heart className="text-white/20 w-80 h-80 animate-pulse" fill="currentColor" strokeWidth={0} />
            </div>

            <div className="z-10 w-full flex flex-col items-center">
              {/* Volume Hint */}
              <div className="mb-6 animate-bounce">
                <div className="flex items-center gap-2 bg-white/60 backdrop-blur-md px-4 py-1.5 rounded-full border border-white/60 shadow-sm text-romantic-secondary">
                  <Volume2 size={14} />
                  <span className="text-[10px] font-sans tracking-widest uppercase font-bold">Sesi Açın</span>
                </div>
              </div>

              {/* Title Section */}
              <div className="mb-8">
                <h1 className="font-script text-6xl md:text-7xl text-romantic-text mb-2 drop-shadow-sm transform -rotate-2">
                  Şeyma <span className="text-romantic-accent text-4xl">&</span> Akif
                </h1>
                <div className="flex items-center justify-center gap-3">
                   <div className="h-[1px] w-8 bg-romantic-secondary/30"></div>
                   <p className="font-serif text-lg md:text-xl text-romantic-secondary tracking-[0.2em] uppercase">En Güzel Günümüze</p>
                   <div className="h-[1px] w-8 bg-romantic-secondary/30"></div>
                </div>
              </div>

              {/* Countdown Section - Glassmorphism */}
              <div className="grid grid-cols-4 gap-3 mb-12 w-full max-w-sm">
                {[
                  { label: 'Gün', value: timeLeft.days },
                  { label: 'Saat', value: timeLeft.hours },
                  { label: 'Dakika', value: timeLeft.minutes },
                  { label: 'Saniye', value: timeLeft.seconds }
                ].map((item, idx) => (
                  <div key={idx} className="flex flex-col items-center p-3 bg-white/40 backdrop-blur-sm rounded-2xl border border-white/60 shadow-lg hover:bg-white/50 transition-colors">
                    <span className="font-serif text-2xl md:text-3xl font-bold text-romantic-text tabular-nums leading-none mb-1">
                      {String(item.value).padStart(2, '0')}
                    </span>
                    <span className="font-sans text-[9px] uppercase tracking-wider text-romantic-secondary/80 font-medium">
                      {item.label}
                    </span>
                  </div>
                ))}
              </div>

              {/* Login Section */}
              <div className="w-full max-w-xs space-y-5">
                <div className={`transition-transform duration-200 ${error ? 'translate-x-[-10px]' : ''}`}>
                  <div className="relative group">
                    <input
                      type="text"
                      value={password}
                      onChange={(e) => {
                        setPassword(e.target.value);
                        setError(false);
                      }}
                      onClick={(e) => e.stopPropagation()}
                      placeholder="Sihirli sözcük..."
                      className={`w-full bg-white/80 backdrop-blur-md border-2 ${error ? 'border-red-300 text-red-500 placeholder:text-red-300' : 'border-white text-romantic-text'} rounded-2xl px-6 py-4 text-center outline-none focus:border-romantic-primary focus:ring-4 focus:ring-romantic-primary/10 transition-all font-serif text-xl placeholder:text-romantic-text/30 shadow-xl placeholder:italic`}
                    />
                    {!password && <Heart size={16} className="absolute right-5 top-1/2 -translate-y-1/2 text-romantic-primary/40 animate-pulse" fill="currentColor" />}
                  </div>
                  {error && <p className="text-red-400 text-xs mt-2 font-sans text-center">İpucu: Birbirimize hep söylediğimiz o iki kelime...</p>}
                </div>

                <div className="flex justify-center">
                  <button 
                    onClick={handleStart}
                    className="group relative bg-gradient-to-r from-romantic-primary to-romantic-accent text-white px-12 py-4 rounded-full shadow-xl font-serif tracking-widest uppercase text-sm flex items-center gap-3 overflow-hidden transform transition-all hover:scale-105 active:scale-95 hover:shadow-2xl hover:brightness-110"
                  >
                    <div className="absolute inset-0 bg-white/20 translate-y-full group-hover:translate-y-0 transition-transform duration-300"></div>
                    <span className="relative flex items-center gap-2">
                      <Play size={16} className="fill-current" /> Hikayemiz Başlasın
                    </span>
                  </button>
                </div>
              </div>
            </div>
          </div>
        );

      case SlideType.WHATSAPP:
        return (
          <div className="flex flex-col h-full items-center justify-start pt-16 px-4 animate-fade-in relative z-20">
            <div className="w-full max-w-[320px] h-[55vh] md:h-[68vh] bg-[#E5DDD5] rounded-2xl shadow-2xl overflow-hidden flex flex-col relative border border-gray-300 ring-4 ring-black/5 mx-auto transition-all duration-300">
              <div className="bg-[#075E54] text-white p-2 px-3 flex items-center shadow-md z-10 shrink-0">
                <ArrowLeft size={18} className="mr-1" />
                <div className="w-8 h-8 bg-gray-300 rounded-full mr-2 flex items-center justify-center text-gray-500 overflow-hidden shrink-0">
                  <div className="bg-gray-400 w-full h-full flex items-center justify-center text-xs font-bold">A</div>
                </div>
                <div className="flex-1 overflow-hidden">
                  <h3 className="font-semibold text-sm leading-tight truncate">{currentSlide.title}</h3>
                  <p className="text-[10px] opacity-80 truncate">Çevrimiçi</p>
                </div>
                <div className="flex gap-3 ml-2">
                  <Video size={16} />
                  <Phone size={16} />
                  <MoreVertical size={16} />
                </div>
              </div>
              <div className="flex-1 p-3 bg-[#E5DDD5] relative overflow-y-auto scrollbar-hide">
                  <div className="absolute inset-0 opacity-10 bg-[url('https://user-images.githubusercontent.com/15075759/28719144-86dc0f70-73b1-11e7-911d-60d70fcded21.png')] pointer-events-none"></div>
                  <div className="flex justify-center mb-4 relative z-10">
                    <span className="bg-[#D4EAF4] text-gray-600 text-[10px] font-medium px-2 py-0.5 rounded-lg shadow-sm">{currentSlide.date}</span>
                  </div>
                  <div className="space-y-2 relative z-10 pb-4">
                    {currentSlide.messages?.map((msg, idx) => (
                      <div key={idx} className={`flex ${msg.isSender ? 'justify-end' : 'justify-start'}`}>
                        <div className={`max-w-[85%] p-1.5 px-2.5 rounded-lg shadow-sm text-xs relative ${msg.isSender ? 'bg-[#E2FFC7] rounded-tr-none' : 'bg-white rounded-tl-none'}`}>
                          <p className="text-[#303030] leading-snug pb-1 whitespace-pre-wrap">{msg.text}</p>
                          <div className="text-right"><span className="text-[9px] text-gray-500">{msg.time}</span></div>
                        </div>
                      </div>
                    ))}
                  </div>
              </div>
            </div>
            <p className="mt-2 text-xs text-romantic-text/60 font-sans italic animate-pulse">(Mesajı aşağı kaydırabilirsin.)</p>
            {currentSlide.footerText && (
              <div className="mt-4 md:mt-6 text-center max-w-xs animate-fade-in" style={{ animationDelay: '0.5s' }}>
                  <p className="font-serif text-xl md:text-2xl text-romantic-text italic font-medium leading-relaxed drop-shadow-sm px-2">{currentSlide.footerText}</p>
              </div>
            )}
          </div>
        );

      case SlideType.MEMORY:
        return (
          <div className={`flex flex-col items-center justify-center h-full px-6 pb-20 animate-fade-in ${currentSlide.textAlign === 'text-left' ? 'items-start' : ''}`}>
            <div className={`relative p-3 bg-white shadow-2xl mb-4 ${currentSlide.containerClass || 'w-full max-w-sm'} ${currentSlide.imageRotate || 'rotate-2'}`}>
              <div className={`${currentSlide.aspectRatio === 'aspect-auto' ? '' : (currentSlide.aspectRatio || 'aspect-[3/4]')} ${currentSlide.aspectRatio === 'aspect-auto' ? '' : 'overflow-hidden'} bg-gray-200`}>
                <img src={currentSlide.image} alt={currentSlide.title} className={`w-full ${currentSlide.aspectRatio === 'aspect-auto' ? 'h-auto' : 'h-full object-cover'}`} />
              </div>
              <div className="absolute -bottom-10 right-0 font-script text-4xl text-romantic-secondary/50 opacity-50 z-[-1]">{currentSlide.watermark || 'Anılar'}</div>
            </div>
            {currentSlide.secondImage && (
              <div className={`relative p-3 bg-white shadow-2xl mb-8 w-full max-w-sm ${currentSlide.imageRotate ? '-'+currentSlide.imageRotate : '-rotate-2'}`}>
                <div className={`${currentSlide.aspectRatio || 'aspect-[3/4]'} overflow-hidden bg-gray-200`}>
                  <img src={currentSlide.secondImage} alt={currentSlide.title} className="w-full h-full object-cover" />
                </div>
              </div>
            )}
            <div className={`w-full max-w-sm ${currentSlide.textAlign || 'text-center'}`}>
              <h2 className="font-serif text-3xl mb-4 text-romantic-text">{currentSlide.title}</h2>
              <p className="font-sans text-lg leading-relaxed text-romantic-text/80 whitespace-pre-line">{currentSlide.text}</p>
              {currentSlide.author && <p className="mt-2 text-sm text-romantic-secondary italic text-right font-serif">— {currentSlide.author}</p>}
            </div>
          </div>
        );

      case SlideType.COLLAGE:
        let layoutClass = "grid grid-cols-2 gap-3";
        if (currentSlide.collageLayout === 'row') layoutClass = "flex flex-row gap-2 h-64 justify-center items-center";
        else if (currentSlide.collageLayout === 'col') layoutClass = "flex flex-col gap-4 w-full mx-auto";
        return (
          <div className="flex flex-col items-center justify-center h-full px-6 animate-fade-in">
             <h2 className="font-serif text-3xl mb-6 text-romantic-text text-center">{currentSlide.title}</h2>
             <div className={`w-full max-w-md bg-white p-3 shadow-xl transform rotate-1 ${layoutClass}`}>
                {currentSlide.collageImages?.map((img, idx) => (
                  <div key={idx} className={`bg-gray-100 rounded-sm ${currentSlide.collageLayout === 'row' ? 'flex-1 h-full overflow-hidden' : currentSlide.collageLayout === 'col' ? 'w-full' : 'aspect-square overflow-hidden'}`}>
                    <img src={img} alt={`Collage ${idx}`} className={`w-full hover:scale-110 transition-transform duration-500 ${currentSlide.collageLayout === 'col' ? 'h-auto' : 'h-full object-cover'}`} />
                  </div>
                ))}
             </div>
             {currentSlide.text && <div className="mt-12 text-center"><p className="font-script text-3xl text-romantic-text whitespace-pre-line leading-relaxed">{currentSlide.text}</p></div>}
          </div>
        );

      case SlideType.MESSAGE:
        return (
          <div className="flex flex-col items-center justify-center h-full px-8 text-center animate-fade-in relative">
            <div className="font-serif text-6xl text-romantic-primary opacity-20 absolute top-[20%] left-4">"</div>
            <h2 className="font-serif text-3xl md:text-4xl leading-relaxed text-romantic-text italic relative z-10">{currentSlide.text}</h2>
            <div className="font-serif text-6xl text-romantic-primary opacity-20 absolute bottom-[20%] right-4">"</div>
            <div className="mt-8"><Heart className="text-romantic-accent fill-current animate-pulse-slow" size={32} /></div>
          </div>
        );

      case SlideType.MUSIC:
        return (
          <div className="flex flex-col items-center justify-center h-full px-6 animate-fade-in">
             <div className="w-48 h-48 bg-gradient-to-br from-romantic-primary to-romantic-secondary rounded-full shadow-2xl flex items-center justify-center mb-10 animate-spin" style={{ animationDuration: '10s' }}><Music size={64} className="text-white" /></div>
             <div className="text-center mb-8">
                <h3 className="font-serif text-2xl font-bold text-romantic-text mb-1">{currentSlide.title}</h3>
                <p className="font-sans text-sm text-romantic-secondary uppercase tracking-widest">{currentSlide.text}</p>
             </div>
             <div className="space-y-2 text-center">
               {currentSlide.extra?.map((line, i) => <p key={i} className="font-serif text-xl italic text-romantic-text/70">{line}</p>)}
             </div>
          </div>
        );

      case SlideType.DREAMS:
        return (
          <div className="flex flex-col items-center justify-center h-full px-8 animate-fade-in">
            <h2 className="font-script text-5xl mb-12 text-romantic-text">{currentSlide.title}</h2>
            <ul className="space-y-6 w-full max-w-md">
              {currentSlide.extra?.map((item, i) => (
                <li key={i} className="flex items-center gap-4 group">
                  <span className="w-8 h-8 flex items-center justify-center rounded-full bg-romantic-primary/20 text-romantic-accent group-hover:bg-romantic-accent group-hover:text-white transition-colors duration-300"><Heart size={14} className="fill-current" /></span>
                  <span className="font-serif text-xl text-romantic-text border-b border-transparent group-hover:border-romantic-primary transition-all">{item}</span>
                </li>
              ))}
            </ul>
          </div>
        );

      case SlideType.VIDEO:
        return (
          <div className="flex flex-col items-center justify-center h-full w-full animate-fade-in relative z-50 p-4">
             {currentSlide.title && <h2 className="font-serif text-2xl mb-4 text-romantic-text text-center">{currentSlide.title}</h2>}
             <div className="w-full max-w-sm aspect-[9/16] max-h-[70vh] rounded-2xl overflow-hidden shadow-2xl border-4 border-white/50 bg-black relative group">
               <iframe width="100%" height="100%" src={`https://www.youtube.com/embed/${currentSlide.videoId}?autoplay=1&playsinline=1&mute=1&rel=0&loop=1&playlist=${currentSlide.videoId}&controls=1&showinfo=0&modestbranding=1&iv_load_policy=3&fs=0`} title="YouTube video player" frameBorder="0" allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share" allowFullScreen className="w-full h-full object-cover"></iframe>
             </div>
             <div className="mt-4 flex items-center gap-2 text-romantic-text/60 animate-pulse bg-white/50 px-3 py-1 rounded-full"><VolumeX size={14} /><p className="font-sans text-xs">Otomatik başlamazsa veya ses gelmezse videoya dokunun.</p></div>
          </div>
        );

      case SlideType.FINAL:
        return (
          <div className="flex flex-col items-center justify-center h-full px-6 text-center animate-fade-in">
            <h1 className="font-script text-6xl mb-6 text-romantic-text">{currentSlide.title}</h1>
            <p className="font-serif text-xl text-romantic-secondary mb-12">{currentSlide.text}</p>
            <div className="relative cursor-pointer group" onClick={(e) => { e.stopPropagation(); setCurrentIndex(prev => prev + 1); }}>
              <Heart size={150} className="text-romantic-accent fill-current animate-pulse group-hover:scale-110 transition-transform duration-300" />
              <span className="absolute inset-0 flex items-center justify-center text-white font-bold font-sans text-sm tracking-wider animate-bounce">Buraya Bas</span>
            </div>
            <button onClick={restart} className="mt-20 text-xs font-sans uppercase tracking-widest text-romantic-secondary/50 hover:text-romantic-secondary transition-colors z-50 p-4 cursor-pointer">Başa Dön ↺</button>
          </div>
        );
      default: return null;
    }
  };

  return (
    <div onClick={handleInteraction} className="relative w-full h-[100dvh] bg-romantic-bg overflow-hidden cursor-pointer select-none">
      <div id="youtube-player" className="absolute top-0 left-0 opacity-1 pointer-events-none -z-50 h-[1px] w-[1px]" />
      <ProgressBar total={SLIDES.length} current={currentIndex} />
      <FloatingHearts />
      <div className="absolute top-[-20%] right-[-10%] w-[500px] h-[500px] bg-romantic-primary/20 rounded-full blur-[100px] pointer-events-none" />
      <div className="absolute bottom-[-10%] left-[-10%] w-[400px] h-[400px] bg-romantic-secondary/20 rounded-full blur-[80px] pointer-events-none" />
      <main className="relative z-10 w-full h-full max-w-lg mx-auto transition-all duration-700 ease-in-out">
        {renderContent()}
      </main>
      {currentIndex > 0 && (
        <div className="absolute bottom-12 md:bottom-8 w-full z-50 pointer-events-none px-8" style={{ paddingBottom: 'env(safe-area-inset-bottom)' }}>
          <div className="flex items-center justify-between text-romantic-text/40">
            <div className={`w-24 flex justify-start transition-opacity duration-300 ${currentIndex > 1 ? 'opacity-100 animate-pulse' : 'opacity-0'}`}><div className="flex items-center gap-1 font-sans text-[10px] uppercase tracking-widest"><ChevronLeft size={10} /> Geri</div></div>
            <div className="font-serif text-sm font-medium tracking-widest opacity-60">{currentIndex} / {SLIDES.length - 1}</div>
            <div className={`w-24 flex justify-end transition-opacity duration-300 ${currentIndex < SLIDES.length - 1 ? 'opacity-100 animate-pulse' : 'opacity-0'}`}><div className="flex items-center gap-1 font-sans text-[10px] uppercase tracking-widest">İleri <ChevronRight size={10} /></div></div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect, useCallback, useMemo } from 'react';
import { Play, Music, Heart, ChevronRight, ChevronLeft, Volume2, Lock, ArrowLeft, Phone, Video, MoreVertical, ChevronsDown, VolumeX } from 'lucide-react';
import { SLIDES, YOUTUBE_VIDEO_ID } from './constants';
import { SlideType } from './types';
import ProgressBar from './components/ProgressBar';
import FloatingHearts from './components/FloatingHearts';

// Helper to access window globals for YouTube API
declare global {
  interface Window {
    onYouTubeIframeAPIReady: () => void;
    YT: any;
  }
}

const App: React.FC = () => {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [isPlaying, setIsPlaying] = useState(false);
  const [password, setPassword] = useState('');
  const [error, setError] = useState(false);
  const playerRef = useRef<any>(null);

  // Countdown State
  const [timeLeft, setTimeLeft] = useState({
    days: 0,
    hours: 0,
    minutes: 0,
    seconds: 0
  });

  // Calculate Countdown
  useEffect(() => {
    const targetDate = new Date('2026-04-25T00:00:00').getTime();

    const interval = setInterval(() => {
      const now = new Date().getTime();
      const difference = targetDate - now;

      if (difference <= 0) {
        clearInterval(interval);
        setTimeLeft({ days: 0, hours: 0, minutes: 0, seconds: 0 });
      } else {
        setTimeLeft({
          days: Math.floor(difference / (1000 * 60 * 60 * 24)),
          hours: Math.floor((difference % (1000 * 60 * 60 * 24)) / (1000 * 60 * 60)),
          minutes: Math.floor((difference % (1000 * 60 * 60)) / (1000 * 60)),
          seconds: Math.floor((difference % (1000 * 60)) / 1000)
        });
      }
    }, 1000);

    return () => clearInterval(interval);
  }, []);

  // Generate static random hearts for Intro to avoid re-render flicker
  const introHearts = useMemo(() => {
    return Array.from({ length: 30 }).map((_, i) => ({
      id: i,
      left: Math.random() * 100,
      delay: Math.random() * 20, // Spread start times
      duration: 10 + Math.random() * 15, // Slow floating
      size: 15 + Math.random() * 30, // Slightly larger
      color: Math.random() > 0.6 ? '#FF6B6B' : '#D4A5A5',
      opacity: 0.6 + Math.random() * 0.4 // Increased opacity (0.6 - 1.0)
    }));
  }, []);

  // Initialize YouTube API
  useEffect(() => {
    if (!window.YT) {
      const tag = document.createElement('script');
      tag.src = "https://www.youtube.com/iframe_api";
      const firstScriptTag = document.getElementsByTagName('script')[0];
      firstScriptTag.parentNode?.insertBefore(tag, firstScriptTag);
    }

    window.onYouTubeIframeAPIReady = () => {
      playerRef.current = new window.YT.Player('youtube-player', {
        height: '1',
        width: '1',
        videoId: YOUTUBE_VIDEO_ID,
        playerVars: {
          'playsinline': 1,
          'controls': 0,
          'disablekb': 1,
          'fs': 0,
          'loop': 1,
          'playlist': YOUTUBE_VIDEO_ID
        },
        events: {
          'onReady': (event: any) => {
             event.target.setVolume(50);
          }
        }
      });
    };

    return () => {
      if (playerRef.current && playerRef.current.destroy) {
        playerRef.current.destroy();
      }
    };
  }, []);

  useEffect(() => {
    if (currentIndex === 0) return;
    const currentSlide = SLIDES[currentIndex];
    if (currentSlide.type === SlideType.VIDEO) {
        if (playerRef.current && playerRef.current.pauseVideo) {
            playerRef.current.pauseVideo();
            setIsPlaying(false);
        }
    } else {
        if (!isPlaying && playerRef.current && playerRef.current.playVideo) {
            playerRef.current.playVideo();
            setIsPlaying(true);
        }
    }
  }, [currentIndex]);

  const handleStart = (e: React.MouseEvent) => {
    e.stopPropagation();
    const cleanInput = password.toLowerCase().replace(/\s/g, '');
    if (cleanInput === 'seniseviyorum') {
      if (playerRef.current && playerRef.current.playVideo) {
        playerRef.current.playVideo();
        setIsPlaying(true);
      }
      setCurrentIndex(1);
      setError(false);
    } else {
      setError(true);
      setTimeout(() => setError(false), 500);
    }
  };

  const handleInteraction = useCallback((e: React.MouseEvent) => {
    if (currentIndex === 0) return;
    if (SLIDES[currentIndex].type !== SlideType.VIDEO && !isPlaying && playerRef.current && playerRef.current.playVideo) {
      playerRef.current.playVideo();
      setIsPlaying(true);
    }
    const { clientX } = e;
    const { innerWidth } = window;
    if (clientX > innerWidth / 2) {
      if (SLIDES[currentIndex].type === SlideType.FINAL) return;
      if (currentIndex < SLIDES.length - 1) setCurrentIndex((prev) => prev + 1);
    } else {
      if (currentIndex > 0) setCurrentIndex((prev) => prev - 1);
    }
  }, [currentIndex, isPlaying]);

  const restart = (e: React.MouseEvent) => {
    e.stopPropagation();
    setCurrentIndex(0);
    setPassword('');
    setIsPlaying(false);
    if (playerRef.current && playerRef.current.stopVideo) {
       playerRef.current.stopVideo();
    }
  };

  const renderContent = () => {
    const currentSlide = SLIDES[currentIndex];
    switch (currentSlide.type) {
      case SlideType.INTRO:
        return (
          <div className="flex flex-col items-center justify-center h-full text-center px-6 animate-fade-in relative overflow-hidden">
            {/* Flying Hearts Background */}
            <div className="absolute inset-0 overflow-hidden pointer-events-none z-0">
               {introHearts.map((heart) => (
                 <div
                   key={heart.id}
                   className="absolute -bottom-10"
                   style={{
                     left: `${heart.left}%`,
                     animation: `floatUp ${heart.duration}s linear infinite`,
                     animationDelay: `-${heart.delay}s`,
                     color: heart.color,
                     opacity: heart.opacity
                   }}
                 >
                   <Heart size={heart.size} fill="currentColor" />
                 </div>
               ))}
            </div>

            {/* Romantic Background Decoration for Intro */}
            <div className="absolute inset-0 z-0 flex items-center justify-center pointer-events-none">
               <div className="absolute w-[500px] h-[500px] bg-romantic-primary/20 rounded-full blur-[100px] animate-pulse-slow"></div>
               <Heart className="text-white/40 w-80 h-80 animate-pulse" fill="currentColor" strokeWidth={0} />
            </div>

            <div className="z-10 w-full flex flex-col items-center">
              {/* Volume Hint */}
              <div className="mb-6 animate-bounce">
                <div className="flex items-center gap-2 bg-white/60 backdrop-blur-md px-4 py-1.5 rounded-full border border-white/60 shadow-sm text-romantic-secondary">
                  <Volume2 size={14} />
                  <span className="text-[10px] font-sans tracking-widest uppercase font-bold">Sesi Açın</span>
                </div>
              </div>

              {/* Title Section */}
              <div className="mb-8">
                <h1 className="font-script text-6xl md:text-7xl text-romantic-text mb-2 drop-shadow-sm transform -rotate-2">
                  Şeyma <span className="text-romantic-accent text-4xl">&</span> Akif
                </h1>
                <div className="flex items-center justify-center gap-3">
                   <div className="h-[1px] w-8 bg-romantic-secondary/30"></div>
                   <p className="font-serif text-lg md:text-xl text-romantic-secondary tracking-[0.2em] uppercase">En Güzel Günümüze</p>
                   <div className="h-[1px] w-8 bg-romantic-secondary/30"></div>
                </div>
              </div>

              {/* Countdown Section - Glassmorphism */}
              <div className="grid grid-cols-4 gap-3 mb-12 w-full max-w-sm">
                {[
                  { label: 'Gün', value: timeLeft.days },
                  { label: 'Saat', value: timeLeft.hours },
                  { label: 'Dakika', value: timeLeft.minutes },
                  { label: 'Saniye', value: timeLeft.seconds }
                ].map((item, idx) => (
                  <div key={idx} className="flex flex-col items-center p-3 bg-white/40 backdrop-blur-sm rounded-2xl border border-white/60 shadow-lg hover:bg-white/50 transition-colors">
                    <span className="font-serif text-2xl md:text-3xl font-bold text-romantic-text tabular-nums leading-none mb-1">
                      {String(item.value).padStart(2, '0')}
                    </span>
                    <span className="font-sans text-[9px] uppercase tracking-wider text-romantic-secondary/80 font-medium">
                      {item.label}
                    </span>
                  </div>
                ))}
              </div>

              {/* Login Section */}
              <div className="w-full max-w-xs space-y-5">
                <div className={`transition-transform duration-200 ${error ? 'translate-x-[-10px]' : ''}`}>
                  <div className="relative group">
                    <input
                      type="text"
                      value={password}
                      onChange={(e) => {
                        setPassword(e.target.value);
                        setError(false);
                      }}
                      onClick={(e) => e.stopPropagation()}
                      placeholder="Sihirli sözcük..."
                      className={`w-full bg-white/80 backdrop-blur-md border-2 ${error ? 'border-red-300 text-red-500 placeholder:text-red-300' : 'border-white text-romantic-text'} rounded-2xl px-6 py-4 text-center outline-none focus:border-romantic-primary focus:ring-4 focus:ring-romantic-primary/10 transition-all font-serif text-xl placeholder:text-romantic-text/30 shadow-xl placeholder:italic`}
                    />
                    {!password && <Heart size={16} className="absolute right-5 top-1/2 -translate-y-1/2 text-romantic-primary/40 animate-pulse" fill="currentColor" />}
                  </div>
                  {error && <p className="text-red-400 text-xs mt-2 font-sans text-center">İpucu: Birbirimize hep söylediğimiz o iki kelime...</p>}
                </div>

                <div className="flex justify-center">
                  <button 
                    onClick={handleStart}
                    className="group relative bg-gradient-to-r from-romantic-primary to-romantic-accent text-white px-12 py-4 rounded-full shadow-xl font-serif tracking-widest uppercase text-sm flex items-center gap-3 overflow-hidden transform transition-all hover:scale-105 active:scale-95 hover:shadow-2xl hover:brightness-110"
                  >
                    <div className="absolute inset-0 bg-white/20 translate-y-full group-hover:translate-y-0 transition-transform duration-300"></div>
                    <span className="relative flex items-center gap-2">
                      <Play size={16} className="fill-current" /> Hikayemiz Başlasın
                    </span>
                  </button>
                </div>
              </div>
            </div>
          </div>
        );

      case SlideType.WHATSAPP:
        return (
          <div className="flex flex-col h-full items-center justify-start pt-16 px-4 animate-fade-in relative z-20">
            <div className="w-full max-w-[320px] h-[55vh] md:h-[68vh] bg-[#E5DDD5] rounded-2xl shadow-2xl overflow-hidden flex flex-col relative border border-gray-300 ring-4 ring-black/5 mx-auto transition-all duration-300">
              <div className="bg-[#075E54] text-white p-2 px-3 flex items-center shadow-md z-10 shrink-0">
                <ArrowLeft size={18} className="mr-1" />
                <div className="w-8 h-8 bg-gray-300 rounded-full mr-2 flex items-center justify-center text-gray-500 overflow-hidden shrink-0">
                  <div className="bg-gray-400 w-full h-full flex items-center justify-center text-xs font-bold">A</div>
                </div>
                <div className="flex-1 overflow-hidden">
                  <h3 className="font-semibold text-sm leading-tight truncate">{currentSlide.title}</h3>
                  <p className="text-[10px] opacity-80 truncate">Çevrimiçi</p>
                </div>
                <div className="flex gap-3 ml-2">
                  <Video size={16} />
                  <Phone size={16} />
                  <MoreVertical size={16} />
                </div>
              </div>
              <div className="flex-1 p-3 bg-[#E5DDD5] relative overflow-y-auto scrollbar-hide">
                  <div className="absolute inset-0 opacity-10 bg-[url('https://user-images.githubusercontent.com/15075759/28719144-86dc0f70-73b1-11e7-911d-60d70fcded21.png')] pointer-events-none"></div>
                  <div className="flex justify-center mb-4 relative z-10">
                    <span className="bg-[#D4EAF4] text-gray-600 text-[10px] font-medium px-2 py-0.5 rounded-lg shadow-sm">{currentSlide.date}</span>
                  </div>
                  <div className="space-y-2 relative z-10 pb-4">
                    {currentSlide.messages?.map((msg, idx) => (
                      <div key={idx} className={`flex ${msg.isSender ? 'justify-end' : 'justify-start'}`}>
                        <div className={`max-w-[85%] p-1.5 px-2.5 rounded-lg shadow-sm text-xs relative ${msg.isSender ? 'bg-[#E2FFC7] rounded-tr-none' : 'bg-white rounded-tl-none'}`}>
                          <p className="text-[#303030] leading-snug pb-1 whitespace-pre-wrap">{msg.text}</p>
                          <div className="text-right"><span className="text-[9px] text-gray-500">{msg.time}</span></div>
                        </div>
                      </div>
                    ))}
                  </div>
              </div>
            </div>
            <p className="mt-2 text-xs text-romantic-text/60 font-sans italic animate-pulse">(Mesajı aşağı kaydırabilirsin.)</p>
            {currentSlide.footerText && (
              <div className="mt-4 md:mt-6 text-center max-w-xs animate-fade-in" style={{ animationDelay: '0.5s' }}>
                  <p className="font-serif text-xl md:text-2xl text-romantic-text italic font-medium leading-relaxed drop-shadow-sm px-2">{currentSlide.footerText}</p>
              </div>
            )}
          </div>
        );

      case SlideType.MEMORY:
        return (
          <div className={`flex flex-col items-center justify-center h-full px-6 pb-20 animate-fade-in ${currentSlide.textAlign === 'text-left' ? 'items-start' : ''}`}>
            <div className={`relative p-3 bg-white shadow-2xl mb-4 ${currentSlide.containerClass || 'w-full max-w-sm'} ${currentSlide.imageRotate || 'rotate-2'}`}>
              <div className={`${currentSlide.aspectRatio === 'aspect-auto' ? '' : (currentSlide.aspectRatio || 'aspect-[3/4]')} ${currentSlide.aspectRatio === 'aspect-auto' ? '' : 'overflow-hidden'} bg-gray-200`}>
                <img src={currentSlide.image} alt={currentSlide.title} className={`w-full ${currentSlide.aspectRatio === 'aspect-auto' ? 'h-auto' : 'h-full object-cover'}`} />
              </div>
              <div className="absolute -bottom-10 right-0 font-script text-4xl text-romantic-secondary/50 opacity-50 z-[-1]">{currentSlide.watermark || 'Anılar'}</div>
            </div>
            {currentSlide.secondImage && (
              <div className={`relative p-3 bg-white shadow-2xl mb-8 w-full max-w-sm ${currentSlide.imageRotate ? '-'+currentSlide.imageRotate : '-rotate-2'}`}>
                <div className={`${currentSlide.aspectRatio || 'aspect-[3/4]'} overflow-hidden bg-gray-200`}>
                  <img src={currentSlide.secondImage} alt={currentSlide.title} className="w-full h-full object-cover" />
                </div>
              </div>
            )}
            <div className={`w-full max-w-sm ${currentSlide.textAlign || 'text-center'}`}>
              <h2 className="font-serif text-3xl mb-4 text-romantic-text">{currentSlide.title}</h2>
              <p className="font-sans text-lg leading-relaxed text-romantic-text/80 whitespace-pre-line">{currentSlide.text}</p>
              {currentSlide.author && <p className="mt-2 text-sm text-romantic-secondary italic text-right font-serif">— {currentSlide.author}</p>}
            </div>
          </div>
        );

      case SlideType.COLLAGE:
        let layoutClass = "grid grid-cols-2 gap-3";
        if (currentSlide.collageLayout === 'row') layoutClass = "flex flex-row gap-2 h-64 justify-center items-center";
        else if (currentSlide.collageLayout === 'col') layoutClass = "flex flex-col gap-4 w-full mx-auto";
        return (
          <div className="flex flex-col items-center justify-center h-full px-6 animate-fade-in">
             <h2 className="font-serif text-3xl mb-6 text-romantic-text text-center">{currentSlide.title}</h2>
             <div className={`w-full max-w-md bg-white p-3 shadow-xl transform rotate-1 ${layoutClass}`}>
                {currentSlide.collageImages?.map((img, idx) => (
                  <div key={idx} className={`bg-gray-100 rounded-sm ${currentSlide.collageLayout === 'row' ? 'flex-1 h-full overflow-hidden' : currentSlide.collageLayout === 'col' ? 'w-full' : 'aspect-square overflow-hidden'}`}>
                    <img src={img} alt={`Collage ${idx}`} className={`w-full hover:scale-110 transition-transform duration-500 ${currentSlide.collageLayout === 'col' ? 'h-auto' : 'h-full object-cover'}`} />
                  </div>
                ))}
             </div>
             {currentSlide.text && <div className="mt-12 text-center"><p className="font-script text-3xl text-romantic-text whitespace-pre-line leading-relaxed">{currentSlide.text}</p></div>}
          </div>
        );

      case SlideType.MESSAGE:
        return (
          <div className="flex flex-col items-center justify-center h-full px-8 text-center animate-fade-in relative">
            <div className="font-serif text-6xl text-romantic-primary opacity-20 absolute top-[20%] left-4">"</div>
            <h2 className="font-serif text-3xl md:text-4xl leading-relaxed text-romantic-text italic relative z-10">{currentSlide.text}</h2>
            <div className="font-serif text-6xl text-romantic-primary opacity-20 absolute bottom-[20%] right-4">"</div>
            <div className="mt-8"><Heart className="text-romantic-accent fill-current animate-pulse-slow" size={32} /></div>
          </div>
        );

      case SlideType.MUSIC:
        return (
          <div className="flex flex-col items-center justify-center h-full px-6 animate-fade-in">
             <div className="w-48 h-48 bg-gradient-to-br from-romantic-primary to-romantic-secondary rounded-full shadow-2xl flex items-center justify-center mb-10 animate-spin" style={{ animationDuration: '10s' }}><Music size={64} className="text-white" /></div>
             <div className="text-center mb-8">
                <h3 className="font-serif text-2xl font-bold text-romantic-text mb-1">{currentSlide.title}</h3>
                <p className="font-sans text-sm text-romantic-secondary uppercase tracking-widest">{currentSlide.text}</p>
             </div>
             <div className="space-y-2 text-center">
               {currentSlide.extra?.map((line, i) => <p key={i} className="font-serif text-xl italic text-romantic-text/70">{line}</p>)}
             </div>
          </div>
        );

      case SlideType.DREAMS:
        return (
          <div className="flex flex-col items-center justify-center h-full px-8 animate-fade-in">
            <h2 className="font-script text-5xl mb-12 text-romantic-text">{currentSlide.title}</h2>
            <ul className="space-y-6 w-full max-w-md">
              {currentSlide.extra?.map((item, i) => (
                <li key={i} className="flex items-center gap-4 group">
                  <span className="w-8 h-8 flex items-center justify-center rounded-full bg-romantic-primary/20 text-romantic-accent group-hover:bg-romantic-accent group-hover:text-white transition-colors duration-300"><Heart size={14} className="fill-current" /></span>
                  <span className="font-serif text-xl text-romantic-text border-b border-transparent group-hover:border-romantic-primary transition-all">{item}</span>
                </li>
              ))}
            </ul>
          </div>
        );

      case SlideType.VIDEO:
        return (
          <div className="flex flex-col items-center justify-center h-full w-full animate-fade-in relative z-50 p-4">
             {currentSlide.title && <h2 className="font-serif text-2xl mb-4 text-romantic-text text-center">{currentSlide.title}</h2>}
             <div className="w-full max-w-sm aspect-[9/16] max-h-[70vh] rounded-2xl overflow-hidden shadow-2xl border-4 border-white/50 bg-black relative group">
               <iframe width="100%" height="100%" src={`https://www.youtube.com/embed/${currentSlide.videoId}?autoplay=1&playsinline=1&mute=1&rel=0&loop=1&playlist=${currentSlide.videoId}&controls=1&showinfo=0&modestbranding=1&iv_load_policy=3&fs=0`} title="YouTube video player" frameBorder="0" allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share" allowFullScreen className="w-full h-full object-cover"></iframe>
             </div>
             <div className="mt-4 flex items-center gap-2 text-romantic-text/60 animate-pulse bg-white/50 px-3 py-1 rounded-full"><VolumeX size={14} /><p className="font-sans text-xs">Otomatik başlamazsa veya ses gelmezse videoya dokunun.</p></div>
          </div>
        );

      case SlideType.FINAL:
        return (
          <div className="flex flex-col items-center justify-center h-full px-6 text-center animate-fade-in">
            <h1 className="font-script text-6xl mb-6 text-romantic-text">{currentSlide.title}</h1>
            <p className="font-serif text-xl text-romantic-secondary mb-12">{currentSlide.text}</p>
            <div className="relative cursor-pointer group" onClick={(e) => { e.stopPropagation(); setCurrentIndex(prev => prev + 1); }}>
              <Heart size={150} className="text-romantic-accent fill-current animate-pulse group-hover:scale-110 transition-transform duration-300" />
              <span className="absolute inset-0 flex items-center justify-center text-white font-bold font-sans text-sm tracking-wider animate-bounce">Buraya Bas</span>
            </div>
            <button onClick={restart} className="mt-20 text-xs font-sans uppercase tracking-widest text-romantic-secondary/50 hover:text-romantic-secondary transition-colors z-50 p-4 cursor-pointer">Başa Dön ↺</button>
          </div>
        );
      default: return null;
    }
  };

  return (
    <div onClick={handleInteraction} className="relative w-full h-[100dvh] bg-romantic-bg overflow-hidden cursor-pointer select-none">
      <div id="youtube-player" className="absolute top-0 left-0 opacity-1 pointer-events-none -z-50 h-[1px] w-[1px]" />
      <ProgressBar total={SLIDES.length} current={currentIndex} />
      <FloatingHearts />
      <div className="absolute top-[-20%] right-[-10%] w-[500px] h-[500px] bg-romantic-primary/20 rounded-full blur-[100px] pointer-events-none" />
      <div className="absolute bottom-[-10%] left-[-10%] w-[400px] h-[400px] bg-romantic-secondary/20 rounded-full blur-[80px] pointer-events-none" />
      <main className="relative z-10 w-full h-full max-w-lg mx-auto transition-all duration-700 ease-in-out">
        {renderContent()}
      </main>
      {currentIndex > 0 && (
        <div className="absolute bottom-12 md:bottom-8 w-full z-50 pointer-events-none px-8" style={{ paddingBottom: 'env(safe-area-inset-bottom)' }}>
          <div className="flex items-center justify-between text-romantic-text/40">
            <div className={`w-24 flex justify-start transition-opacity duration-300 ${currentIndex > 1 ? 'opacity-100 animate-pulse' : 'opacity-0'}`}><div className="flex items-center gap-1 font-sans text-[10px] uppercase tracking-widest"><ChevronLeft size={10} /> Geri</div></div>
            <div className="font-serif text-sm font-medium tracking-widest opacity-60">{currentIndex} / {SLIDES.length - 1}</div>
            <div className={`w-24 flex justify-end transition-opacity duration-300 ${currentIndex < SLIDES.length - 1 ? 'opacity-100 animate-pulse' : 'opacity-0'}`}><div className="flex items-center gap-1 font-sans text-[10px] uppercase tracking-widest">İleri <ChevronRight size={10} /></div></div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect, useCallback, useMemo } from 'react';
import { Play, Music, Heart, ChevronRight, ChevronLeft, Volume2, Lock, ArrowLeft, Phone, Video, MoreVertical, ChevronsDown, VolumeX } from 'lucide-react';
import { SLIDES, YOUTUBE_VIDEO_ID } from './constants';
import { SlideType } from './types';
import ProgressBar from './components/ProgressBar';
import FloatingHearts from './components/FloatingHearts';

// Helper to access window globals for YouTube API
declare global {
  interface Window {
    onYouTubeIframeAPIReady: () => void;
    YT: any;
  }
}

const App: React.FC = () => {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [isPlaying, setIsPlaying] = useState(false);
  const [password, setPassword] = useState('');
  const [error, setError] = useState(false);
  const playerRef = useRef<any>(null);

  // Countdown State
  const [timeLeft, setTimeLeft] = useState({
    days: 0,
    hours: 0,
    minutes: 0,
    seconds: 0
  });

  // Calculate Countdown
  useEffect(() => {
    const targetDate = new Date('2026-04-25T00:00:00').getTime();

    const interval = setInterval(() => {
      const now = new Date().getTime();
      const difference = targetDate - now;

      if (difference <= 0) {
        clearInterval(interval);
        setTimeLeft({ days: 0, hours: 0, minutes: 0, seconds: 0 });
      } else {
        setTimeLeft({
          days: Math.floor(difference / (1000 * 60 * 60 * 24)),
          hours: Math.floor((difference % (1000 * 60 * 60 * 24)) / (1000 * 60 * 60)),
          minutes: Math.floor((difference % (1000 * 60 * 60)) / (1000 * 60)),
          seconds: Math.floor((difference % (1000 * 60)) / 1000)
        });
      }
    }, 1000);

    return () => clearInterval(interval);
  }, []);

  // Generate static random hearts for Intro to avoid re-render flicker
  const introHearts = useMemo(() => {
    return Array.from({ length: 50 }).map((_, i) => ({
      id: i,
      left: Math.random() * 100, // Random horizontal position 0-100%
      delay: Math.random() * 20, // Spread start times
      duration: 10 + Math.random() * 20, // Slow floating (10s to 30s)
      size: 10 + Math.random() * 40, // Varied sizes (10px to 50px)
      color: Math.random() > 0.5 ? '#FF6B6B' : '#D4A5A5',
      opacity: 0.3 + Math.random() * 0.5 // Opacity between 0.3 and 0.8
    }));
  }, []);

  // Initialize YouTube API
  useEffect(() => {
    if (!window.YT) {
      const tag = document.createElement('script');
      tag.src = "https://www.youtube.com/iframe_api";
      const firstScriptTag = document.getElementsByTagName('script')[0];
      firstScriptTag.parentNode?.insertBefore(tag, firstScriptTag);
    }

    window.onYouTubeIframeAPIReady = () => {
      playerRef.current = new window.YT.Player('youtube-player', {
        height: '1',
        width: '1',
        videoId: YOUTUBE_VIDEO_ID,
        playerVars: {
          'playsinline': 1,
          'controls': 0,
          'disablekb': 1,
          'fs': 0,
          'loop': 1,
          'playlist': YOUTUBE_VIDEO_ID
        },
        events: {
          'onReady': (event: any) => {
             event.target.setVolume(50);
          }
        }
      });
    };

    return () => {
      if (playerRef.current && playerRef.current.destroy) {
        playerRef.current.destroy();
      }
    };
  }, []);

  useEffect(() => {
    if (currentIndex === 0) return;
    const currentSlide = SLIDES[currentIndex];
    if (currentSlide.type === SlideType.VIDEO) {
        if (playerRef.current && playerRef.current.pauseVideo) {
            playerRef.current.pauseVideo();
            setIsPlaying(false);
        }
    } else {
        if (!isPlaying && playerRef.current && playerRef.current.playVideo) {
            playerRef.current.playVideo();
            setIsPlaying(true);
        }
    }
  }, [currentIndex]);

  const handleStart = (e: React.MouseEvent) => {
    e.stopPropagation();
    const cleanInput = password.toLowerCase().replace(/\s/g, '');
    if (cleanInput === 'seniseviyorum') {
      if (playerRef.current && playerRef.current.playVideo) {
        playerRef.current.playVideo();
        setIsPlaying(true);
      }
      setCurrentIndex(1);
      setError(false);
    } else {
      setError(true);
      setTimeout(() => setError(false), 500);
    }
  };

  const handleInteraction = useCallback((e: React.MouseEvent) => {
    if (currentIndex === 0) return;
    if (SLIDES[currentIndex].type !== SlideType.VIDEO && !isPlaying && playerRef.current && playerRef.current.playVideo) {
      playerRef.current.playVideo();
      setIsPlaying(true);
    }
    const { clientX } = e;
    const { innerWidth } = window;
    if (clientX > innerWidth / 2) {
      if (SLIDES[currentIndex].type === SlideType.FINAL) return;
      if (currentIndex < SLIDES.length - 1) setCurrentIndex((prev) => prev + 1);
    } else {
      if (currentIndex > 0) setCurrentIndex((prev) => prev - 1);
    }
  }, [currentIndex, isPlaying]);

  const restart = (e: React.MouseEvent) => {
    e.stopPropagation();
    setCurrentIndex(0);
    setPassword('');
    setIsPlaying(false);
    if (playerRef.current && playerRef.current.stopVideo) {
       playerRef.current.stopVideo();
    }
  };

  const renderContent = () => {
    const currentSlide = SLIDES[currentIndex];
    switch (currentSlide.type) {
      case SlideType.INTRO:
        return (
          <div className="flex flex-col items-center justify-center h-full text-center px-6 animate-fade-in relative overflow-hidden">
            {/* Flying Hearts Background */}
            <div className="absolute inset-0 overflow-hidden pointer-events-none z-0">
               {introHearts.map((heart) => (
                 <div
                   key={heart.id}
                   className="absolute -bottom-10"
                   style={{
                     left: `${heart.left}%`,
                     animation: `floatUp ${heart.duration}s linear infinite`,
                     animationDelay: `-${heart.delay}s`,
                     color: heart.color,
                     opacity: heart.opacity
                   }}
                 >
                   <Heart size={heart.size} fill="currentColor" />
                 </div>
               ))}
            </div>

            {/* Romantic Background Decoration for Intro */}
            <div className="absolute inset-0 z-0 flex items-center justify-center pointer-events-none">
               <div className="absolute w-[500px] h-[500px] bg-romantic-primary/20 rounded-full blur-[100px] animate-pulse-slow"></div>
               <Heart className="text-white/40 w-80 h-80 animate-pulse" fill="currentColor" strokeWidth={0} />
            </div>

            <div className="z-10 w-full flex flex-col items-center">
              {/* Volume Hint */}
              <div className="mb-6 animate-bounce">
                <div className="flex items-center gap-2 bg-white/60 backdrop-blur-md px-4 py-1.5 rounded-full border border-white/60 shadow-sm text-romantic-secondary">
                  <Volume2 size={14} />
                  <span className="text-[10px] font-sans tracking-widest uppercase font-bold">Sesi Açın</span>
                </div>
              </div>

              {/* Title Section */}
              <div className="mb-8">
                <h1 className="font-script text-6xl md:text-7xl text-romantic-text mb-2 drop-shadow-sm transform -rotate-2">
                  Şeyma <span className="text-romantic-accent text-4xl">&</span> Akif
                </h1>
                <div className="flex items-center justify-center gap-3">
                   <div className="h-[1px] w-8 bg-romantic-secondary/30"></div>
                   <p className="font-serif text-lg md:text-xl text-romantic-secondary tracking-[0.2em] uppercase">En Güzel Günümüze</p>
                   <div className="h-[1px] w-8 bg-romantic-secondary/30"></div>
                </div>
              </div>

              {/* Countdown Section - Glassmorphism */}
              <div className="grid grid-cols-4 gap-3 mb-12 w-full max-w-sm">
                {[
                  { label: 'Gün', value: timeLeft.days },
                  { label: 'Saat', value: timeLeft.hours },
                  { label: 'Dakika', value: timeLeft.minutes },
                  { label: 'Saniye', value: timeLeft.seconds }
                ].map((item, idx) => (
                  <div key={idx} className="flex flex-col items-center p-3 bg-white/40 backdrop-blur-sm rounded-2xl border border-white/60 shadow-lg hover:bg-white/50 transition-colors">
                    <span className="font-serif text-2xl md:text-3xl font-bold text-romantic-text tabular-nums leading-none mb-1">
                      {String(item.value).padStart(2, '0')}
                    </span>
                    <span className="font-sans text-[9px] uppercase tracking-wider text-romantic-secondary/80 font-medium">
                      {item.label}
                    </span>
                  </div>
                ))}
              </div>

              {/* Login Section */}
              <div className="w-full max-w-xs space-y-5">
                <div className={`transition-transform duration-200 ${error ? 'translate-x-[-10px]' : ''}`}>
                  <div className="relative group">
                    <input
                      type="text"
                      value={password}
                      onChange={(e) => {
                        setPassword(e.target.value);
                        setError(false);
                      }}
                      onClick={(e) => e.stopPropagation()}
                      placeholder="Sihirli sözcük..."
                      className={`w-full bg-white/80 backdrop-blur-md border-2 ${error ? 'border-red-300 text-red-500 placeholder:text-red-300' : 'border-white text-romantic-text'} rounded-2xl px-6 py-4 text-center outline-none focus:border-romantic-primary focus:ring-4 focus:ring-romantic-primary/10 transition-all font-serif text-xl placeholder:text-romantic-text/30 shadow-xl placeholder:italic`}
                    />
                    {!password && <Heart size={16} className="absolute right-5 top-1/2 -translate-y-1/2 text-romantic-primary/40 animate-pulse" fill="currentColor" />}
                  </div>
                  {error && <p className="text-red-400 text-xs mt-2 font-sans text-center">İpucu: Birbirimize hep söylediğimiz o iki kelime...</p>}
                </div>

                <div className="flex justify-center">
                  <button 
                    onClick={handleStart}
                    className="group relative bg-gradient-to-r from-romantic-primary to-romantic-accent text-white px-12 py-4 rounded-full shadow-xl font-serif tracking-widest uppercase text-sm flex items-center gap-3 overflow-hidden transform transition-all hover:scale-105 active:scale-95 hover:shadow-2xl hover:brightness-110"
                  >
                    <div className="absolute inset-0 bg-white/20 translate-y-full group-hover:translate-y-0 transition-transform duration-300"></div>
                    <span className="relative flex items-center gap-2">
                      <Play size={16} className="fill-current" /> Hikayemiz Başlasın
                    </span>
                  </button>
                </div>
              </div>
            </div>
          </div>
        );

      case SlideType.WHATSAPP:
        return (
          <div className="flex flex-col h-full items-center justify-start pt-16 px-4 animate-fade-in relative z-20">
            <div className="w-full max-w-[320px] h-[55vh] md:h-[68vh] bg-[#E5DDD5] rounded-2xl shadow-2xl overflow-hidden flex flex-col relative border border-gray-300 ring-4 ring-black/5 mx-auto transition-all duration-300">
              <div className="bg-[#075E54] text-white p-2 px-3 flex items-center shadow-md z-10 shrink-0">
                <ArrowLeft size={18} className="mr-1" />
                <div className="w-8 h-8 bg-gray-300 rounded-full mr-2 flex items-center justify-center text-gray-500 overflow-hidden shrink-0">
                  <div className="bg-gray-400 w-full h-full flex items-center justify-center text-xs font-bold">A</div>
                </div>
                <div className="flex-1 overflow-hidden">
                  <h3 className="font-semibold text-sm leading-tight truncate">{currentSlide.title}</h3>
                  <p className="text-[10px] opacity-80 truncate">Çevrimiçi</p>
                </div>
                <div className="flex gap-3 ml-2">
                  <Video size={16} />
                  <Phone size={16} />
                  <MoreVertical size={16} />
                </div>
              </div>
              <div className="flex-1 p-3 bg-[#E5DDD5] relative overflow-y-auto scrollbar-hide">
                  <div className="absolute inset-0 opacity-10 bg-[url('https://user-images.githubusercontent.com/15075759/28719144-86dc0f70-73b1-11e7-911d-60d70fcded21.png')] pointer-events-none"></div>
                  <div className="flex justify-center mb-4 relative z-10">
                    <span className="bg-[#D4EAF4] text-gray-600 text-[10px] font-medium px-2 py-0.5 rounded-lg shadow-sm">{currentSlide.date}</span>
                  </div>
                  <div className="space-y-2 relative z-10 pb-4">
                    {currentSlide.messages?.map((msg, idx) => (
                      <div key={idx} className={`flex ${msg.isSender ? 'justify-end' : 'justify-start'}`}>
                        <div className={`max-w-[85%] p-1.5 px-2.5 rounded-lg shadow-sm text-xs relative ${msg.isSender ? 'bg-[#E2FFC7] rounded-tr-none' : 'bg-white rounded-tl-none'}`}>
                          <p className="text-[#303030] leading-snug pb-1 whitespace-pre-wrap">{msg.text}</p>
                          <div className="text-right"><span className="text-[9px] text-gray-500">{msg.time}</span></div>
                        </div>
                      </div>
                    ))}
                  </div>
              </div>
            </div>
            <p className="mt-2 text-xs text-romantic-text/60 font-sans italic animate-pulse">(Mesajı aşağı kaydırabilirsin.)</p>
            {currentSlide.footerText && (
              <div className="mt-4 md:mt-6 text-center max-w-xs animate-fade-in" style={{ animationDelay: '0.5s' }}>
                  <p className="font-serif text-xl md:text-2xl text-romantic-text italic font-medium leading-relaxed drop-shadow-sm px-2">{currentSlide.footerText}</p>
              </div>
            )}
          </div>
        );

      case SlideType.MEMORY:
        return (
          <div className={`flex flex-col items-center justify-center h-full px-6 pb-20 animate-fade-in ${currentSlide.textAlign === 'text-left' ? 'items-start' : ''}`}>
            <div className={`relative p-3 bg-white shadow-2xl mb-4 ${currentSlide.containerClass || 'w-full max-w-sm'} ${currentSlide.imageRotate || 'rotate-2'}`}>
              <div className={`${currentSlide.aspectRatio === 'aspect-auto' ? '' : (currentSlide.aspectRatio || 'aspect-[3/4]')} ${currentSlide.aspectRatio === 'aspect-auto' ? '' : 'overflow-hidden'} bg-gray-200`}>
                <img src={currentSlide.image} alt={currentSlide.title} className={`w-full ${currentSlide.aspectRatio === 'aspect-auto' ? 'h-auto' : 'h-full object-cover'}`} />
              </div>
              <div className="absolute -bottom-10 right-0 font-script text-4xl text-romantic-secondary/50 opacity-50 z-[-1]">{currentSlide.watermark || 'Anılar'}</div>
            </div>
            {currentSlide.secondImage && (
              <div className={`relative p-3 bg-white shadow-2xl mb-8 w-full max-w-sm ${currentSlide.imageRotate ? '-'+currentSlide.imageRotate : '-rotate-2'}`}>
                <div className={`${currentSlide.aspectRatio || 'aspect-[3/4]'} overflow-hidden bg-gray-200`}>
                  <img src={currentSlide.secondImage} alt={currentSlide.title} className="w-full h-full object-cover" />
                </div>
              </div>
            )}
            <div className={`w-full max-w-sm ${currentSlide.textAlign || 'text-center'}`}>
              <h2 className="font-serif text-3xl mb-4 text-romantic-text">{currentSlide.title}</h2>
              <p className="font-sans text-lg leading-relaxed text-romantic-text/80 whitespace-pre-line">{currentSlide.text}</p>
              {currentSlide.author && <p className="mt-2 text-sm text-romantic-secondary italic text-right font-serif">— {currentSlide.author}</p>}
            </div>
          </div>
        );

      case SlideType.COLLAGE:
        let layoutClass = "grid grid-cols-2 gap-3";
        if (currentSlide.collageLayout === 'row') layoutClass = "flex flex-row gap-2 h-64 justify-center items-center";
        else if (currentSlide.collageLayout === 'col') layoutClass = "flex flex-col gap-4 w-full mx-auto";
        return (
          <div className="flex flex-col items-center justify-center h-full px-6 animate-fade-in">
             <h2 className="font-serif text-3xl mb-6 text-romantic-text text-center">{currentSlide.title}</h2>
             <div className={`w-full max-w-md bg-white p-3 shadow-xl transform rotate-1 ${layoutClass}`}>
                {currentSlide.collageImages?.map((img, idx) => (
                  <div key={idx} className={`bg-gray-100 rounded-sm ${currentSlide.collageLayout === 'row' ? 'flex-1 h-full overflow-hidden' : currentSlide.collageLayout === 'col' ? 'w-full' : 'aspect-square overflow-hidden'}`}>
                    <img src={img} alt={`Collage ${idx}`} className={`w-full hover:scale-110 transition-transform duration-500 ${currentSlide.collageLayout === 'col' ? 'h-auto' : 'h-full object-cover'}`} />
                  </div>
                ))}
             </div>
             {currentSlide.text && <div className="mt-12 text-center"><p className="font-script text-3xl text-romantic-text whitespace-pre-line leading-relaxed">{currentSlide.text}</p></div>}
          </div>
        );

      case SlideType.MESSAGE:
        return (
          <div className="flex flex-col items-center justify-center h-full px-8 text-center animate-fade-in relative">
            <div className="font-serif text-6xl text-romantic-primary opacity-20 absolute top-[20%] left-4">"</div>
            <h2 className="font-serif text-3xl md:text-4xl leading-relaxed text-romantic-text italic relative z-10">{currentSlide.text}</h2>
            <div className="font-serif text-6xl text-romantic-primary opacity-20 absolute bottom-[20%] right-4">"</div>
            <div className="mt-8"><Heart className="text-romantic-accent fill-current animate-pulse-slow" size={32} /></div>
          </div>
        );

      case SlideType.MUSIC:
        return (
          <div className="flex flex-col items-center justify-center h-full px-6 animate-fade-in">
             <div className="w-48 h-48 bg-gradient-to-br from-romantic-primary to-romantic-secondary rounded-full shadow-2xl flex items-center justify-center mb-10 animate-spin" style={{ animationDuration: '10s' }}><Music size={64} className="text-white" /></div>
             <div className="text-center mb-8">
                <h3 className="font-serif text-2xl font-bold text-romantic-text mb-1">{currentSlide.title}</h3>
                <p className="font-sans text-sm text-romantic-secondary uppercase tracking-widest">{currentSlide.text}</p>
             </div>
             <div className="space-y-2 text-center">
               {currentSlide.extra?.map((line, i) => <p key={i} className="font-serif text-xl italic text-romantic-text/70">{line}</p>)}
             </div>
          </div>
        );

      case SlideType.DREAMS:
        return (
          <div className="flex flex-col items-center justify-center h-full px-8 animate-fade-in">
            <h2 className="font-script text-5xl mb-12 text-romantic-text">{currentSlide.title}</h2>
            <ul className="space-y-6 w-full max-w-md">
              {currentSlide.extra?.map((item, i) => (
                <li key={i} className="flex items-center gap-4 group">
                  <span className="w-8 h-8 flex items-center justify-center rounded-full bg-romantic-primary/20 text-romantic-accent group-hover:bg-romantic-accent group-hover:text-white transition-colors duration-300"><Heart size={14} className="fill-current" /></span>
                  <span className="font-serif text-xl text-romantic-text border-b border-transparent group-hover:border-romantic-primary transition-all">{item}</span>
                </li>
              ))}
            </ul>
          </div>
        );

      case SlideType.VIDEO:
        return (
          <div className="flex flex-col items-center justify-center h-full w-full animate-fade-in relative z-50 p-4">
             {currentSlide.title && <h2 className="font-serif text-2xl mb-4 text-romantic-text text-center">{currentSlide.title}</h2>}
             <div className="w-full max-w-sm aspect-[9/16] max-h-[70vh] rounded-2xl overflow-hidden shadow-2xl border-4 border-white/50 bg-black relative group">
               <iframe width="100%" height="100%" src={`https://www.youtube.com/embed/${currentSlide.videoId}?autoplay=1&playsinline=1&mute=1&rel=0&loop=1&playlist=${currentSlide.videoId}&controls=1&showinfo=0&modestbranding=1&iv_load_policy=3&fs=0`} title="YouTube video player" frameBorder="0" allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share" allowFullScreen className="w-full h-full object-cover"></iframe>
             </div>
             <div className="mt-4 flex items-center gap-2 text-romantic-text/60 animate-pulse bg-white/50 px-3 py-1 rounded-full"><VolumeX size={14} /><p className="font-sans text-xs">Otomatik başlamazsa veya ses gelmezse videoya dokunun.</p></div>
          </div>
        );

      case SlideType.FINAL:
        return (
          <div className="flex flex-col items-center justify-center h-full px-6 text-center animate-fade-in">
            <h1 className="font-script text-6xl mb-6 text-romantic-text">{currentSlide.title}</h1>
            <p className="font-serif text-xl text-romantic-secondary mb-12">{currentSlide.text}</p>
            <div className="relative cursor-pointer group" onClick={(e) => { e.stopPropagation(); setCurrentIndex(prev => prev + 1); }}>
              <Heart size={150} className="text-romantic-accent fill-current animate-pulse group-hover:scale-110 transition-transform duration-300" />
              <span className="absolute inset-0 flex items-center justify-center text-white font-bold font-sans text-sm tracking-wider animate-bounce">Buraya Bas</span>
            </div>
            <button onClick={restart} className="mt-20 text-xs font-sans uppercase tracking-widest text-romantic-secondary/50 hover:text-romantic-secondary transition-colors z-50 p-4 cursor-pointer">Başa Dön ↺</button>
          </div>
        );
      default: return null;
    }
  };

  return (
    <div onClick={handleInteraction} className="relative w-full h-[100dvh] bg-romantic-bg overflow-hidden cursor-pointer select-none">
      <div id="youtube-player" className="absolute top-0 left-0 opacity-1 pointer-events-none -z-50 h-[1px] w-[1px]" />
      <ProgressBar total={SLIDES.length} current={currentIndex} />
      <FloatingHearts />
      <div className="absolute top-[-20%] right-[-10%] w-[500px] h-[500px] bg-romantic-primary/20 rounded-full blur-[100px] pointer-events-none" />
      <div className="absolute bottom-[-10%] left-[-10%] w-[400px] h-[400px] bg-romantic-secondary/20 rounded-full blur-[80px] pointer-events-none" />
      <main className="relative z-10 w-full h-full max-w-lg mx-auto transition-all duration-700 ease-in-out">
        {renderContent()}
      </main>
      {currentIndex > 0 && (
        <div className="absolute bottom-12 md:bottom-8 w-full z-50 pointer-events-none px-8" style={{ paddingBottom: 'env(safe-area-inset-bottom)' }}>
          <div className="flex items-center justify-between text-romantic-text/40">
            <div className={`w-24 flex justify-start transition-opacity duration-300 ${currentIndex > 1 ? 'opacity-100 animate-pulse' : 'opacity-0'}`}><div className="flex items-center gap-1 font-sans text-[10px] uppercase tracking-widest"><ChevronLeft size={10} /> Geri</div></div>
            <div className="font-serif text-sm font-medium tracking-widest opacity-60">{currentIndex} / {SLIDES.length - 1}</div>
            <div className={`w-24 flex justify-end transition-opacity duration-300 ${currentIndex < SLIDES.length - 1 ? 'opacity-100 animate-pulse' : 'opacity-0'}`}><div className="flex items-center gap-1 font-sans text-[10px] uppercase tracking-widest">İleri <ChevronRight size={10} /></div></div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect, useCallback, useMemo } from 'react';
import { Play, Music, Heart, ChevronRight, ChevronLeft, Volume2, Lock, ArrowLeft, Phone, Video, MoreVertical, ChevronsDown, VolumeX } from 'lucide-react';
import { SLIDES, YOUTUBE_VIDEO_ID } from './constants';
import { SlideType } from './types';
import ProgressBar from './components/ProgressBar';
import FloatingHearts from './components/FloatingHearts';

// Helper to access window globals for YouTube API
declare global {
  interface Window {
    onYouTubeIframeAPIReady: () => void;
    YT: any;
  }
}

const App: React.FC = () => {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [isPlaying, setIsPlaying] = useState(false);
  const [password, setPassword] = useState('');
  const [error, setError] = useState(false);
  const playerRef = useRef<any>(null);

  // Countdown State
  const [timeLeft, setTimeLeft] = useState({
    days: 0,
    hours: 0,
    minutes: 0,
    seconds: 0
  });

  // Calculate Countdown
  useEffect(() => {
    const targetDate = new Date('2026-04-25T00:00:00').getTime();

    const interval = setInterval(() => {
      const now = new Date().getTime();
      const difference = targetDate - now;

      if (difference <= 0) {
        clearInterval(interval);
        setTimeLeft({ days: 0, hours: 0, minutes: 0, seconds: 0 });
      } else {
        setTimeLeft({
          days: Math.floor(difference / (1000 * 60 * 60 * 24)),
          hours: Math.floor((difference % (1000 * 60 * 60 * 24)) / (1000 * 60 * 60)),
          minutes: Math.floor((difference % (1000 * 60 * 60)) / (1000 * 60)),
          seconds: Math.floor((difference % (1000 * 60)) / 1000)
        });
      }
    }, 1000);

    return () => clearInterval(interval);
  }, []);

  // Generate static random hearts for Intro to avoid re-render flicker
  const introHearts = useMemo(() => {
    return Array.from({ length: 50 }).map((_, i) => ({
      id: i,
      left: Math.random() * 100, // Random horizontal position 0-100%
      delay: Math.random() * 20, // Spread start times
      duration: 8 + Math.random() * 12, // Faster floating (8s to 20s)
      size: 15 + Math.random() * 35, // Varied sizes (15px to 50px)
      color: Math.random() > 0.5 ? '#FF6B6B' : '#D4A5A5',
      opacity: 0.6 + Math.random() * 0.4 // High opacity for better visibility
    }));
  }, []);

  // Initialize YouTube API
  useEffect(() => {
    if (!window.YT) {
      const tag = document.createElement('script');
      tag.src = "https://www.youtube.com/iframe_api";
      const firstScriptTag = document.getElementsByTagName('script')[0];
      firstScriptTag.parentNode?.insertBefore(tag, firstScriptTag);
    }

    window.onYouTubeIframeAPIReady = () => {
      playerRef.current = new window.YT.Player('youtube-player', {
        height: '1',
        width: '1',
        videoId: YOUTUBE_VIDEO_ID,
        playerVars: {
          'playsinline': 1,
          'controls': 0,
          'disablekb': 1,
          'fs': 0,
          'loop': 1,
          'playlist': YOUTUBE_VIDEO_ID
        },
        events: {
          'onReady': (event: any) => {
             event.target.setVolume(50);
          }
        }
      });
    };

    return () => {
      if (playerRef.current && playerRef.current.destroy) {
        playerRef.current.destroy();
      }
    };
  }, []);

  useEffect(() => {
    if (currentIndex === 0) return;
    const currentSlide = SLIDES[currentIndex];
    if (currentSlide.type === SlideType.VIDEO) {
        if (playerRef.current && playerRef.current.pauseVideo) {
            playerRef.current.pauseVideo();
            setIsPlaying(false);
        }
    } else {
        if (!isPlaying && playerRef.current && playerRef.current.playVideo) {
            playerRef.current.playVideo();
            setIsPlaying(true);
        }
    }
  }, [currentIndex]);

  const handleStart = (e: React.MouseEvent) => {
    e.stopPropagation();
    const cleanInput = password.toLowerCase().replace(/\s/g, '');
    if (cleanInput === 'seniseviyorum') {
      if (playerRef.current && playerRef.current.playVideo) {
        playerRef.current.playVideo();
        setIsPlaying(true);
      }
      setCurrentIndex(1);
      setError(false);
    } else {
      setError(true);
      setTimeout(() => setError(false), 500);
    }
  };

  const handleInteraction = useCallback((e: React.MouseEvent) => {
    if (currentIndex === 0) return;
    if (SLIDES[currentIndex].type !== SlideType.VIDEO && !isPlaying && playerRef.current && playerRef.current.playVideo) {
      playerRef.current.playVideo();
      setIsPlaying(true);
    }
    const { clientX } = e;
    const { innerWidth } = window;
    if (clientX > innerWidth / 2) {
      if (SLIDES[currentIndex].type === SlideType.FINAL) return;
      if (currentIndex < SLIDES.length - 1) setCurrentIndex((prev) => prev + 1);
    } else {
      if (currentIndex > 0) setCurrentIndex((prev) => prev - 1);
    }
  }, [currentIndex, isPlaying]);

  const restart = (e: React.MouseEvent) => {
    e.stopPropagation();
    setCurrentIndex(0);
    setPassword('');
    setIsPlaying(false);
    if (playerRef.current && playerRef.current.stopVideo) {
       playerRef.current.stopVideo();
    }
  };

  const renderContent = () => {
    const currentSlide = SLIDES[currentIndex];
    switch (currentSlide.type) {
      case SlideType.INTRO:
        return (
          <div className="flex flex-col items-center justify-center h-full text-center px-6 animate-fade-in relative overflow-hidden">
            {/* Flying Hearts Background */}
            <div className="absolute inset-0 overflow-hidden pointer-events-none z-0">
               {introHearts.map((heart) => (
                 <div
                   key={heart.id}
                   className="absolute -bottom-10"
                   style={{
                     left: `${heart.left}%`,
                     animation: `floatUp ${heart.duration}s linear infinite`,
                     animationDelay: `-${heart.delay}s`,
                     color: heart.color,
                     opacity: heart.opacity
                   }}
                 >
                   <Heart size={heart.size} fill="currentColor" />
                 </div>
               ))}
            </div>

            {/* Romantic Background Decoration for Intro */}
            <div className="absolute inset-0 z-0 flex items-center justify-center pointer-events-none">
               <div className="absolute w-[500px] h-[500px] bg-romantic-primary/20 rounded-full blur-[100px] animate-pulse-slow"></div>
               <Heart className="text-white/40 w-80 h-80 animate-pulse" fill="currentColor" strokeWidth={0} />
            </div>

            <div className="z-10 w-full flex flex-col items-center">
              {/* Volume Hint */}
              <div className="mb-6 animate-bounce">
                <div className="flex items-center gap-2 bg-white/60 backdrop-blur-md px-4 py-1.5 rounded-full border border-white/60 shadow-sm text-romantic-secondary">
                  <Volume2 size={14} />
                  <span className="text-[10px] font-sans tracking-widest uppercase font-bold">Sesi Açın</span>
                </div>
              </div>

              {/* Title Section */}
              <div className="mb-8">
                <h1 className="font-script text-6xl md:text-7xl text-romantic-text mb-2 drop-shadow-sm transform -rotate-2">
                  Şeyma <span className="text-romantic-accent text-4xl">&</span> Akif
                </h1>
                <div className="flex items-center justify-center gap-3">
                   <div className="h-[1px] w-8 bg-romantic-secondary/30"></div>
                   <p className="font-serif text-lg md:text-xl text-romantic-secondary tracking-[0.2em] uppercase">En Güzel Günümüze</p>
                   <div className="h-[1px] w-8 bg-romantic-secondary/30"></div>
                </div>
              </div>

              {/* Countdown Section - Glassmorphism */}
              <div className="grid grid-cols-4 gap-3 mb-12 w-full max-w-sm">
                {[
                  { label: 'Gün', value: timeLeft.days },
                  { label: 'Saat', value: timeLeft.hours },
                  { label: 'Dakika', value: timeLeft.minutes },
                  { label: 'Saniye', value: timeLeft.seconds }
                ].map((item, idx) => (
                  <div key={idx} className="flex flex-col items-center p-3 bg-white/40 backdrop-blur-sm rounded-2xl border border-white/60 shadow-lg hover:bg-white/50 transition-colors">
                    <span className="font-serif text-2xl md:text-3xl font-bold text-romantic-text tabular-nums leading-none mb-1">
                      {String(item.value).padStart(2, '0')}
                    </span>
                    <span className="font-sans text-[9px] uppercase tracking-wider text-romantic-secondary/80 font-medium">
                      {item.label}
                    </span>
                  </div>
                ))}
              </div>

              {/* Login Section */}
              <div className="w-full max-w-xs space-y-5">
                <div className={`transition-transform duration-200 ${error ? 'translate-x-[-10px]' : ''}`}>
                  <div className="relative group">
                    <input
                      type="text"
                      value={password}
                      onChange={(e) => {
                        setPassword(e.target.value);
                        setError(false);
                      }}
                      onClick={(e) => e.stopPropagation()}
                      placeholder="Sihirli sözcük..."
                      className={`w-full bg-white/80 backdrop-blur-md border-2 ${error ? 'border-red-300 text-red-500 placeholder:text-red-300' : 'border-white text-romantic-text'} rounded-2xl px-6 py-4 text-center outline-none focus:border-romantic-primary focus:ring-4 focus:ring-romantic-primary/10 transition-all font-serif text-xl placeholder:text-romantic-text/30 shadow-xl placeholder:italic`}
                    />
                    {!password && <Heart size={16} className="absolute right-5 top-1/2 -translate-y-1/2 text-romantic-primary/40 animate-pulse" fill="currentColor" />}
                  </div>
                  {error && <p className="text-red-400 text-xs mt-2 font-sans text-center">İpucu: Birbirimize hep söylediğimiz o iki kelime...</p>}
                </div>

                <div className="flex justify-center">
                  <button 
                    onClick={handleStart}
                    className="group relative bg-gradient-to-r from-romantic-primary to-romantic-accent text-white px-12 py-4 rounded-full shadow-xl font-serif tracking-widest uppercase text-sm flex items-center gap-3 overflow-hidden transform transition-all hover:scale-105 active:scale-95 hover:shadow-2xl hover:brightness-110"
                  >
                    <div className="absolute inset-0 bg-white/20 translate-y-full group-hover:translate-y-0 transition-transform duration-300"></div>
                    <span className="relative flex items-center gap-2">
                      <Play size={16} className="fill-current" /> Hikayemiz Başlasın
                    </span>
                  </button>
                </div>
              </div>
            </div>
          </div>
        );

      case SlideType.WHATSAPP:
        return (
          <div className="flex flex-col h-full items-center justify-start pt-16 px-4 animate-fade-in relative z-20">
            <div className="w-full max-w-[320px] h-[55vh] md:h-[68vh] bg-[#E5DDD5] rounded-2xl shadow-2xl overflow-hidden flex flex-col relative border border-gray-300 ring-4 ring-black/5 mx-auto transition-all duration-300">
              <div className="bg-[#075E54] text-white p-2 px-3 flex items-center shadow-md z-10 shrink-0">
                <ArrowLeft size={18} className="mr-1" />
                <div className="w-8 h-8 bg-gray-300 rounded-full mr-2 flex items-center justify-center text-gray-500 overflow-hidden shrink-0">
                  <div className="bg-gray-400 w-full h-full flex items-center justify-center text-xs font-bold">A</div>
                </div>
                <div className="flex-1 overflow-hidden">
                  <h3 className="font-semibold text-sm leading-tight truncate">{currentSlide.title}</h3>
                  <p className="text-[10px] opacity-80 truncate">Çevrimiçi</p>
                </div>
                <div className="flex gap-3 ml-2">
                  <Video size={16} />
                  <Phone size={16} />
                  <MoreVertical size={16} />
                </div>
              </div>
              <div className="flex-1 p-3 bg-[#E5DDD5] relative overflow-y-auto scrollbar-hide">
                  <div className="absolute inset-0 opacity-10 bg-[url('https://user-images.githubusercontent.com/15075759/28719144-86dc0f70-73b1-11e7-911d-60d70fcded21.png')] pointer-events-none"></div>
                  <div className="flex justify-center mb-4 relative z-10">
                    <span className="bg-[#D4EAF4] text-gray-600 text-[10px] font-medium px-2 py-0.5 rounded-lg shadow-sm">{currentSlide.date}</span>
                  </div>
                  <div className="space-y-2 relative z-10 pb-4">
                    {currentSlide.messages?.map((msg, idx) => (
                      <div key={idx} className={`flex ${msg.isSender ? 'justify-end' : 'justify-start'}`}>
                        <div className={`max-w-[85%] p-1.5 px-2.5 rounded-lg shadow-sm text-xs relative ${msg.isSender ? 'bg-[#E2FFC7] rounded-tr-none' : 'bg-white rounded-tl-none'}`}>
                          <p className="text-[#303030] leading-snug pb-1 whitespace-pre-wrap">{msg.text}</p>
                          <div className="text-right"><span className="text-[9px] text-gray-500">{msg.time}</span></div>
                        </div>
                      </div>
                    ))}
                  </div>
              </div>
            </div>
            <p className="mt-2 text-xs text-romantic-text/60 font-sans italic animate-pulse">(Mesajı aşağı kaydırabilirsin.)</p>
            {currentSlide.footerText && (
              <div className="mt-4 md:mt-6 text-center max-w-xs animate-fade-in" style={{ animationDelay: '0.5s' }}>
                  <p className="font-serif text-xl md:text-2xl text-romantic-text italic font-medium leading-relaxed drop-shadow-sm px-2">{currentSlide.footerText}</p>
              </div>
            )}
          </div>
        );

      case SlideType.MEMORY:
        return (
          <div className={`flex flex-col items-center justify-center h-full px-6 pb-20 animate-fade-in ${currentSlide.textAlign === 'text-left' ? 'items-start' : ''}`}>
            <div className={`relative p-3 bg-white shadow-2xl mb-4 ${currentSlide.containerClass || 'w-full max-w-sm'} ${currentSlide.imageRotate || 'rotate-2'}`}>
              <div className={`${currentSlide.aspectRatio === 'aspect-auto' ? '' : (currentSlide.aspectRatio || 'aspect-[3/4]')} ${currentSlide.aspectRatio === 'aspect-auto' ? '' : 'overflow-hidden'} bg-gray-200`}>
                <img src={currentSlide.image} alt={currentSlide.title} className={`w-full ${currentSlide.aspectRatio === 'aspect-auto' ? 'h-auto' : 'h-full object-cover'}`} />
              </div>
              <div className="absolute -bottom-10 right-0 font-script text-4xl text-romantic-secondary/50 opacity-50 z-[-1]">{currentSlide.watermark || 'Anılar'}</div>
            </div>
            {currentSlide.secondImage && (
              <div className={`relative p-3 bg-white shadow-2xl mb-8 w-full max-w-sm ${currentSlide.imageRotate ? '-'+currentSlide.imageRotate : '-rotate-2'}`}>
                <div className={`${currentSlide.aspectRatio || 'aspect-[3/4]'} overflow-hidden bg-gray-200`}>
                  <img src={currentSlide.secondImage} alt={currentSlide.title} className="w-full h-full object-cover" />
                </div>
              </div>
            )}
            <div className={`w-full max-w-sm ${currentSlide.textAlign || 'text-center'}`}>
              <h2 className="font-serif text-3xl mb-4 text-romantic-text">{currentSlide.title}</h2>
              <p className="font-sans text-lg leading-relaxed text-romantic-text/80 whitespace-pre-line">{currentSlide.text}</p>
              {currentSlide.author && <p className="mt-2 text-sm text-romantic-secondary italic text-right font-serif">— {currentSlide.author}</p>}
            </div>
          </div>
        );

      case SlideType.COLLAGE:
        let layoutClass = "grid grid-cols-2 gap-3";
        if (currentSlide.collageLayout === 'row') layoutClass = "flex flex-row gap-2 h-64 justify-center items-center";
        else if (currentSlide.collageLayout === 'col') layoutClass = "flex flex-col gap-4 w-full mx-auto";
        return (
          <div className="flex flex-col items-center justify-center h-full px-6 animate-fade-in">
             <h2 className="font-serif text-3xl mb-6 text-romantic-text text-center">{currentSlide.title}</h2>
             <div className={`w-full max-w-md bg-white p-3 shadow-xl transform rotate-1 ${layoutClass}`}>
                {currentSlide.collageImages?.map((img, idx) => (
                  <div key={idx} className={`bg-gray-100 rounded-sm ${currentSlide.collageLayout === 'row' ? 'flex-1 h-full overflow-hidden' : currentSlide.collageLayout === 'col' ? 'w-full' : 'aspect-square overflow-hidden'}`}>
                    <img src={img} alt={`Collage ${idx}`} className={`w-full hover:scale-110 transition-transform duration-500 ${currentSlide.collageLayout === 'col' ? 'h-auto' : 'h-full object-cover'}`} />
                  </div>
                ))}
             </div>
             {currentSlide.text && <div className="mt-12 text-center"><p className="font-script text-3xl text-romantic-text whitespace-pre-line leading-relaxed">{currentSlide.text}</p></div>}
          </div>
        );

      case SlideType.MESSAGE:
        return (
          <div className="flex flex-col items-center justify-center h-full px-8 text-center animate-fade-in relative">
            <div className="font-serif text-6xl text-romantic-primary opacity-20 absolute top-[20%] left-4">"</div>
            <h2 className="font-serif text-3xl md:text-4xl leading-relaxed text-romantic-text italic relative z-10">{currentSlide.text}</h2>
            <div className="font-serif text-6xl text-romantic-primary opacity-20 absolute bottom-[20%] right-4">"</div>
            <div className="mt-8"><Heart className="text-romantic-accent fill-current animate-pulse-slow" size={32} /></div>
          </div>
        );

      case SlideType.MUSIC:
        return (
          <div className="flex flex-col items-center justify-center h-full px-6 animate-fade-in">
             <div className="w-48 h-48 bg-gradient-to-br from-romantic-primary to-romantic-secondary rounded-full shadow-2xl flex items-center justify-center mb-10 animate-spin" style={{ animationDuration: '10s' }}><Music size={64} className="text-white" /></div>
             <div className="text-center mb-8">
                <h3 className="font-serif text-2xl font-bold text-romantic-text mb-1">{currentSlide.title}</h3>
                <p className="font-sans text-sm text-romantic-secondary uppercase tracking-widest">{currentSlide.text}</p>
             </div>
             <div className="space-y-2 text-center">
               {currentSlide.extra?.map((line, i) => <p key={i} className="font-serif text-xl italic text-romantic-text/70">{line}</p>)}
             </div>
          </div>
        );

      case SlideType.DREAMS:
        return (
          <div className="flex flex-col items-center justify-center h-full px-8 animate-fade-in">
            <h2 className="font-script text-5xl mb-12 text-romantic-text">{currentSlide.title}</h2>
            <ul className="space-y-6 w-full max-w-md">
              {currentSlide.extra?.map((item, i) => (
                <li key={i} className="flex items-center gap-4 group">
                  <span className="w-8 h-8 flex items-center justify-center rounded-full bg-romantic-primary/20 text-romantic-accent group-hover:bg-romantic-accent group-hover:text-white transition-colors duration-300"><Heart size={14} className="fill-current" /></span>
                  <span className="font-serif text-xl text-romantic-text border-b border-transparent group-hover:border-romantic-primary transition-all">{item}</span>
                </li>
              ))}
            </ul>
          </div>
        );

      case SlideType.VIDEO:
        return (
          <div className="flex flex-col items-center justify-center h-full w-full animate-fade-in relative z-50 p-4">
             {currentSlide.title && <h2 className="font-serif text-2xl mb-4 text-romantic-text text-center">{currentSlide.title}</h2>}
             <div className="w-full max-w-sm aspect-[9/16] max-h-[70vh] rounded-2xl overflow-hidden shadow-2xl border-4 border-white/50 bg-black relative group">
               <iframe width="100%" height="100%" src={`https://www.youtube.com/embed/${currentSlide.videoId}?autoplay=1&playsinline=1&mute=1&rel=0&loop=1&playlist=${currentSlide.videoId}&controls=1&showinfo=0&modestbranding=1&iv_load_policy=3&fs=0`} title="YouTube video player" frameBorder="0" allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share" allowFullScreen className="w-full h-full object-cover"></iframe>
             </div>
             <div className="mt-4 flex items-center gap-2 text-romantic-text/60 animate-pulse bg-white/50 px-3 py-1 rounded-full"><VolumeX size={14} /><p className="font-sans text-xs">Otomatik başlamazsa veya ses gelmezse videoya dokunun.</p></div>
          </div>
        );

      case SlideType.FINAL:
        return (
          <div className="flex flex-col items-center justify-center h-full px-6 text-center animate-fade-in">
            <h1 className="font-script text-6xl mb-6 text-romantic-text">{currentSlide.title}</h1>
            <p className="font-serif text-xl text-romantic-secondary mb-12">{currentSlide.text}</p>
            <div className="relative cursor-pointer group" onClick={(e) => { e.stopPropagation(); setCurrentIndex(prev => prev + 1); }}>
              <Heart size={150} className="text-romantic-accent fill-current animate-pulse group-hover:scale-110 transition-transform duration-300" />
              <span className="absolute inset-0 flex items-center justify-center text-white font-bold font-sans text-sm tracking-wider animate-bounce">Buraya Bas</span>
            </div>
            <button onClick={restart} className="mt-20 text-xs font-sans uppercase tracking-widest text-romantic-secondary/50 hover:text-romantic-secondary transition-colors z-50 p-4 cursor-pointer">Başa Dön ↺</button>
          </div>
        );
      default: return null;
    }
  };

  return (
    <div onClick={handleInteraction} className="relative w-full h-[100dvh] bg-romantic-bg overflow-hidden cursor-pointer select-none">
      <div id="youtube-player" className="absolute top-0 left-0 opacity-1 pointer-events-none -z-50 h-[1px] w-[1px]" />
      <ProgressBar total={SLIDES.length} current={currentIndex} />
      <FloatingHearts />
      <div className="absolute top-[-20%] right-[-10%] w-[500px] h-[500px] bg-romantic-primary/20 rounded-full blur-[100px] pointer-events-none" />
      <div className="absolute bottom-[-10%] left-[-10%] w-[400px] h-[400px] bg-romantic-secondary/20 rounded-full blur-[80px] pointer-events-none" />
      <main className="relative z-10 w-full h-full max-w-lg mx-auto transition-all duration-700 ease-in-out">
        {renderContent()}
      </main>
      {currentIndex > 0 && (
        <div className="absolute bottom-12 md:bottom-8 w-full z-50 pointer-events-none px-8" style={{ paddingBottom: 'env(safe-area-inset-bottom)' }}>
          <div className="flex items-center justify-between text-romantic-text/40">
            <div className={`w-24 flex justify-start transition-opacity duration-300 ${currentIndex > 1 ? 'opacity-100 animate-pulse' : 'opacity-0'}`}><div className="flex items-center gap-1 font-sans text-[10px] uppercase tracking-widest"><ChevronLeft size={10} /> Geri</div></div>
            <div className="font-serif text-sm font-medium tracking-widest opacity-60">{currentIndex} / {SLIDES.length - 1}</div>
            <div className={`w-24 flex justify-end transition-opacity duration-300 ${currentIndex < SLIDES.length - 1 ? 'opacity-100 animate-pulse' : 'opacity-0'}`}><div className="flex items-center gap-1 font-sans text-[10px] uppercase tracking-widest">İleri <ChevronRight size={10} /></div></div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect, useCallback, useMemo } from 'react';
import { Play, Music, Heart, ChevronRight, ChevronLeft, Volume2, Lock, ArrowLeft, Phone, Video, MoreVertical, ChevronsDown, VolumeX } from 'lucide-react';
import { SLIDES, YOUTUBE_VIDEO_ID } from './constants';
import { SlideType } from './types';
import ProgressBar from './components/ProgressBar';
import FloatingHearts from './components/FloatingHearts';

// Helper to access window globals for YouTube API
declare global {
  interface Window {
    onYouTubeIframeAPIReady: () => void;
    YT: any;
  }
}

const App: React.FC = () => {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [isPlaying, setIsPlaying] = useState(false);
  const [password, setPassword] = useState('');
  const [error, setError] = useState(false);
  const playerRef = useRef<any>(null);

  // Countdown State
  const [timeLeft, setTimeLeft] = useState({
    days: 0,
    hours: 0,
    minutes: 0,
    seconds: 0
  });

  // Calculate Countdown
  useEffect(() => {
    const targetDate = new Date('2026-04-25T00:00:00').getTime();

    const interval = setInterval(() => {
      const now = new Date().getTime();
      const difference = targetDate - now;

      if (difference <= 0) {
        clearInterval(interval);
        setTimeLeft({ days: 0, hours: 0, minutes: 0, seconds: 0 });
      } else {
        setTimeLeft({
          days: Math.floor(difference / (1000 * 60 * 60 * 24)),
          hours: Math.floor((difference % (1000 * 60 * 60 * 24)) / (1000 * 60 * 60)),
          minutes: Math.floor((difference % (1000 * 60 * 60)) / (1000 * 60)),
          seconds: Math.floor((difference % (1000 * 60)) / 1000)
        });
      }
    }, 1000);

    return () => clearInterval(interval);
  }, []);

  // Generate static random hearts for Intro to avoid re-render flicker
  const introHearts = useMemo(() => {
    return Array.from({ length: 50 }).map((_, i) => ({
      id: i,
      left: Math.random() * 100, // Random horizontal position 0-100%
      delay: Math.random() * 20, // Spread start times
      duration: 8 + Math.random() * 12, // Faster floating (8s to 20s)
      size: 15 + Math.random() * 35, // Varied sizes (15px to 50px)
      color: Math.random() > 0.5 ? '#FF6B6B' : '#D4A5A5',
      opacity: 0.25 + Math.random() * 0.4 // Reduced opacity (0.25 - 0.65) for better text contrast
    }));
  }, []);

  // Initialize YouTube API
  useEffect(() => {
    if (!window.YT) {
      const tag = document.createElement('script');
      tag.src = "https://www.youtube.com/iframe_api";
      const firstScriptTag = document.getElementsByTagName('script')[0];
      firstScriptTag.parentNode?.insertBefore(tag, firstScriptTag);
    }

    window.onYouTubeIframeAPIReady = () => {
      playerRef.current = new window.YT.Player('youtube-player', {
        height: '1',
        width: '1',
        videoId: YOUTUBE_VIDEO_ID,
        playerVars: {
          'playsinline': 1,
          'controls': 0,
          'disablekb': 1,
          'fs': 0,
          'loop': 1,
          'playlist': YOUTUBE_VIDEO_ID
        },
        events: {
          'onReady': (event: any) => {
             event.target.setVolume(50);
          }
        }
      });
    };

    return () => {
      if (playerRef.current && playerRef.current.destroy) {
        playerRef.current.destroy();
      }
    };
  }, []);

  useEffect(() => {
    if (currentIndex === 0) return;
    const currentSlide = SLIDES[currentIndex];
    if (currentSlide.type === SlideType.VIDEO) {
        if (playerRef.current && playerRef.current.pauseVideo) {
            playerRef.current.pauseVideo();
            setIsPlaying(false);
        }
    } else {
        if (!isPlaying && playerRef.current && playerRef.current.playVideo) {
            playerRef.current.playVideo();
            setIsPlaying(true);
        }
    }
  }, [currentIndex]);

  const handleStart = (e: React.MouseEvent) => {
    e.stopPropagation();
    const cleanInput = password.toLowerCase().replace(/\s/g, '');
    if (cleanInput === 'seniseviyorum') {
      if (playerRef.current && playerRef.current.playVideo) {
        playerRef.current.playVideo();
        setIsPlaying(true);
      }
      setCurrentIndex(1);
      setError(false);
    } else {
      setError(true);
      setTimeout(() => setError(false), 500);
    }
  };

  const handleInteraction = useCallback((e: React.MouseEvent) => {
    if (currentIndex === 0) return;
    if (SLIDES[currentIndex].type !== SlideType.VIDEO && !isPlaying && playerRef.current && playerRef.current.playVideo) {
      playerRef.current.playVideo();
      setIsPlaying(true);
    }
    const { clientX } = e;
    const { innerWidth } = window;
    if (clientX > innerWidth / 2) {
      if (SLIDES[currentIndex].type === SlideType.FINAL) return;
      if (currentIndex < SLIDES.length - 1) setCurrentIndex((prev) => prev + 1);
    } else {
      if (currentIndex > 0) setCurrentIndex((prev) => prev - 1);
    }
  }, [currentIndex, isPlaying]);

  const restart = (e: React.MouseEvent) => {
    e.stopPropagation();
    setCurrentIndex(0);
    setPassword('');
    setIsPlaying(false);
    if (playerRef.current && playerRef.current.stopVideo) {
       playerRef.current.stopVideo();
    }
  };

  const renderContent = () => {
    const currentSlide = SLIDES[currentIndex];
    switch (currentSlide.type) {
      case SlideType.INTRO:
        return (
          <div className="flex flex-col items-center justify-center h-full text-center px-6 animate-fade-in relative overflow-hidden">
            {/* Flying Hearts Background */}
            <div className="absolute inset-0 overflow-hidden pointer-events-none z-0">
               {introHearts.map((heart) => (
                 <div
                   key={heart.id}
                   className="absolute -bottom-10"
                   style={{
                     left: `${heart.left}%`,
                     animation: `floatUp ${heart.duration}s linear infinite`,
                     animationDelay: `-${heart.delay}s`,
                     color: heart.color,
                     opacity: heart.opacity
                   }}
                 >
                   <Heart size={heart.size} fill="currentColor" />
                 </div>
               ))}
            </div>

            {/* Romantic Background Decoration for Intro */}
            <div className="absolute inset-0 z-0 flex items-center justify-center pointer-events-none">
               <div className="absolute w-[500px] h-[500px] bg-romantic-primary/20 rounded-full blur-[100px] animate-pulse-slow"></div>
               <Heart className="text-white/40 w-80 h-80 animate-pulse" fill="currentColor" strokeWidth={0} />
            </div>

            <div className="z-10 w-full flex flex-col items-center">
              {/* Volume Hint */}
              <div className="mb-6 animate-bounce">
                <div className="flex items-center gap-2 bg-white/80 backdrop-blur-md px-4 py-1.5 rounded-full border border-white/60 shadow-md text-romantic-secondary">
                  <Volume2 size={14} className="text-romantic-text" />
                  <span className="text-[10px] font-sans tracking-widest uppercase font-bold text-romantic-text">Sesi Açın</span>
                </div>
              </div>

              {/* Title Section */}
              <div className="mb-8">
                <h1 className="font-script text-6xl md:text-7xl text-romantic-text mb-2 drop-shadow-lg transform -rotate-2">
                  Şeyma <span className="text-romantic-accent text-4xl">&</span> Akif
                </h1>
                <div className="flex items-center justify-center gap-3 mt-4">
                   <div className="h-[2px] w-8 bg-romantic-text/40 rounded-full"></div>
                   <p className="font-serif text-lg md:text-xl text-romantic-text/90 font-bold tracking-[0.2em] uppercase drop-shadow-sm">En Güzel Günümüze</p>
                   <div className="h-[2px] w-8 bg-romantic-text/40 rounded-full"></div>
                </div>
              </div>

              {/* Countdown Section - High Contrast */}
              <div className="grid grid-cols-4 gap-3 mb-12 w-full max-w-sm">
                {[
                  { label: 'Gün', value: timeLeft.days },
                  { label: 'Saat', value: timeLeft.hours },
                  { label: 'Dakika', value: timeLeft.minutes },
                  { label: 'Saniye', value: timeLeft.seconds }
                ].map((item, idx) => (
                  <div key={idx} className="flex flex-col items-center p-3 bg-white/80 backdrop-blur-md rounded-2xl border-2 border-white/60 shadow-xl hover:bg-white/90 transition-colors">
                    <span className="font-serif text-2xl md:text-3xl font-black text-romantic-text tabular-nums leading-none mb-1 drop-shadow-sm">
                      {String(item.value).padStart(2, '0')}
                    </span>
                    <span className="font-sans text-[10px] uppercase tracking-wider text-romantic-text/80 font-bold">
                      {item.label}
                    </span>
                  </div>
                ))}
              </div>

              {/* Login Section */}
              <div className="w-full max-w-xs space-y-5">
                <div className={`transition-transform duration-200 ${error ? 'translate-x-[-10px]' : ''}`}>
                  <div className="relative group">
                    <input
                      type="text"
                      value={password}
                      onChange={(e) => {
                        setPassword(e.target.value);
                        setError(false);
                      }}
                      onClick={(e) => e.stopPropagation()}
                      placeholder="Sihirli sözcük..."
                      className={`w-full bg-white/90 backdrop-blur-md border-2 ${error ? 'border-red-300 text-red-600 placeholder:text-red-400' : 'border-white text-romantic-text'} rounded-2xl px-6 py-4 text-center outline-none focus:border-romantic-primary focus:ring-4 focus:ring-romantic-primary/20 transition-all font-serif text-xl placeholder:text-romantic-text/50 shadow-xl placeholder:italic font-semibold`}
                    />
                    {!password && <Heart size={16} className="absolute right-5 top-1/2 -translate-y-1/2 text-romantic-primary/60 animate-pulse" fill="currentColor" />}
                  </div>
                  {error && <p className="text-red-500 text-xs mt-2 font-sans font-bold text-center bg-white/60 py-1 px-2 rounded-lg inline-block w-full">İpucu: Birbirimize hep söylediğimiz o iki kelime...</p>}
                </div>

                <div className="flex justify-center">
                  <button 
                    onClick={handleStart}
                    className="group relative bg-gradient-to-r from-romantic-primary to-romantic-accent text-white px-12 py-4 rounded-full shadow-xl font-serif tracking-widest uppercase text-sm flex items-center gap-3 overflow-hidden transform transition-all hover:scale-105 active:scale-95 hover:shadow-2xl hover:brightness-110 border-2 border-white/20"
                  >
                    <div className="absolute inset-0 bg-white/20 translate-y-full group-hover:translate-y-0 transition-transform duration-300"></div>
                    <span className="relative flex items-center gap-2 font-bold text-shadow-sm">
                      <Play size={16} className="fill-current" /> Hikayemiz Başlasın
                    </span>
                  </button>
                </div>
              </div>
            </div>
          </div>
        );

      case SlideType.WHATSAPP:
        return (
          <div className="flex flex-col h-full items-center justify-start pt-16 px-4 animate-fade-in relative z-20">
            <div className="w-full max-w-[320px] h-[55vh] md:h-[68vh] bg-[#E5DDD5] rounded-2xl shadow-2xl overflow-hidden flex flex-col relative border border-gray-300 ring-4 ring-black/5 mx-auto transition-all duration-300">
              <div className="bg-[#075E54] text-white p-2 px-3 flex items-center shadow-md z-10 shrink-0">
                <ArrowLeft size={18} className="mr-1" />
                <div className="w-8 h-8 bg-gray-300 rounded-full mr-2 flex items-center justify-center text-gray-500 overflow-hidden shrink-0">
                  <div className="bg-gray-400 w-full h-full flex items-center justify-center text-xs font-bold">A</div>
                </div>
                <div className="flex-1 overflow-hidden">
                  <h3 className="font-semibold text-sm leading-tight truncate">{currentSlide.title}</h3>
                  <p className="text-[10px] opacity-80 truncate">Çevrimiçi</p>
                </div>
                <div className="flex gap-3 ml-2">
                  <Video size={16} />
                  <Phone size={16} />
                  <MoreVertical size={16} />
                </div>
              </div>
              <div className="flex-1 p-3 bg-[#E5DDD5] relative overflow-y-auto scrollbar-hide">
                  <div className="absolute inset-0 opacity-10 bg-[url('https://user-images.githubusercontent.com/15075759/28719144-86dc0f70-73b1-11e7-911d-60d70fcded21.png')] pointer-events-none"></div>
                  <div className="flex justify-center mb-4 relative z-10">
                    <span className="bg-[#D4EAF4] text-gray-600 text-[10px] font-medium px-2 py-0.5 rounded-lg shadow-sm">{currentSlide.date}</span>
                  </div>
                  <div className="space-y-2 relative z-10 pb-4">
                    {currentSlide.messages?.map((msg, idx) => (
                      <div key={idx} className={`flex ${msg.isSender ? 'justify-end' : 'justify-start'}`}>
                        <div className={`max-w-[85%] p-1.5 px-2.5 rounded-lg shadow-sm text-xs relative ${msg.isSender ? 'bg-[#E2FFC7] rounded-tr-none' : 'bg-white rounded-tl-none'}`}>
                          <p className="text-[#303030] leading-snug pb-1 whitespace-pre-wrap">{msg.text}</p>
                          <div className="text-right"><span className="text-[9px] text-gray-500">{msg.time}</span></div>
                        </div>
                      </div>
                    ))}
                  </div>
              </div>
            </div>
            <p className="mt-2 text-xs text-romantic-text/60 font-sans italic animate-pulse">(Mesajı aşağı kaydırabilirsin.)</p>
            {currentSlide.footerText && (
              <div className="mt-4 md:mt-6 text-center max-w-xs animate-fade-in" style={{ animationDelay: '0.5s' }}>
                  <p className="font-serif text-xl md:text-2xl text-romantic-text italic font-medium leading-relaxed drop-shadow-sm px-2">{currentSlide.footerText}</p>
              </div>
            )}
          </div>
        );

      case SlideType.MEMORY:
        return (
          <div className={`flex flex-col items-center justify-center h-full px-6 pb-20 animate-fade-in ${currentSlide.textAlign === 'text-left' ? 'items-start' : ''}`}>
            <div className={`relative p-3 bg-white shadow-2xl mb-4 ${currentSlide.containerClass || 'w-full max-w-sm'} ${currentSlide.imageRotate || 'rotate-2'}`}>
              <div className={`${currentSlide.aspectRatio === 'aspect-auto' ? '' : (currentSlide.aspectRatio || 'aspect-[3/4]')} ${currentSlide.aspectRatio === 'aspect-auto' ? '' : 'overflow-hidden'} bg-gray-200`}>
                <img src={currentSlide.image} alt={currentSlide.title} className={`w-full ${currentSlide.aspectRatio === 'aspect-auto' ? 'h-auto' : 'h-full object-cover'}`} />
              </div>
              <div className="absolute -bottom-10 right-0 font-script text-4xl text-romantic-secondary/50 opacity-50 z-[-1]">{currentSlide.watermark || 'Anılar'}</div>
            </div>
            {currentSlide.secondImage && (
              <div className={`relative p-3 bg-white shadow-2xl mb-8 w-full max-w-sm ${currentSlide.imageRotate ? '-'+currentSlide.imageRotate : '-rotate-2'}`}>
                <div className={`${currentSlide.aspectRatio || 'aspect-[3/4]'} overflow-hidden bg-gray-200`}>
                  <img src={currentSlide.secondImage} alt={currentSlide.title} className="w-full h-full object-cover" />
                </div>
              </div>
            )}
            <div className={`w-full max-w-sm ${currentSlide.textAlign || 'text-center'}`}>
              <h2 className="font-serif text-3xl mb-4 text-romantic-text">{currentSlide.title}</h2>
              <p className="font-sans text-lg leading-relaxed text-romantic-text/80 whitespace-pre-line">{currentSlide.text}</p>
              {currentSlide.author && <p className="mt-2 text-sm text-romantic-secondary italic text-right font-serif">— {currentSlide.author}</p>}
            </div>
          </div>
        );

      case SlideType.COLLAGE:
        let layoutClass = "grid grid-cols-2 gap-3";
        if (currentSlide.collageLayout === 'row') layoutClass = "flex flex-row gap-2 h-64 justify-center items-center";
        else if (currentSlide.collageLayout === 'col') layoutClass = "flex flex-col gap-4 w-full mx-auto";
        return (
          <div className="flex flex-col items-center justify-center h-full px-6 animate-fade-in">
             <h2 className="font-serif text-3xl mb-6 text-romantic-text text-center">{currentSlide.title}</h2>
             <div className={`w-full max-w-md bg-white p-3 shadow-xl transform rotate-1 ${layoutClass}`}>
                {currentSlide.collageImages?.map((img, idx) => (
                  <div key={idx} className={`bg-gray-100 rounded-sm ${currentSlide.collageLayout === 'row' ? 'flex-1 h-full overflow-hidden' : currentSlide.collageLayout === 'col' ? 'w-full' : 'aspect-square overflow-hidden'}`}>
                    <img src={img} alt={`Collage ${idx}`} className={`w-full hover:scale-110 transition-transform duration-500 ${currentSlide.collageLayout === 'col' ? 'h-auto' : 'h-full object-cover'}`} />
                  </div>
                ))}
             </div>
             {currentSlide.text && <div className="mt-12 text-center"><p className="font-script text-3xl text-romantic-text whitespace-pre-line leading-relaxed">{currentSlide.text}</p></div>}
          </div>
        );

      case SlideType.MESSAGE:
        return (
          <div className="flex flex-col items-center justify-center h-full px-8 text-center animate-fade-in relative">
            <div className="font-serif text-6xl text-romantic-primary opacity-20 absolute top-[20%] left-4">"</div>
            <h2 className="font-serif text-3xl md:text-4xl leading-relaxed text-romantic-text italic relative z-10">{currentSlide.text}</h2>
            <div className="font-serif text-6xl text-romantic-primary opacity-20 absolute bottom-[20%] right-4">"</div>
            <div className="mt-8"><Heart className="text-romantic-accent fill-current animate-pulse-slow" size={32} /></div>
          </div>
        );

      case SlideType.MUSIC:
        return (
          <div className="flex flex-col items-center justify-center h-full px-6 animate-fade-in">
             <div className="w-48 h-48 bg-gradient-to-br from-romantic-primary to-romantic-secondary rounded-full shadow-2xl flex items-center justify-center mb-10 animate-spin" style={{ animationDuration: '10s' }}><Music size={64} className="text-white" /></div>
             <div className="text-center mb-8">
                <h3 className="font-serif text-2xl font-bold text-romantic-text mb-1">{currentSlide.title}</h3>
                <p className="font-sans text-sm text-romantic-secondary uppercase tracking-widest">{currentSlide.text}</p>
             </div>
             <div className="space-y-2 text-center">
               {currentSlide.extra?.map((line, i) => <p key={i} className="font-serif text-xl italic text-romantic-text/70">{line}</p>)}
             </div>
          </div>
        );

      case SlideType.DREAMS:
        return (
          <div className="flex flex-col items-center justify-center h-full px-8 animate-fade-in">
            <h2 className="font-script text-5xl mb-12 text-romantic-text">{currentSlide.title}</h2>
            <ul className="space-y-6 w-full max-w-md">
              {currentSlide.extra?.map((item, i) => (
                <li key={i} className="flex items-center gap-4 group">
                  <span className="w-8 h-8 flex items-center justify-center rounded-full bg-romantic-primary/20 text-romantic-accent group-hover:bg-romantic-accent group-hover:text-white transition-colors duration-300"><Heart size={14} className="fill-current" /></span>
                  <span className="font-serif text-xl text-romantic-text border-b border-transparent group-hover:border-romantic-primary transition-all">{item}</span>
                </li>
              ))}
            </ul>
          </div>
        );

      case SlideType.VIDEO:
        return (
          <div className="flex flex-col items-center justify-center h-full w-full animate-fade-in relative z-50 p-4">
             {currentSlide.title && <h2 className="font-serif text-2xl mb-4 text-romantic-text text-center">{currentSlide.title}</h2>}
             <div className="w-full max-w-sm aspect-[9/16] max-h-[70vh] rounded-2xl overflow-hidden shadow-2xl border-4 border-white/50 bg-black relative group">
               <iframe width="100%" height="100%" src={`https://www.youtube.com/embed/${currentSlide.videoId}?autoplay=1&playsinline=1&mute=1&rel=0&loop=1&playlist=${currentSlide.videoId}&controls=1&showinfo=0&modestbranding=1&iv_load_policy=3&fs=0`} title="YouTube video player" frameBorder="0" allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share" allowFullScreen className="w-full h-full object-cover"></iframe>
             </div>
             <div className="mt-4 flex items-center gap-2 text-romantic-text/60 animate-pulse bg-white/50 px-3 py-1 rounded-full"><VolumeX size={14} /><p className="font-sans text-xs">Otomatik başlamazsa veya ses gelmezse videoya dokunun.</p></div>
          </div>
        );

      case SlideType.FINAL:
        return (
          <div className="flex flex-col items-center justify-center h-full px-6 text-center animate-fade-in">
            <h1 className="font-script text-6xl mb-6 text-romantic-text">{currentSlide.title}</h1>
            <p className="font-serif text-xl text-romantic-secondary mb-12">{currentSlide.text}</p>
            <div className="relative cursor-pointer group" onClick={(e) => { e.stopPropagation(); setCurrentIndex(prev => prev + 1); }}>
              <Heart size={150} className="text-romantic-accent fill-current animate-pulse group-hover:scale-110 transition-transform duration-300" />
              <span className="absolute inset-0 flex items-center justify-center text-white font-bold font-sans text-sm tracking-wider animate-bounce">Buraya Bas</span>
            </div>
            <button onClick={restart} className="mt-20 text-xs font-sans uppercase tracking-widest text-romantic-secondary/50 hover:text-romantic-secondary transition-colors z-50 p-4 cursor-pointer">Başa Dön ↺</button>
          </div>
        );
      default: return null;
    }
  };

  return (
    <div onClick={handleInteraction} className="relative w-full h-[100dvh] bg-romantic-bg overflow-hidden cursor-pointer select-none">
      <div id="youtube-player" className="absolute top-0 left-0 opacity-1 pointer-events-none -z-50 h-[1px] w-[1px]" />
      <ProgressBar total={SLIDES.length} current={currentIndex} />
      <FloatingHearts />
      <div className="absolute top-[-20%] right-[-10%] w-[500px] h-[500px] bg-romantic-primary/20 rounded-full blur-[100px] pointer-events-none" />
      <div className="absolute bottom-[-10%] left-[-10%] w-[400px] h-[400px] bg-romantic-secondary/20 rounded-full blur-[80px] pointer-events-none" />
      <main className="relative z-10 w-full h-full max-w-lg mx-auto transition-all duration-700 ease-in-out">
        {renderContent()}
      </main>
      {currentIndex > 0 && (
        <div className="absolute bottom-12 md:bottom-8 w-full z-50 pointer-events-none px-8" style={{ paddingBottom: 'env(safe-area-inset-bottom)' }}>
          <div className="flex items-center justify-between text-romantic-text/40">
            <div className={`w-24 flex justify-start transition-opacity duration-300 ${currentIndex > 1 ? 'opacity-100 animate-pulse' : 'opacity-0'}`}><div className="flex items-center gap-1 font-sans text-[10px] uppercase tracking-widest"><ChevronLeft size={10} /> Geri</div></div>
            <div className="font-serif text-sm font-medium tracking-widest opacity-60">{currentIndex} / {SLIDES.length - 1}</div>
            <div className={`w-24 flex justify-end transition-opacity duration-300 ${currentIndex < SLIDES.length - 1 ? 'opacity-100 animate-pulse' : 'opacity-0'}`}><div className="flex items-center gap-1 font-sans text-[10px] uppercase tracking-widest">İleri <ChevronRight size={10} /></div></div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect, useCallback, useMemo } from 'react';
import { Play, Music, Heart, ChevronRight, ChevronLeft, Volume2, Lock, ArrowLeft, Phone, Video, MoreVertical, ChevronsDown, VolumeX } from 'lucide-react';
import { SLIDES, YOUTUBE_VIDEO_ID } from './constants';
import { SlideType } from './types';
import ProgressBar from './components/ProgressBar';
import FloatingHearts from './components/FloatingHearts';

// Helper to access window globals for YouTube API
declare global {
  interface Window {
    onYouTubeIframeAPIReady: () => void;
    YT: any;
  }
}

const App: React.FC = () => {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [isPlaying, setIsPlaying] = useState(false);
  const [password, setPassword] = useState('');
  const [error, setError] = useState(false);
  const playerRef = useRef<any>(null);

  // Countdown State
  const [timeLeft, setTimeLeft] = useState({
    days: 0,
    hours: 0,
    minutes: 0,
    seconds: 0
  });

  // Calculate Countdown
  useEffect(() => {
    const targetDate = new Date('2026-04-25T00:00:00').getTime();

    const interval = setInterval(() => {
      const now = new Date().getTime();
      const difference = targetDate - now;

      if (difference <= 0) {
        clearInterval(interval);
        setTimeLeft({ days: 0, hours: 0, minutes: 0, seconds: 0 });
      } else {
        setTimeLeft({
          days: Math.floor(difference / (1000 * 60 * 60 * 24)),
          hours: Math.floor((difference % (1000 * 60 * 60 * 24)) / (1000 * 60 * 60)),
          minutes: Math.floor((difference % (1000 * 60 * 60)) / (1000 * 60)),
          seconds: Math.floor((difference % (1000 * 60)) / 1000)
        });
      }
    }, 1000);

    return () => clearInterval(interval);
  }, []);

  // Generate static random hearts for Intro to avoid re-render flicker
  const introHearts = useMemo(() => {
    return Array.from({ length: 50 }).map((_, i) => ({
      id: i,
      left: Math.random() * 100, // Random horizontal position 0-100%
      delay: Math.random() * 20, // Spread start times
      duration: 8 + Math.random() * 12, // Faster floating (8s to 20s)
      size: 15 + Math.random() * 35, // Varied sizes (15px to 50px)
      color: Math.random() > 0.5 ? '#FF6B6B' : '#D4A5A5',
      opacity: 0.1 + Math.random() * 0.3 // Significantly reduced opacity (0.1 - 0.4) for better text contrast
    }));
  }, []);

  // Initialize YouTube API
  useEffect(() => {
    if (!window.YT) {
      const tag = document.createElement('script');
      tag.src = "https://www.youtube.com/iframe_api";
      const firstScriptTag = document.getElementsByTagName('script')[0];
      firstScriptTag.parentNode?.insertBefore(tag, firstScriptTag);
    }

    window.onYouTubeIframeAPIReady = () => {
      playerRef.current = new window.YT.Player('youtube-player', {
        height: '1',
        width: '1',
        videoId: YOUTUBE_VIDEO_ID,
        playerVars: {
          'playsinline': 1,
          'controls': 0,
          'disablekb': 1,
          'fs': 0,
          'loop': 1,
          'playlist': YOUTUBE_VIDEO_ID
        },
        events: {
          'onReady': (event: any) => {
             event.target.setVolume(50);
          }
        }
      });
    };

    return () => {
      if (playerRef.current && playerRef.current.destroy) {
        playerRef.current.destroy();
      }
    };
  }, []);

  useEffect(() => {
    if (currentIndex === 0) return;
    const currentSlide = SLIDES[currentIndex];
    if (currentSlide.type === SlideType.VIDEO) {
        if (playerRef.current && playerRef.current.pauseVideo) {
            playerRef.current.pauseVideo();
            setIsPlaying(false);
        }
    } else {
        if (!isPlaying && playerRef.current && playerRef.current.playVideo) {
            playerRef.current.playVideo();
            setIsPlaying(true);
        }
    }
  }, [currentIndex]);

  const handleStart = (e: React.MouseEvent) => {
    e.stopPropagation();
    const cleanInput = password.toLowerCase().replace(/\s/g, '');
    if (cleanInput === 'seniseviyorum') {
      if (playerRef.current && playerRef.current.playVideo) {
        playerRef.current.playVideo();
        setIsPlaying(true);
      }
      setCurrentIndex(1);
      setError(false);
    } else {
      setError(true);
      setTimeout(() => setError(false), 500);
    }
  };

  const handleInteraction = useCallback((e: React.MouseEvent) => {
    if (currentIndex === 0) return;
    if (SLIDES[currentIndex].type !== SlideType.VIDEO && !isPlaying && playerRef.current && playerRef.current.playVideo) {
      playerRef.current.playVideo();
      setIsPlaying(true);
    }
    const { clientX } = e;
    const { innerWidth } = window;
    if (clientX > innerWidth / 2) {
      if (SLIDES[currentIndex].type === SlideType.FINAL) return;
      if (currentIndex < SLIDES.length - 1) setCurrentIndex((prev) => prev + 1);
    } else {
      if (currentIndex > 0) setCurrentIndex((prev) => prev - 1);
    }
  }, [currentIndex, isPlaying]);

  const restart = (e: React.MouseEvent) => {
    e.stopPropagation();
    setCurrentIndex(0);
    setPassword('');
    setIsPlaying(false);
    if (playerRef.current && playerRef.current.stopVideo) {
       playerRef.current.stopVideo();
    }
  };

  const renderContent = () => {
    const currentSlide = SLIDES[currentIndex];
    switch (currentSlide.type) {
      case SlideType.INTRO:
        return (
          <div className="flex flex-col items-center justify-center h-full text-center px-6 animate-fade-in relative overflow-hidden">
            {/* Flying Hearts Background */}
            <div className="absolute inset-0 overflow-hidden pointer-events-none z-0">
               {introHearts.map((heart) => (
                 <div
                   key={heart.id}
                   className="absolute -bottom-10"
                   style={{
                     left: `${heart.left}%`,
                     animation: `floatUp ${heart.duration}s linear infinite`,
                     animationDelay: `-${heart.delay}s`,
                     color: heart.color,
                     opacity: heart.opacity
                   }}
                 >
                   <Heart size={heart.size} fill="currentColor" />
                 </div>
               ))}
            </div>

            {/* Romantic Background Decoration for Intro */}
            <div className="absolute inset-0 z-0 flex items-center justify-center pointer-events-none">
               <div className="absolute w-[500px] h-[500px] bg-romantic-primary/20 rounded-full blur-[100px] animate-pulse-slow"></div>
               <Heart className="text-white/40 w-80 h-80 animate-pulse" fill="currentColor" strokeWidth={0} />
            </div>

            <div className="z-10 w-full flex flex-col items-center">
              {/* Volume Hint */}
              <div className="mb-6 animate-bounce">
                <div className="flex items-center gap-2 bg-white/80 backdrop-blur-md px-4 py-1.5 rounded-full border border-white/60 shadow-md text-romantic-secondary">
                  <Volume2 size={14} className="text-romantic-text" />
                  <span className="text-[10px] font-sans tracking-widest uppercase font-bold text-romantic-text">Sesi Açın</span>
                </div>
              </div>

              {/* Title Section */}
              <div className="mb-8">
                <h1 className="font-script text-6xl md:text-7xl text-romantic-text mb-2 drop-shadow-lg transform -rotate-2">
                  Şeyma <span className="text-romantic-accent text-4xl">&</span> Akif
                </h1>
                <div className="flex items-center justify-center gap-3 mt-4">
                   <div className="h-[2px] w-8 bg-romantic-text/40 rounded-full"></div>
                   <p className="font-serif text-lg md:text-xl text-romantic-text/90 font-bold tracking-[0.2em] uppercase drop-shadow-sm">En Güzel Günümüze</p>
                   <div className="h-[2px] w-8 bg-romantic-text/40 rounded-full"></div>
                </div>
              </div>

              {/* Countdown Section - High Contrast */}
              <div className="grid grid-cols-4 gap-3 mb-12 w-full max-w-sm">
                {[
                  { label: 'Gün', value: timeLeft.days },
                  { label: 'Saat', value: timeLeft.hours },
                  { label: 'Dakika', value: timeLeft.minutes },
                  { label: 'Saniye', value: timeLeft.seconds }
                ].map((item, idx) => (
                  <div key={idx} className="flex flex-col items-center p-3 bg-white/80 backdrop-blur-md rounded-2xl border-2 border-white/60 shadow-xl hover:bg-white/90 transition-colors">
                    <span className="font-serif text-2xl md:text-3xl font-black text-romantic-text tabular-nums leading-none mb-1 drop-shadow-sm">
                      {String(item.value).padStart(2, '0')}
                    </span>
                    <span className="font-sans text-[10px] uppercase tracking-wider text-romantic-text/80 font-bold">
                      {item.label}
                    </span>
                  </div>
                ))}
              </div>

              {/* Login Section */}
              <div className="w-full max-w-xs space-y-5">
                <div className={`transition-transform duration-200 ${error ? 'translate-x-[-10px]' : ''}`}>
                  <div className="relative group">
                    <input
                      type="text"
                      value={password}
                      onChange={(e) => {
                        setPassword(e.target.value);
                        setError(false);
                      }}
                      onClick={(e) => e.stopPropagation()}
                      placeholder="Sihirli sözcük..."
                      className={`w-full bg-white/90 backdrop-blur-md border-2 ${error ? 'border-red-300 text-red-600 placeholder:text-red-400' : 'border-white text-romantic-text'} rounded-2xl px-6 py-4 text-center outline-none focus:border-romantic-primary focus:ring-4 focus:ring-romantic-primary/20 transition-all font-serif text-xl placeholder:text-romantic-text/50 shadow-xl placeholder:italic font-semibold`}
                    />
                    {!password && <Heart size={16} className="absolute right-5 top-1/2 -translate-y-1/2 text-romantic-primary/60 animate-pulse" fill="currentColor" />}
                  </div>
                  {error && <p className="text-red-500 text-xs mt-2 font-sans font-bold text-center bg-white/60 py-1 px-2 rounded-lg inline-block w-full">İpucu: Birbirimize hep söylediğimiz o iki kelime...</p>}
                </div>

                <div className="flex justify-center">
                  <button 
                    onClick={handleStart}
                    className="group relative bg-gradient-to-r from-romantic-primary to-romantic-accent text-white px-12 py-4 rounded-full shadow-xl font-serif tracking-widest uppercase text-sm flex items-center gap-3 overflow-hidden transform transition-all hover:scale-105 active:scale-95 hover:shadow-2xl hover:brightness-110 border-2 border-white/20"
                  >
                    <div className="absolute inset-0 bg-white/20 translate-y-full group-hover:translate-y-0 transition-transform duration-300"></div>
                    <span className="relative flex items-center gap-2 font-bold text-shadow-sm">
                      <Play size={16} className="fill-current" /> Hikayemiz Başlasın
                    </span>
                  </button>
                </div>
              </div>
            </div>
          </div>
        );

      case SlideType.WHATSAPP:
        return (
          <div className="flex flex-col h-full items-center justify-start pt-16 px-4 animate-fade-in relative z-20">
            <div className="w-full max-w-[320px] h-[55vh] md:h-[68vh] bg-[#E5DDD5] rounded-2xl shadow-2xl overflow-hidden flex flex-col relative border border-gray-300 ring-4 ring-black/5 mx-auto transition-all duration-300">
              <div className="bg-[#075E54] text-white p-2 px-3 flex items-center shadow-md z-10 shrink-0">
                <ArrowLeft size={18} className="mr-1" />
                <div className="w-8 h-8 bg-gray-300 rounded-full mr-2 flex items-center justify-center text-gray-500 overflow-hidden shrink-0">
                  <div className="bg-gray-400 w-full h-full flex items-center justify-center text-xs font-bold">A</div>
                </div>
                <div className="flex-1 overflow-hidden">
                  <h3 className="font-semibold text-sm leading-tight truncate">{currentSlide.title}</h3>
                  <p className="text-[10px] opacity-80 truncate">Çevrimiçi</p>
                </div>
                <div className="flex gap-3 ml-2">
                  <Video size={16} />
                  <Phone size={16} />
                  <MoreVertical size={16} />
                </div>
              </div>
              <div className="flex-1 p-3 bg-[#E5DDD5] relative overflow-y-auto scrollbar-hide">
                  <div className="absolute inset-0 opacity-10 bg-[url('https://user-images.githubusercontent.com/15075759/28719144-86dc0f70-73b1-11e7-911d-60d70fcded21.png')] pointer-events-none"></div>
                  <div className="flex justify-center mb-4 relative z-10">
                    <span className="bg-[#D4EAF4] text-gray-600 text-[10px] font-medium px-2 py-0.5 rounded-lg shadow-sm">{currentSlide.date}</span>
                  </div>
                  <div className="space-y-2 relative z-10 pb-4">
                    {currentSlide.messages?.map((msg, idx) => (
                      <div key={idx} className={`flex ${msg.isSender ? 'justify-end' : 'justify-start'}`}>
                        <div className={`max-w-[85%] p-1.5 px-2.5 rounded-lg shadow-sm text-xs relative ${msg.isSender ? 'bg-[#E2FFC7] rounded-tr-none' : 'bg-white rounded-tl-none'}`}>
                          <p className="text-[#303030] leading-snug pb-1 whitespace-pre-wrap">{msg.text}</p>
                          <div className="text-right"><span className="text-[9px] text-gray-500">{msg.time}</span></div>
                        </div>
                      </div>
                    ))}
                  </div>
              </div>
            </div>
            <p className="mt-2 text-xs text-romantic-text/60 font-sans italic animate-pulse">(Mesajı aşağı kaydırabilirsin.)</p>
            {currentSlide.footerText && (
              <div className="mt-4 md:mt-6 text-center max-w-xs animate-fade-in" style={{ animationDelay: '0.5s' }}>
                  <p className="font-serif text-xl md:text-2xl text-romantic-text italic font-medium leading-relaxed drop-shadow-sm px-2">{currentSlide.footerText}</p>
              </div>
            )}
          </div>
        );

      case SlideType.MEMORY:
        return (
          <div className={`flex flex-col items-center justify-center h-full px-6 pb-20 animate-fade-in ${currentSlide.textAlign === 'text-left' ? 'items-start' : ''}`}>
            <div className={`relative p-3 bg-white shadow-2xl mb-4 ${currentSlide.containerClass || 'w-full max-w-sm'} ${currentSlide.imageRotate || 'rotate-2'}`}>
              <div className={`${currentSlide.aspectRatio === 'aspect-auto' ? '' : (currentSlide.aspectRatio || 'aspect-[3/4]')} ${currentSlide.aspectRatio === 'aspect-auto' ? '' : 'overflow-hidden'} bg-gray-200`}>
                <img src={currentSlide.image} alt={currentSlide.title} className={`w-full ${currentSlide.aspectRatio === 'aspect-auto' ? 'h-auto' : 'h-full object-cover'}`} />
              </div>
              <div className="absolute -bottom-10 right-0 font-script text-4xl text-romantic-secondary/50 opacity-50 z-[-1]">{currentSlide.watermark || 'Anılar'}</div>
            </div>
            {currentSlide.secondImage && (
              <div className={`relative p-3 bg-white shadow-2xl mb-8 w-full max-w-sm ${currentSlide.imageRotate ? '-'+currentSlide.imageRotate : '-rotate-2'}`}>
                <div className={`${currentSlide.aspectRatio || 'aspect-[3/4]'} overflow-hidden bg-gray-200`}>
                  <img src={currentSlide.secondImage} alt={currentSlide.title} className="w-full h-full object-cover" />
                </div>
              </div>
            )}
            <div className={`w-full max-w-sm ${currentSlide.textAlign || 'text-center'}`}>
              <h2 className="font-serif text-3xl mb-4 text-romantic-text">{currentSlide.title}</h2>
              <p className="font-sans text-lg leading-relaxed text-romantic-text/80 whitespace-pre-line">{currentSlide.text}</p>
              {currentSlide.author && <p className="mt-2 text-sm text-romantic-secondary italic text-right font-serif">— {currentSlide.author}</p>}
            </div>
          </div>
        );

      case SlideType.COLLAGE:
        let layoutClass = "grid grid-cols-2 gap-3";
        if (currentSlide.collageLayout === 'row') layoutClass = "flex flex-row gap-2 h-64 justify-center items-center";
        else if (currentSlide.collageLayout === 'col') layoutClass = "flex flex-col gap-4 w-full mx-auto";
        return (
          <div className="flex flex-col items-center justify-center h-full px-6 animate-fade-in">
             <h2 className="font-serif text-3xl mb-6 text-romantic-text text-center">{currentSlide.title}</h2>
             <div className={`w-full max-w-md bg-white p-3 shadow-xl transform rotate-1 ${layoutClass}`}>
                {currentSlide.collageImages?.map((img, idx) => (
                  <div key={idx} className={`bg-gray-100 rounded-sm ${currentSlide.collageLayout === 'row' ? 'flex-1 h-full overflow-hidden' : currentSlide.collageLayout === 'col' ? 'w-full' : 'aspect-square overflow-hidden'}`}>
                    <img src={img} alt={`Collage ${idx}`} className={`w-full hover:scale-110 transition-transform duration-500 ${currentSlide.collageLayout === 'col' ? 'h-auto' : 'h-full object-cover'}`} />
                  </div>
                ))}
             </div>
             {currentSlide.text && <div className="mt-12 text-center"><p className="font-script text-3xl text-romantic-text whitespace-pre-line leading-relaxed">{currentSlide.text}</p></div>}
          </div>
        );

      case SlideType.MESSAGE:
        return (
          <div className="flex flex-col items-center justify-center h-full px-8 text-center animate-fade-in relative">
            <div className="font-serif text-6xl text-romantic-primary opacity-20 absolute top-[20%] left-4">"</div>
            <h2 className="font-serif text-3xl md:text-4xl leading-relaxed text-romantic-text italic relative z-10">{currentSlide.text}</h2>
            <div className="font-serif text-6xl text-romantic-primary opacity-20 absolute bottom-[20%] right-4">"</div>
            <div className="mt-8"><Heart className="text-romantic-accent fill-current animate-pulse-slow" size={32} /></div>
          </div>
        );

      case SlideType.MUSIC:
        return (
          <div className="flex flex-col items-center justify-center h-full px-6 animate-fade-in">
             <div className="w-48 h-48 bg-gradient-to-br from-romantic-primary to-romantic-secondary rounded-full shadow-2xl flex items-center justify-center mb-10 animate-spin" style={{ animationDuration: '10s' }}><Music size={64} className="text-white" /></div>
             <div className="text-center mb-8">
                <h3 className="font-serif text-2xl font-bold text-romantic-text mb-1">{currentSlide.title}</h3>
                <p className="font-sans text-sm text-romantic-secondary uppercase tracking-widest">{currentSlide.text}</p>
             </div>
             <div className="space-y-2 text-center">
               {currentSlide.extra?.map((line, i) => <p key={i} className="font-serif text-xl italic text-romantic-text/70">{line}</p>)}
             </div>
          </div>
        );

      case SlideType.DREAMS:
        return (
          <div className="flex flex-col items-center justify-center h-full px-8 animate-fade-in">
            <h2 className="font-script text-5xl mb-12 text-romantic-text">{currentSlide.title}</h2>
            <ul className="space-y-6 w-full max-w-md">
              {currentSlide.extra?.map((item, i) => (
                <li key={i} className="flex items-center gap-4 group">
                  <span className="w-8 h-8 flex items-center justify-center rounded-full bg-romantic-primary/20 text-romantic-accent group-hover:bg-romantic-accent group-hover:text-white transition-colors duration-300"><Heart size={14} className="fill-current" /></span>
                  <span className="font-serif text-xl text-romantic-text border-b border-transparent group-hover:border-romantic-primary transition-all">{item}</span>
                </li>
              ))}
            </ul>
          </div>
        );

      case SlideType.VIDEO:
        return (
          <div className="flex flex-col items-center justify-center h-full w-full animate-fade-in relative z-50 p-4">
             {currentSlide.title && <h2 className="font-serif text-2xl mb-4 text-romantic-text text-center">{currentSlide.title}</h2>}
             <div className="w-full max-w-sm aspect-[9/16] max-h-[70vh] rounded-2xl overflow-hidden shadow-2xl border-4 border-white/50 bg-black relative group">
               <iframe width="100%" height="100%" src={`https://www.youtube.com/embed/${currentSlide.videoId}?autoplay=1&playsinline=1&mute=1&rel=0&loop=1&playlist=${currentSlide.videoId}&controls=1&showinfo=0&modestbranding=1&iv_load_policy=3&fs=0`} title="YouTube video player" frameBorder="0" allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share" allowFullScreen className="w-full h-full object-cover"></iframe>
             </div>
             <div className="mt-4 flex items-center gap-2 text-romantic-text/60 animate-pulse bg-white/50 px-3 py-1 rounded-full"><VolumeX size={14} /><p className="font-sans text-xs">Otomatik başlamazsa veya ses gelmezse videoya dokunun.</p></div>
          </div>
        );

      case SlideType.FINAL:
        return (
          <div className="flex flex-col items-center justify-center h-full px-6 text-center animate-fade-in">
            <h1 className="font-script text-6xl mb-6 text-romantic-text">{currentSlide.title}</h1>
            <p className="font-serif text-xl text-romantic-secondary mb-12">{currentSlide.text}</p>
            <div className="relative cursor-pointer group" onClick={(e) => { e.stopPropagation(); setCurrentIndex(prev => prev + 1); }}>
              <Heart size={150} className="text-romantic-accent fill-current animate-pulse group-hover:scale-110 transition-transform duration-300" />
              <span className="absolute inset-0 flex items-center justify-center text-white font-bold font-sans text-sm tracking-wider animate-bounce">Buraya Bas</span>
            </div>
            <button onClick={restart} className="mt-20 text-xs font-sans uppercase tracking-widest text-romantic-secondary/50 hover:text-romantic-secondary transition-colors z-50 p-4 cursor-pointer">Başa Dön ↺</button>
          </div>
        );
      default: return null;
    }
  };

  return (
    <div onClick={handleInteraction} className="relative w-full h-[100dvh] bg-romantic-bg overflow-hidden cursor-pointer select-none">
      <div id="youtube-player" className="absolute top-0 left-0 opacity-1 pointer-events-none -z-50 h-[1px] w-[1px]" />
      <ProgressBar total={SLIDES.length} current={currentIndex} />
      <FloatingHearts />
      <div className="absolute top-[-20%] right-[-10%] w-[500px] h-[500px] bg-romantic-primary/20 rounded-full blur-[100px] pointer-events-none" />
      <div className="absolute bottom-[-10%] left-[-10%] w-[400px] h-[400px] bg-romantic-secondary/20 rounded-full blur-[80px] pointer-events-none" />
      <main className="relative z-10 w-full h-full max-w-lg mx-auto transition-all duration-700 ease-in-out">
        {renderContent()}
      </main>
      {currentIndex > 0 && (
        <div className="absolute bottom-12 md:bottom-8 w-full z-50 pointer-events-none px-8" style={{ paddingBottom: 'env(safe-area-inset-bottom)' }}>
          <div className="flex items-center justify-between text-romantic-text/40">
            <div className={`w-24 flex justify-start transition-opacity duration-300 ${currentIndex > 1 ? 'opacity-100 animate-pulse' : 'opacity-0'}`}><div className="flex items-center gap-1 font-sans text-[10px] uppercase tracking-widest"><ChevronLeft size={10} /> Geri</div></div>
            <div className="font-serif text-sm font-medium tracking-widest opacity-60">{currentIndex} / {SLIDES.length - 1}</div>
            <div className={`w-24 flex justify-end transition-opacity duration-300 ${currentIndex < SLIDES.length - 1 ? 'opacity-100 animate-pulse' : 'opacity-0'}`}><div className="flex items-center gap-1 font-sans text-[10px] uppercase tracking-widest">İleri <ChevronRight size={10} /></div></div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect, useCallback, useMemo } from 'react';
import { Play, Music, Heart, ChevronRight, ChevronLeft, Volume2, Lock, ArrowLeft, Phone, Video, MoreVertical, ChevronsDown, VolumeX } from 'lucide-react';
import { SLIDES, YOUTUBE_VIDEO_ID } from './constants';
import { SlideType } from './types';
import ProgressBar from './components/ProgressBar';
import FloatingHearts from './components/FloatingHearts';

// Helper to access window globals for YouTube API
declare global {
  interface Window {
    onYouTubeIframeAPIReady: () => void;
    YT: any;
  }
}

const App: React.FC = () => {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [isPlaying, setIsPlaying] = useState(false);
  const [password, setPassword] = useState('');
  const [error, setError] = useState(false);
  const playerRef = useRef<any>(null);

  // Countdown State
  const [timeLeft, setTimeLeft] = useState({
    days: 0,
    hours: 0,
    minutes: 0,
    seconds: 0
  });

  // Calculate Countdown
  useEffect(() => {
    const targetDate = new Date('2026-04-25T00:00:00').getTime();

    const interval = setInterval(() => {
      const now = new Date().getTime();
      const difference = targetDate - now;

      if (difference <= 0) {
        clearInterval(interval);
        setTimeLeft({ days: 0, hours: 0, minutes: 0, seconds: 0 });
      } else {
        setTimeLeft({
          days: Math.floor(difference / (1000 * 60 * 60 * 24)),
          hours: Math.floor((difference % (1000 * 60 * 60 * 24)) / (1000 * 60 * 60)),
          minutes: Math.floor((difference % (1000 * 60 * 60)) / (1000 * 60)),
          seconds: Math.floor((difference % (1000 * 60)) / 1000)
        });
      }
    }, 1000);

    return () => clearInterval(interval);
  }, []);

  // Generate static random hearts for Intro to avoid re-render flicker
  const introHearts = useMemo(() => {
    // Reduced from 50 to 20 for cleaner look
    return Array.from({ length: 20 }).map((_, i) => ({
      id: i,
      left: Math.random() * 100, // Random horizontal position 0-100%
      delay: Math.random() * 20, // Spread start times
      duration: 8 + Math.random() * 12, // Faster floating (8s to 20s)
      size: 15 + Math.random() * 35, // Varied sizes (15px to 50px)
      color: Math.random() > 0.5 ? '#FF6B6B' : '#D4A5A5',
      opacity: 0.1 + Math.random() * 0.3 // Significantly reduced opacity (0.1 - 0.4) for better text contrast
    }));
  }, []);

  // Initialize YouTube API
  useEffect(() => {
    if (!window.YT) {
      const tag = document.createElement('script');
      tag.src = "https://www.youtube.com/iframe_api";
      const firstScriptTag = document.getElementsByTagName('script')[0];
      firstScriptTag.parentNode?.insertBefore(tag, firstScriptTag);
    }

    window.onYouTubeIframeAPIReady = () => {
      playerRef.current = new window.YT.Player('youtube-player', {
        height: '1',
        width: '1',
        videoId: YOUTUBE_VIDEO_ID,
        playerVars: {
          'playsinline': 1,
          'controls': 0,
          'disablekb': 1,
          'fs': 0,
          'loop': 1,
          'playlist': YOUTUBE_VIDEO_ID
        },
        events: {
          'onReady': (event: any) => {
             event.target.setVolume(50);
          }
        }
      });
    };

    return () => {
      if (playerRef.current && playerRef.current.destroy) {
        playerRef.current.destroy();
      }
    };
  }, []);

  useEffect(() => {
    if (currentIndex === 0) return;
    const currentSlide = SLIDES[currentIndex];
    if (currentSlide.type === SlideType.VIDEO) {
        if (playerRef.current && playerRef.current.pauseVideo) {
            playerRef.current.pauseVideo();
            setIsPlaying(false);
        }
    } else {
        if (!isPlaying && playerRef.current && playerRef.current.playVideo) {
            playerRef.current.playVideo();
            setIsPlaying(true);
        }
    }
  }, [currentIndex]);

  const handleStart = (e: React.MouseEvent) => {
    e.stopPropagation();
    const cleanInput = password.toLowerCase().replace(/\s/g, '');
    if (cleanInput === 'seniseviyorum') {
      if (playerRef.current && playerRef.current.playVideo) {
        playerRef.current.playVideo();
        setIsPlaying(true);
      }
      setCurrentIndex(1);
      setError(false);
    } else {
      setError(true);
      setTimeout(() => setError(false), 500);
    }
  };

  const handleInteraction = useCallback((e: React.MouseEvent) => {
    if (currentIndex === 0) return;
    if (SLIDES[currentIndex].type !== SlideType.VIDEO && !isPlaying && playerRef.current && playerRef.current.playVideo) {
      playerRef.current.playVideo();
      setIsPlaying(true);
    }
    const { clientX } = e;
    const { innerWidth } = window;
    if (clientX > innerWidth / 2) {
      if (SLIDES[currentIndex].type === SlideType.FINAL) return;
      if (currentIndex < SLIDES.length - 1) setCurrentIndex((prev) => prev + 1);
    } else {
      if (currentIndex > 0) setCurrentIndex((prev) => prev - 1);
    }
  }, [currentIndex, isPlaying]);

  const restart = (e: React.MouseEvent) => {
    e.stopPropagation();
    setCurrentIndex(0);
    setPassword('');
    setIsPlaying(false);
    if (playerRef.current && playerRef.current.stopVideo) {
       playerRef.current.stopVideo();
    }
  };

  const renderContent = () => {
    const currentSlide = SLIDES[currentIndex];
    switch (currentSlide.type) {
      case SlideType.INTRO:
        return (
          <div className="flex flex-col items-center justify-center h-full text-center px-6 animate-fade-in relative overflow-hidden">
            {/* Flying Hearts Background */}
            <div className="absolute inset-0 overflow-hidden pointer-events-none z-0">
               {introHearts.map((heart) => (
                 <div
                   key={heart.id}
                   className="absolute -bottom-10"
                   style={{
                     left: `${heart.left}%`,
                     animation: `floatUp ${heart.duration}s linear infinite`,
                     animationDelay: `-${heart.delay}s`,
                     color: heart.color,
                     opacity: heart.opacity
                   }}
                 >
                   <Heart size={heart.size} fill="currentColor" />
                 </div>
               ))}
            </div>

            {/* Romantic Background Decoration for Intro */}
            <div className="absolute inset-0 z-0 flex items-center justify-center pointer-events-none">
               <div className="absolute w-[500px] h-[500px] bg-romantic-primary/20 rounded-full blur-[100px] animate-pulse-slow"></div>
               <Heart className="text-white/40 w-80 h-80 animate-pulse" fill="currentColor" strokeWidth={0} />
            </div>

            <div className="z-10 w-full flex flex-col items-center">
              {/* Volume Hint */}
              <div className="mb-6 animate-bounce">
                <div className="flex items-center gap-2 bg-white/80 backdrop-blur-md px-4 py-1.5 rounded-full border border-white/60 shadow-md text-romantic-secondary">
                  <Volume2 size={14} className="text-romantic-text" />
                  <span className="text-[10px] font-sans tracking-widest uppercase font-bold text-romantic-text">Sesi Açın</span>
                </div>
              </div>

              {/* Title Section */}
              <div className="mb-8">
                <h1 className="font-script text-6xl md:text-7xl text-romantic-text mb-2 drop-shadow-lg transform -rotate-2">
                  Şeyma <span className="text-romantic-accent text-4xl">&</span> Akif
                </h1>
                <div className="flex items-center justify-center gap-3 mt-4">
                   <div className="h-[2px] w-8 bg-romantic-text/40 rounded-full"></div>
                   <p className="font-serif text-lg md:text-xl text-romantic-text/90 font-bold tracking-[0.2em] uppercase drop-shadow-sm">En Güzel Günümüze</p>
                   <div className="h-[2px] w-8 bg-romantic-text/40 rounded-full"></div>
                </div>
              </div>

              {/* Countdown Section - High Contrast */}
              <div className="grid grid-cols-4 gap-3 mb-12 w-full max-w-sm">
                {[
                  { label: 'Gün', value: timeLeft.days },
                  { label: 'Saat', value: timeLeft.hours },
                  { label: 'Dakika', value: timeLeft.minutes },
                  { label: 'Saniye', value: timeLeft.seconds }
                ].map((item, idx) => (
                  <div key={idx} className="flex flex-col items-center p-3 bg-white/80 backdrop-blur-md rounded-2xl border-2 border-white/60 shadow-xl hover:bg-white/90 transition-colors">
                    <span className="font-serif text-2xl md:text-3xl font-black text-romantic-text tabular-nums leading-none mb-1 drop-shadow-sm">
                      {String(item.value).padStart(2, '0')}
                    </span>
                    <span className="font-sans text-[10px] uppercase tracking-wider text-romantic-text/80 font-bold">
                      {item.label}
                    </span>
                  </div>
                ))}
              </div>

              {/* Login Section */}
              <div className="w-full max-w-xs space-y-5">
                <div className={`transition-transform duration-200 ${error ? 'translate-x-[-10px]' : ''}`}>
                  <div className="relative group">
                    <input
                      type="text"
                      value={password}
                      onChange={(e) => {
                        setPassword(e.target.value);
                        setError(false);
                      }}
                      onClick={(e) => e.stopPropagation()}
                      placeholder="Sihirli sözcük..."
                      className={`w-full bg-white/90 backdrop-blur-md border-2 ${error ? 'border-red-300 text-red-600 placeholder:text-red-400' : 'border-white text-romantic-text'} rounded-2xl px-6 py-4 text-center outline-none focus:border-romantic-primary focus:ring-4 focus:ring-romantic-primary/20 transition-all font-serif text-xl placeholder:text-romantic-text/50 shadow-xl placeholder:italic font-semibold`}
                    />
                    {!password && <Heart size={16} className="absolute right-5 top-1/2 -translate-y-1/2 text-romantic-primary/60 animate-pulse" fill="currentColor" />}
                  </div>
                  {error && <p className="text-red-500 text-xs mt-2 font-sans font-bold text-center bg-white/60 py-1 px-2 rounded-lg inline-block w-full">İpucu: Birbirimize hep söylediğimiz o iki kelime...</p>}
                </div>

                <div className="flex justify-center">
                  <button 
                    onClick={handleStart}
                    className="group relative bg-gradient-to-r from-romantic-primary to-romantic-accent text-white px-12 py-4 rounded-full shadow-xl font-serif tracking-widest uppercase text-sm flex items-center gap-3 overflow-hidden transform transition-all hover:scale-105 active:scale-95 hover:shadow-2xl hover:brightness-110 border-2 border-white/20"
                  >
                    <div className="absolute inset-0 bg-white/20 translate-y-full group-hover:translate-y-0 transition-transform duration-300"></div>
                    <span className="relative flex items-center gap-2 font-bold text-shadow-sm">
                      <Play size={16} className="fill-current" /> Hikayemiz Başlasın
                    </span>
                  </button>
                </div>
              </div>
            </div>
          </div>
        );

      case SlideType.WHATSAPP:
        return (
          <div className="flex flex-col h-full items-center justify-start pt-16 px-4 animate-fade-in relative z-20">
            <div className="w-full max-w-[320px] h-[55vh] md:h-[68vh] bg-[#E5DDD5] rounded-2xl shadow-2xl overflow-hidden flex flex-col relative border border-gray-300 ring-4 ring-black/5 mx-auto transition-all duration-300">
              <div className="bg-[#075E54] text-white p-2 px-3 flex items-center shadow-md z-10 shrink-0">
                <ArrowLeft size={18} className="mr-1" />
                <div className="w-8 h-8 bg-gray-300 rounded-full mr-2 flex items-center justify-center text-gray-500 overflow-hidden shrink-0">
                  <div className="bg-gray-400 w-full h-full flex items-center justify-center text-xs font-bold">A</div>
                </div>
                <div className="flex-1 overflow-hidden">
                  <h3 className="font-semibold text-sm leading-tight truncate">{currentSlide.title}</h3>
                  <p className="text-[10px] opacity-80 truncate">Çevrimiçi</p>
                </div>
                <div className="flex gap-3 ml-2">
                  <Video size={16} />
                  <Phone size={16} />
                  <MoreVertical size={16} />
                </div>
              </div>
              <div className="flex-1 p-3 bg-[#E5DDD5] relative overflow-y-auto scrollbar-hide">
                  <div className="absolute inset-0 opacity-10 bg-[url('https://user-images.githubusercontent.com/15075759/28719144-86dc0f70-73b1-11e7-911d-60d70fcded21.png')] pointer-events-none"></div>
                  <div className="flex justify-center mb-4 relative z-10">
                    <span className="bg-[#D4EAF4] text-gray-600 text-[10px] font-medium px-2 py-0.5 rounded-lg shadow-sm">{currentSlide.date}</span>
                  </div>
                  <div className="space-y-2 relative z-10 pb-4">
                    {currentSlide.messages?.map((msg, idx) => (
                      <div key={idx} className={`flex ${msg.isSender ? 'justify-end' : 'justify-start'}`}>
                        <div className={`max-w-[85%] p-1.5 px-2.5 rounded-lg shadow-sm text-xs relative ${msg.isSender ? 'bg-[#E2FFC7] rounded-tr-none' : 'bg-white rounded-tl-none'}`}>
                          <p className="text-[#303030] leading-snug pb-1 whitespace-pre-wrap">{msg.text}</p>
                          <div className="text-right"><span className="text-[9px] text-gray-500">{msg.time}</span></div>
                        </div>
                      </div>
                    ))}
                  </div>
              </div>
            </div>
            <p className="mt-2 text-xs text-romantic-text/60 font-sans italic animate-pulse">(Mesajı aşağı kaydırabilirsin.)</p>
            {currentSlide.footerText && (
              <div className="mt-4 md:mt-6 text-center max-w-xs animate-fade-in" style={{ animationDelay: '0.5s' }}>
                  <p className="font-serif text-xl md:text-2xl text-romantic-text italic font-medium leading-relaxed drop-shadow-sm px-2">{currentSlide.footerText}</p>
              </div>
            )}
          </div>
        );

      case SlideType.MEMORY:
        return (
          <div className={`flex flex-col items-center justify-center h-full px-6 pb-20 animate-fade-in ${currentSlide.textAlign === 'text-left' ? 'items-start' : ''}`}>
            <div className={`relative p-3 bg-white shadow-2xl mb-4 ${currentSlide.containerClass || 'w-full max-w-sm'} ${currentSlide.imageRotate || 'rotate-2'}`}>
              <div className={`${currentSlide.aspectRatio === 'aspect-auto' ? '' : (currentSlide.aspectRatio || 'aspect-[3/4]')} ${currentSlide.aspectRatio === 'aspect-auto' ? '' : 'overflow-hidden'} bg-gray-200`}>
                <img src={currentSlide.image} alt={currentSlide.title} className={`w-full ${currentSlide.aspectRatio === 'aspect-auto' ? 'h-auto' : 'h-full object-cover'}`} />
              </div>
              <div className="absolute -bottom-10 right-0 font-script text-4xl text-romantic-secondary/50 opacity-50 z-[-1]">{currentSlide.watermark || 'Anılar'}</div>
            </div>
            {currentSlide.secondImage && (
              <div className={`relative p-3 bg-white shadow-2xl mb-8 w-full max-w-sm ${currentSlide.imageRotate ? '-'+currentSlide.imageRotate : '-rotate-2'}`}>
                <div className={`${currentSlide.aspectRatio || 'aspect-[3/4]'} overflow-hidden bg-gray-200`}>
                  <img src={currentSlide.secondImage} alt={currentSlide.title} className="w-full h-full object-cover" />
                </div>
              </div>
            )}
            <div className={`w-full max-w-sm ${currentSlide.textAlign || 'text-center'}`}>
              <h2 className="font-serif text-3xl mb-4 text-romantic-text">{currentSlide.title}</h2>
              <p className="font-sans text-lg leading-relaxed text-romantic-text/80 whitespace-pre-line">{currentSlide.text}</p>
              {currentSlide.author && <p className="mt-2 text-sm text-romantic-secondary italic text-right font-serif">— {currentSlide.author}</p>}
            </div>
          </div>
        );

      case SlideType.COLLAGE:
        let layoutClass = "grid grid-cols-2 gap-3";
        if (currentSlide.collageLayout === 'row') layoutClass = "flex flex-row gap-2 h-64 justify-center items-center";
        else if (currentSlide.collageLayout === 'col') layoutClass = "flex flex-col gap-4 w-full mx-auto";
        return (
          <div className="flex flex-col items-center justify-center h-full px-6 animate-fade-in">
             <h2 className="font-serif text-3xl mb-6 text-romantic-text text-center">{currentSlide.title}</h2>
             <div className={`w-full max-w-md bg-white p-3 shadow-xl transform rotate-1 ${layoutClass}`}>
                {currentSlide.collageImages?.map((img, idx) => (
                  <div key={idx} className={`bg-gray-100 rounded-sm ${currentSlide.collageLayout === 'row' ? 'flex-1 h-full overflow-hidden' : currentSlide.collageLayout === 'col' ? 'w-full' : 'aspect-square overflow-hidden'}`}>
                    <img src={img} alt={`Collage ${idx}`} className={`w-full hover:scale-110 transition-transform duration-500 ${currentSlide.collageLayout === 'col' ? 'h-auto' : 'h-full object-cover'}`} />
                  </div>
                ))}
             </div>
             {currentSlide.text && <div className="mt-12 text-center"><p className="font-script text-3xl text-romantic-text whitespace-pre-line leading-relaxed">{currentSlide.text}</p></div>}
          </div>
        );

      case SlideType.MESSAGE:
        return (
          <div className="flex flex-col items-center justify-center h-full px-8 text-center animate-fade-in relative">
            <div className="font-serif text-6xl text-romantic-primary opacity-20 absolute top-[20%] left-4">"</div>
            <h2 className="font-serif text-3xl md:text-4xl leading-relaxed text-romantic-text italic relative z-10">{currentSlide.text}</h2>
            <div className="font-serif text-6xl text-romantic-primary opacity-20 absolute bottom-[20%] right-4">"</div>
            <div className="mt-8"><Heart className="text-romantic-accent fill-current animate-pulse-slow" size={32} /></div>
          </div>
        );

      case SlideType.MUSIC:
        return (
          <div className="flex flex-col items-center justify-center h-full px-6 animate-fade-in">
             <div className="w-48 h-48 bg-gradient-to-br from-romantic-primary to-romantic-secondary rounded-full shadow-2xl flex items-center justify-center mb-10 animate-spin" style={{ animationDuration: '10s' }}><Music size={64} className="text-white" /></div>
             <div className="text-center mb-8">
                <h3 className="font-serif text-2xl font-bold text-romantic-text mb-1">{currentSlide.title}</h3>
                <p className="font-sans text-sm text-romantic-secondary uppercase tracking-widest">{currentSlide.text}</p>
             </div>
             <div className="space-y-2 text-center">
               {currentSlide.extra?.map((line, i) => <p key={i} className="font-serif text-xl italic text-romantic-text/70">{line}</p>)}
             </div>
          </div>
        );

      case SlideType.DREAMS:
        return (
          <div className="flex flex-col items-center justify-center h-full px-8 animate-fade-in">
            <h2 className="font-script text-5xl mb-12 text-romantic-text">{currentSlide.title}</h2>
            <ul className="space-y-6 w-full max-w-md">
              {currentSlide.extra?.map((item, i) => (
                <li key={i} className="flex items-center gap-4 group">
                  <span className="w-8 h-8 flex items-center justify-center rounded-full bg-romantic-primary/20 text-romantic-accent group-hover:bg-romantic-accent group-hover:text-white transition-colors duration-300"><Heart size={14} className="fill-current" /></span>
                  <span className="font-serif text-xl text-romantic-text border-b border-transparent group-hover:border-romantic-primary transition-all">{item}</span>
                </li>
              ))}
            </ul>
          </div>
        );

      case SlideType.VIDEO:
        return (
          <div className="flex flex-col items-center justify-center h-full w-full animate-fade-in relative z-50 p-4">
             {currentSlide.title && <h2 className="font-serif text-2xl mb-4 text-romantic-text text-center">{currentSlide.title}</h2>}
             <div className="w-full max-w-sm aspect-[9/16] max-h-[70vh] rounded-2xl overflow-hidden shadow-2xl border-4 border-white/50 bg-black relative group">
               <iframe width="100%" height="100%" src={`https://www.youtube.com/embed/${currentSlide.videoId}?autoplay=1&playsinline=1&mute=1&rel=0&loop=1&playlist=${currentSlide.videoId}&controls=1&showinfo=0&modestbranding=1&iv_load_policy=3&fs=0`} title="YouTube video player" frameBorder="0" allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share" allowFullScreen className="w-full h-full object-cover"></iframe>
             </div>
             <div className="mt-4 flex items-center gap-2 text-romantic-text/60 animate-pulse bg-white/50 px-3 py-1 rounded-full"><VolumeX size={14} /><p className="font-sans text-xs">Otomatik başlamazsa veya ses gelmezse videoya dokunun.</p></div>
          </div>
        );

      case SlideType.FINAL:
        return (
          <div className="flex flex-col items-center justify-center h-full px-6 text-center animate-fade-in">
            <h1 className="font-script text-6xl mb-6 text-romantic-text">{currentSlide.title}</h1>
            <p className="font-serif text-xl text-romantic-secondary mb-12">{currentSlide.text}</p>
            <div className="relative cursor-pointer group" onClick={(e) => { e.stopPropagation(); setCurrentIndex(prev => prev + 1); }}>
              <Heart size={150} className="text-romantic-accent fill-current animate-pulse group-hover:scale-110 transition-transform duration-300" />
              <span className="absolute inset-0 flex items-center justify-center text-white font-bold font-sans text-sm tracking-wider animate-bounce">Buraya Bas</span>
            </div>
            <button onClick={restart} className="mt-20 text-xs font-sans uppercase tracking-widest text-romantic-secondary/50 hover:text-romantic-secondary transition-colors z-50 p-4 cursor-pointer">Başa Dön ↺</button>
          </div>
        );
      default: return null;
    }
  };

  return (
    <div onClick={handleInteraction} className="relative w-full h-[100dvh] bg-romantic-bg overflow-hidden cursor-pointer select-none">
      <div id="youtube-player" className="absolute top-0 left-0 opacity-1 pointer-events-none -z-50 h-[1px] w-[1px]" />
      <ProgressBar total={SLIDES.length} current={currentIndex} />
      <FloatingHearts />
      <div className="absolute top-[-20%] right-[-10%] w-[500px] h-[500px] bg-romantic-primary/20 rounded-full blur-[100px] pointer-events-none" />
      <div className="absolute bottom-[-10%] left-[-10%] w-[400px] h-[400px] bg-romantic-secondary/20 rounded-full blur-[80px] pointer-events-none" />
      <main className="relative z-10 w-full h-full max-w-lg mx-auto transition-all duration-700 ease-in-out">
        {renderContent()}
      </main>
      {currentIndex > 0 && (
        <div className="absolute bottom-12 md:bottom-8 w-full z-50 pointer-events-none px-8" style={{ paddingBottom: 'env(safe-area-inset-bottom)' }}>
          <div className="flex items-center justify-between text-romantic-text/40">
            <div className={`w-24 flex justify-start transition-opacity duration-300 ${currentIndex > 1 ? 'opacity-100 animate-pulse' : 'opacity-0'}`}><div className="flex items-center gap-1 font-sans text-[10px] uppercase tracking-widest"><ChevronLeft size={10} /> Geri</div></div>
            <div className="font-serif text-sm font-medium tracking-widest opacity-60">{currentIndex} / {SLIDES.length - 1}</div>
            <div className={`w-24 flex justify-end transition-opacity duration-300 ${currentIndex < SLIDES.length - 1 ? 'opacity-100 animate-pulse' : 'opacity-0'}`}><div className="flex items-center gap-1 font-sans text-[10px] uppercase tracking-widest">İleri <ChevronRight size={10} /></div></div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;
